/**
 * CAN Bus Discovery Plugin
 * 
 * Discovers CAN devices by listening for messages
 * Passive discovery - listens to CAN bus traffic
 */

import type { AgentLogger } from '../../logging/agent-logger';
import { LogComponents } from '../../logging/types';
import { BaseDiscoveryPlugin, DiscoveredDevice } from '../types';
import { generateCANFingerprint } from '../fingerprint';

export interface CANDiscoveryOptions {
  interface?: string; // e.g., 'can0', 'vcan0'
  listenDuration?: number; // ms to listen (discovery phase)
}

export class CANDiscoveryPlugin extends BaseDiscoveryPlugin {
	constructor(logger?: AgentLogger) {
		super('can', logger);
	}

	/**
   * Phase 1: Passive listen to detect message IDs
   */
	async discover(options?: CANDiscoveryOptions): Promise<DiscoveredDevice[]> {
		const discovered: DiscoveredDevice[] = [];

		this.logger?.debugSync('Starting CAN discovery', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			protocol: this.protocol,
			phase: 'discovery'
		});

		const canInterface = options?.interface || 'can0';
		const listenDuration = options?.listenDuration || 5000;

		try {
			// Dynamic import - socketcan may not be available on all platforms
			// @ts-ignore - socketcan is an optional Linux-only dependency
			const socketcan = await import('socketcan');
			const channel = socketcan.createRawChannel(canInterface, true);

			const seenIds = new Set<number>();
			const messageCaptures: Map<number, any[]> = new Map();

			channel.addListener('onMessage', (msg: any) => {
				if (!seenIds.has(msg.id)) {
					seenIds.add(msg.id);
					this.logger?.debugSync(`Discovered CAN ID: 0x${msg.id.toString(16)}`, {
						component: LogComponents.discovery + "] [" + this.protocol as any,
						phase: 'discovery'
					});
				}

				// Capture for validation
				if (!messageCaptures.has(msg.id)) {
					messageCaptures.set(msg.id, []);
				}
        messageCaptures.get(msg.id)!.push({
	timestamp: Date.now(),
	data: msg.data
        });
			});

			channel.start();
			await new Promise(resolve => setTimeout(resolve, listenDuration));
			channel.stop();

			// Create discovered devices
			for (const canId of Array.from(seenIds)) {
				// Format CAN ID as pattern (e.g., "0x18FEF100")
				const canIdPattern = `0x${canId.toString(16).toUpperCase().padStart(8, '0')}`;

				// Generate cryptographic fingerprint
				const fingerprint = generateCANFingerprint(canIdPattern);

				discovered.push({
					name: `can_id_0x${canId.toString(16)}`,
					protocol: 'can' as const,
					fingerprint,
					connection: {
						interface: canInterface,
						filters: [{ id: canId, mask: 0x7FF }]
					},
					dataPoints: [{
						id: canId,
						name: `message_0x${canId.toString(16)}`,
						signals: []
					}],
					confidence: 'low',
					discoveredAt: new Date().toISOString(),
					validated: false,
					metadata: {
						canId,
						canIdPattern,
						canInterface,
						messageCaptures: messageCaptures.get(canId) || [],
						discoveryMethod: 'broadcast'
					}
				});
			}

			this.logger?.debugSync(`Discovered ${discovered.length} CAN IDs`, {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				interface: canInterface,
				phase: 'discovery'
			});
		} catch (error) {
			this.logger?.warnSync('CAN discovery failed', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				error: (error as Error).message
			});
		}

		return discovered;
	}

	/**
   * Phase 2: Validate messages (pattern analysis)
   */
	async validate(device: DiscoveredDevice, _timeout = 10000): Promise<any> {
		this.logger?.debugSync('Validating CAN messages', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			canId: device.metadata?.canId,
			phase: 'validation'
		});

		const messages = device.metadata?.messageCaptures || [];
		if (messages.length === 0) {
			return null;
		}

		const capabilities: string[] = [];

		// Analyze message frequency
		if (messages.length > 1) {
			const intervals = [];
			for (let i = 1; i < messages.length; i++) {
				intervals.push(messages[i].timestamp - messages[i - 1].timestamp);
			}
			const avgInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
			const variance = intervals.reduce((sum, val) => sum + Math.pow(val - avgInterval, 2), 0) / intervals.length;

			if (variance < avgInterval * 0.1) {
				capabilities.push(`periodic_${Math.round(avgInterval)}ms`);
			} else {
				capabilities.push('sporadic');
			}
		}

		// Check data patterns
		const dataHashes = new Set(messages.map((m: any) => JSON.stringify(m.data)));
		if (dataHashes.size === 1) {
			capabilities.push('static_data');
		} else {
			capabilities.push('dynamic_data');
		}

		// Check for common protocols
		const canId = device.metadata?.canId;
		if (canId >= 0x7E0 && canId <= 0x7EF) {
			capabilities.push('obd2');
		} else if ((canId & 0x1FFFF000) === 0x18F00000) {
			capabilities.push('j1939');
		}

		return {
			capabilities,
			messageCount: messages.length,
			dataVariability: dataHashes.size / messages.length
		};
	}

	/**
   * Check if CAN interface is available
   */
	async isAvailable(): Promise<boolean> {
		try {
			// Check if socketcan module is available (Linux only)
			// @ts-ignore - socketcan is an optional Linux-only dependency
			await import('socketcan');
			// TODO: Check if CAN interface exists (e.g., can0)
			return true;
		} catch {
			// socketcan not available (Windows, macOS, or not installed)
			return false;
		}
	}
}

import * as net from 'net';
import * as fs from 'fs';
import * as path from 'path';
import { DeviceDataPoint, SocketOutput, Logger } from '../types.js';

/**
 * IPC Socket Server that receives sensor data and serves it to connected clients
 * Supports both Unix Domain Sockets (Linux/macOS) and Named Pipes (Windows)
 */
export class SocketServer {
	private server?: net.Server;
	private clients: net.Socket[] = [];
	private config: SocketOutput;
	private logger: Logger;
	private started = false;
	private isWindowsNamedPipe: boolean;
	private readonly MAX_CLIENTS = 10; // Prevent IPC DoS attacks

	constructor(config: SocketOutput, logger: Logger) {
		this.config = config;
		this.logger = logger;

		// Detect if this is a Windows Named Pipe
		this.isWindowsNamedPipe = this.config.socketPath.startsWith('\\\\.\\pipe\\');
	}

	/**
   * Start the IPC socket server (Unix socket or Windows Named Pipe)
   */
	async start(): Promise<void> {
		if (this.started) {
			this.logger.debug(`IPC server already running at: ${this.config.socketPath}`);
			return;
		}

		try {
			// For Unix sockets, ensure directory exists and clean up old socket
			if (!this.isWindowsNamedPipe) {
				const socketDir = path.dirname(this.config.socketPath);
				if (!fs.existsSync(socketDir)) {
					fs.mkdirSync(socketDir, { recursive: true });
				}

				// Remove existing socket file if it exists
				if (fs.existsSync(this.config.socketPath)) {
					fs.unlinkSync(this.config.socketPath);
				}
			}

			this.server = net.createServer((socket) => {
				this.handleClientConnection(socket);
			});

			await new Promise<void>((resolve, reject) => {
				let settled = false;

        this.server!.listen(this.config.socketPath, () => {
	const transportType = this.isWindowsNamedPipe ? 'Windows Named Pipe' : 'Unix socket';
	this.logger.info(`IPC server started (${transportType}) at: ${this.config.socketPath}`);

	// Set restrictive permissions on Unix socket file (owner + group only)
	// Prevents unauthorized local processes from connecting
	if (!this.isWindowsNamedPipe) {
		try {
			fs.chmodSync(this.config.socketPath, 0o660);
		} catch (error) {
			this.logger.warn(`Failed to set socket permissions: ${error}`);
		}
	}

	this.started = true;
	settled = true;
	resolve();
        });

        // Handle errors during startup and post-startup
        this.server!.on('error', (error) => {
	if (!settled) {
		// Startup error - reject promise
		reject(error);
	} else {
		// Runtime error after successful start
		this.logger.error(`Socket server runtime error: ${error.message}`);
	}
        });
			});

		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.error(`Failed to start socket server: ${errorMessage}`);
			throw error;
		}
	}

	/**
   * Stop the IPC socket server (Unix socket or Windows Named Pipe)
   */
	async stop(): Promise<void> {
		if (!this.started || !this.server) {
			return;
		}

		try {
			// Close all client connections
			for (const client of this.clients) {
				client.destroy();
			}
			this.clients = [];

			// Close server
			await new Promise<void>((resolve) => {
        this.server!.close(() => {
	const transportType = this.isWindowsNamedPipe ? 'Windows Named Pipe' : 'Unix socket';
	this.logger.debug(`IPC server stopped (${transportType})`);
	resolve();
        });
			});

			// Remove Unix socket file (Named Pipes are cleaned up automatically by Windows)
			if (!this.isWindowsNamedPipe) {
				try {
					if (fs.existsSync(this.config.socketPath)) {
						fs.unlinkSync(this.config.socketPath);
					}
				} catch (unlinkError: any) {
					// Ignore ENOENT (file already deleted) - not an error condition
					if (unlinkError?.code !== 'ENOENT') {
						this.logger.warn(`Failed to remove socket file: ${unlinkError?.message || unlinkError}`);
					}
				}
			}

			this.started = false;
			this.server = undefined;

		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.error(`Error stopping socket server: ${errorMessage}`);
		}
	}

	/**
   * Send sensor data to all connected clients
   * 
   * Backpressure handling: Drops slow consumers instead of buffering
   * Rationale: Real-time telemetry data loses value quickly, and slow consumers
   * shouldn't block fast ones or cause memory growth on edge devices.
   * 
   * TODO (OPTIMIZATION): Broadcast amplification at high scale
   * 
   * Current approach: Write same payload N times (one per client)
   * - Fine for typical edge deployments (1-2 clients, <1k msgs/sec)
   * - Becomes CPU-bound at high scale (10+ clients ├ù 1k msgs/sec = 10k syscalls/sec)
   * 
   * Optimization strategies (if profiling shows bottleneck):
   * 1. Per-client sampling: Fast clients get all data, debug clients get every Nth message
   * 2. Shared memory: Write once, clients read at their own pace (zero-copy broadcast)
   * 3. Client rate limiting: Cap per-client throughput (e.g., max 100 msgs/sec)
   * 
   * Decision: Keep simple broadcast until proven hot. The backpressure handling
   * already prevents the critical failure mode (OOM from slow consumers).
   */
	sendData(dataPoints: DeviceDataPoint[]): void {
		if (!this.started || this.clients.length === 0) {
			return;
		}

		try {
			const message = this.formatData(dataPoints);
			const data = message + this.config.delimiter;

			// Send to all connected clients with backpressure handling
			this.clients.forEach((client, index) => {
				try {
					const flushed = client.write(data);

					// Backpressure detected: kernel buffer full
					if (!flushed) {
						this.logger.warn(`Dropping slow IPC client (backpressure detected) at ${this.config.socketPath}`, {
							clientIndex: index,
							bufferSize: data.length,
							reason: 'kernel_buffer_full'
						});
						this.removeClient(client);
					}
				} catch (error) {
					this.logger.warn(`Failed to send data to client ${index}: ${error}`);
					this.removeClient(client);
				}
			});

		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.error(`Error sending data: ${errorMessage}`);
		}
	}

	/**
   * Get number of connected clients
   */
	getClientCount(): number {
		return this.clients.length;
	}

	/**
   * Check if server is running
   */
	isRunning(): boolean {
		return this.started;
	}

	/**
   * Handle new client connection
   */
	private handleClientConnection(socket: net.Socket): void {
		// Prevent IPC DoS: reject connections beyond max client limit
		if (this.clients.length >= this.MAX_CLIENTS) {
			this.logger.warn(`Rejected IPC client (max ${this.MAX_CLIENTS} clients reached) at ${this.config.socketPath}`);
			socket.destroy();
			return;
		}

		this.clients.push(socket);

		// Use 'once' to prevent duplicate cleanup when multiple events fire
		// (error ΓåÆ close ΓåÆ end can all trigger for same disconnect)
		socket.once('error', (error) => {
			this.logger.warn(`Client socket error: ${error.message}`);
			this.removeClient(socket);
		});

		socket.once('close', () => {
			this.removeClient(socket);
		});

		socket.once('end', () => {
			this.removeClient(socket);
		});
	}

	/**
   * Remove client from the list
   */
	private removeClient(socket: net.Socket): void {
		const index = this.clients.indexOf(socket);
		if (index > -1) {
			this.clients.splice(index, 1);
			try {
				socket.destroy();
			} catch (_error) {
				// Ignore errors when destroying socket
			}
		}
	}

	/**
   * Format sensor data based on configuration
   * 
   * TODO (PRODUCTION): Replace delimiter-based framing with robust protocol
   * 
   * Current approach: message + delimiter (e.g., '\n')
   * Limitations:
   * - JSON data could contain delimiter (e.g., user input with embedded '\n')
   * - Partial write() calls could split frames (rare on IPC, common on network sockets)
   * - Client reading mid-frame gets corrupted data
   * 
   * Why it works now (POC-acceptable):
   * - JSON.stringify() produces single-line output (no embedded '\n')
   * - IPC sockets (Unix/Named Pipe) have low partial-write probability
   * - Trusted clients (sensor-publish) with controlled input
   * 
   * Production alternatives:
   * 1. Length-prefixed framing: 4-byte uint32 length + payload (most robust)
   * 2. NDJSON: Newline-delimited JSON with validation (simpler, less safe)
   * 3. MessagePack framing: Aligns with existing compression stack (recommended)
   * 
   * Recommendation: Migrate to MessagePack framing when consolidating serialization.
   * This matches the sensor-publish msgpack usage and provides type-safe framing.
   */
	private formatData(dataPoints: DeviceDataPoint[]): string {
		if (this.config.dataFormat === 'csv') {
			return this.formatAsCsv(dataPoints);
		} else {
			return this.formatAsJson(dataPoints);
		}
	}

	/**
   * Format data as JSON
   * Returns flat array of readings for cleaner database storage
   */
	private formatAsJson(dataPoints: DeviceDataPoint[]): string {
		const timestamp = new Date().toISOString();

		// Create flat array of readings (one per register)
		const readings = dataPoints.map(point => ({
			timestamp: point.timestamp,
			deviceName: point.deviceName,
			...(point.deviceId && { deviceId: point.deviceId }),
			...(point.endpoint_uuid && { endpoint_uuid: point.endpoint_uuid }),
			...(point.device_uuid && { device_uuid: point.device_uuid }),
			...(point.protocol && { protocol: point.protocol }),
			metric: point.metric,
			value: point.value,
			unit: point.unit,
			quality: point.quality,
			...(point.qualityCode && { qualityCode: point.qualityCode })
		}));

		// Return array directly for single reading, or wrapped for batch
		if (readings.length === 1) {
			return JSON.stringify(readings[0]);
		} else {
			return JSON.stringify({ timestamp, readings });
		}
	}

	/**
   * Format data as CSV
   */
	private formatAsCsv(dataPoints: DeviceDataPoint[]): string {
		const rows: string[] = [];

		for (const point of dataPoints) {
			const row = [
				point.deviceName,
				point.metric,
				String(point.value),
				point.unit,
				point.quality,
				point.timestamp
			].join(',');

			rows.push(row);
		}

		return rows.join('\n');
	}
}

/**
 * Protocol Adapter Manager
 *
 * Manages industrial protocol adapters (Modbus, OPC-UA, SNMP, MQTT, BACnet, CAN).
 * Each adapter polls devices and emits 'data' events.
 * AdapterManager creates one SocketServer per protocol and routes adapter data
 * to sockets for consumption by the publish pipeline.
 *
 * Architecture:
 * - Protocol Adapters: Socket-agnostic, emit data events
 * - AdapterManager: Creates SocketServers, routes adapter data to sockets
 * - Publish pipeline: Reads from sockets, publishes to MQTT
 */

import { EventEmitter } from 'events';
import { AgentLogger } from '../logging/agent-logger.js';
import { ModbusAdapter } from './modbus/adapter.js';
import { ModbusAdapterConfig } from './modbus/types.js';
import { LocalBrokerMqttAdapter } from './mqtt/adapter.js';
import { MqttAdapterConfig } from './mqtt/types.js';
import { SocketServer } from './common/socket-server.js';
import { DeviceDataPoint, SocketOutput } from './types.js';
import { EndpointOutputModel } from '../db/models/endpoint-outputs.model.js';
import { EndpointModel } from '../db/models/endpoint.model.js';
import { encodeIfUuid } from '../mqtt/codec.js';

// Type imports only (no runtime loading)
import type { OPCUAAdapterConfig } from './opcua/types.js';

// SNMP imports
import { SNMPAdapter } from './snmp/adapter.js';

// BACnet imports
import { BACnetAdapter } from './bacnet/adapter.js';
import { BACnetAdapterConfig } from './bacnet/types.js';

export interface AdapterConfig {
  modbus?: { enabled: boolean; config?: ModbusAdapterConfig };
  can?: { enabled: boolean };
  opcua?: { enabled: boolean; config?: OPCUAAdapterConfig };
  snmp?: { enabled: boolean };
  mqtt?: { enabled: boolean; config?: MqttAdapterConfig };
  bacnet?: { enabled: boolean; config?: BACnetAdapterConfig };
}

export class AdapterManager extends EventEmitter {
	private adapters: Map<string, any> = new Map();
	private socketServers: Map<string, SocketServer> = new Map();
	// Shared endpoint-UUID lookup used by the MQTT data handler; updated in-place on hot-reload
	// so the event-handler closure always sees the latest deviceΓåÆUUID mappings.
	private mqttEndpointUuidByName: Map<string, string> = new Map();
	private config: AdapterConfig;
	private deviceUuid: string;
	private running = false;
	private readonly logger: { info(m: string): void; warn(m: string): void; error(m: string, ...a: any[]): void; debug(m: string, ...a: any[]): void };

	private enrichWithEndpointUuid(
		dataPoints: DeviceDataPoint[],
		endpointUuidByName: Map<string, string>
	): DeviceDataPoint[] {
		if (endpointUuidByName.size === 0 || dataPoints.length === 0) {
			return dataPoints;
		}

		return dataPoints.map((point) => {
			const endpointUuid = endpointUuidByName.get(point.deviceName);
			if (!endpointUuid) {
				return point;
			}

			// Each endpoint in the endpoints table is itself a device with a UUID.
			// Honour any asset-level device_uuid supplied by the source (e.g. a fleet
			// simulator that assigns its own UUIDs), otherwise the endpoint UUID is the
			// device identity for protocol adapters (OPC UA, Modbus, SNMP, MQTT).
			const device_uuid = point.device_uuid || endpointUuid;

			// Build a unique device display name: "{displayBase}-{first8ofDeviceUuid}"
			// - displayBase: protocol-discovered name (OPC-UA DisplayName, SNMP sysName, BACnet
			//   objectName) or config displayName override; falls back to the raw endpoint config name
			// - uuid suffix: first 8 hex chars of device_uuid make it globally unique across agents
			//   e.g. "opcua-4" (raw) ΓåÆ "Siemens S7-1500-eaaeff83" (discovered) or "opcua-4-eaaeff83"
			const displayBase = point.resolvedDisplayName || point.deviceName;
			const uuidSuffix = device_uuid.replace(/-/g, '').slice(0, 8);
			const deviceName = uuidSuffix.length === 8
				? `${displayBase}-${uuidSuffix}`
				: displayBase;

			this.logger.debug('Built endpoint deviceName', {
				displayBase,
				device_uuid,
				endpointUuid,
				finalDeviceName: deviceName,
			});

			return {
				...point,
				deviceName,
				endpoint_uuid: endpointUuid,
				device_uuid,
			};
		});
	}

	/** Build a device-name ΓåÆ endpoint-UUID lookup from a list of device configs */
	private buildUuidMap(devices: any[]): Map<string, string> {
		const map = new Map<string, string>();
		for (const device of devices) {
			const endpointUuid =
        (typeof device.uuid === 'string' && device.uuid.trim()) ||
        (typeof device.metadata?.uuid === 'string' && device.metadata.uuid.trim()) ||
        (typeof device.metadata?.device_uuid === 'string' && device.metadata.device_uuid.trim());
			if (endpointUuid && typeof device.name === 'string') {
				map.set(device.name, endpointUuid);
			}
		}
		return map;
	}

	/** Load output config from DB, create and start a SocketServer for the given protocol */
	private async createSocketServer(protocol: string): Promise<SocketServer> {
		const dbOutput = await EndpointOutputModel.getOutput(protocol);
		if (!dbOutput) throw new Error(`${protocol} output configuration not found in database`);
		const outputConfig: SocketOutput = {
			socketPath: dbOutput.socket_path,
			dataFormat: dbOutput.data_format as 'json' | 'csv',
			delimiter: dbOutput.delimiter,
			includeTimestamp: dbOutput.include_timestamp,
			includeDeviceName: dbOutput.include_device_name,
		};
		const socket = new SocketServer(outputConfig, this.logger);
		await socket.start();
		this.socketServers.set(protocol, socket);
		return socket;
	}

	/** Wire the four standard adapter events (started, data, device-connected, device-disconnected) */
	private wireAdapterEvents(
		protocol: string,
		adapter: EventEmitter,
		socket: SocketServer,
		uuidMap: Map<string, string>
	): void {
		const label = protocol.toUpperCase();
		adapter.on('started',             ()                       => this.logger.info(`${label} adapter started`));
		adapter.on('data',                (dps: DeviceDataPoint[]) => socket.sendData(this.enrichWithEndpointUuid(dps, uuidMap)));
		adapter.on('device-connected',    (name: string)           => this.logger.info(`${label} device connected: ${name}`));
		adapter.on('device-disconnected', (name: string)           => this.logger.warn(`${label} device disconnected: ${name}`));
		adapter.on('device-error',        (name: string, err: Error | string) => this.logger.error(`${label} device error [${name}]: ${err instanceof Error ? err.message : err}`));
	}

	constructor(config: AdapterConfig, agentLogger: AgentLogger, deviceUuid: string) {
		super();
		this.config = config;
		this.deviceUuid = deviceUuid;
		this.logger = {
			info:  (m) => agentLogger.infoSync(m,  { component: 'Adapters' }),
			warn:  (m) => agentLogger.warnSync(m,  { component: 'Adapters' }),
			error: (m, ...a) => agentLogger.errorSync(m, a[0] instanceof Error ? a[0] : undefined, { component: 'Adapters' }),
			debug: (m, ...a) => { if (process.env.PROTOCOL_ADAPTERS_DEBUG === 'true') agentLogger.debugSync(m, { component: 'Adapters', args: a }); },
		};
	}

	/** Start all enabled protocol adapters */
	async start(): Promise<void> {
		if (this.running) return;
		if (this.config.modbus?.enabled)  await this.startModbusAdapter();
		if (this.config.opcua?.enabled)   await this.startOPCUAAdapter();
		if (this.config.snmp?.enabled)    await this.startSNMPAdapter();
		if (this.config.mqtt?.enabled)    await this.startMQTTAdapter();
		if (this.config.bacnet?.enabled)  await this.startBACnetAdapter();
		if (this.config.can?.enabled)     this.logger.warn('CAN adapter not yet implemented');
		this.running = true;
		this.emit('started');
	}

	/** Stop all running protocol adapters and socket servers */
	async stop(): Promise<void> {
		if (!this.running) return;
		for (const [, adapter] of this.adapters) {
			if (adapter && typeof adapter.stop === 'function') await adapter.stop();
		}
		this.adapters.clear();
		for (const [, server] of this.socketServers) await server.stop();
		this.socketServers.clear();
		this.running = false;
		this.emit('stopped');
	}

	isRunning(): boolean { return this.running; }

	/**
   * Start Modbus adapter
   */
	private async startModbusAdapter(): Promise<void> {
		try {
			let modbusConfig: ModbusAdapterConfig;

			if (this.config.modbus?.config) {
				modbusConfig = this.config.modbus.config;
			} else {
				const dbDevices = await EndpointModel.getEnabled('modbus');
				modbusConfig = {
					devices: dbDevices.map(d => ({
						uuid: d.uuid,
						name: d.name,
						enabled: d.enabled,
						slaveId: d.connection.slaveId || 1,
						connection: d.connection as any,
						pollInterval: d.poll_interval,
						registers: (d.data_points || []).map((dp: any) => {
							let functionCode = dp.functionCode;
							if (!functionCode && dp.type) {
								const typeMap: Record<string, number> = { coil: 1, discrete: 2, holding: 3, input: 4 };
								functionCode = typeMap[dp.type.toLowerCase()];
							}
							return {
								...dp,
								functionCode,
								dataType: dp.dataType || 'float32',
								count: dp.count || (dp.dataType === 'float32' || dp.dataType === 'int32' || dp.dataType === 'uint32' ? 2 : 1),
								scale: dp.scale !== undefined ? dp.scale : 1,
								offset: dp.offset !== undefined ? dp.offset : 0,
							};
						}),
					}) as any),
					logging: { level: 'info', enableConsole: false, enableFile: false },
				};
			}

			const uuidMap = this.buildUuidMap(modbusConfig.devices);
			const socket = await this.createSocketServer('modbus');
			const adapter = new ModbusAdapter(modbusConfig, this.logger);
			this.adapters.set('modbus', adapter);
			(adapter as any)._socketServer = socket;
			this.wireAdapterEvents('modbus', adapter, socket, uuidMap);
			await adapter.start();

		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.error(`Failed to start Modbus adapter: ${errorMessage}`);
			throw error;
		}
	}

	/**
   * Start OPC-UA adapter
   */
	private async startOPCUAAdapter(): Promise<void> {
		try {
