	/**
   * Get a specific protocol adapter
   * @param protocol - Protocol name ('modbus', 'opcua', 'snmp', 'mqtt', 'bacnet')
   * @returns The adapter instance or undefined if not running
   */
	getAdapter(protocol: string): any | undefined {
		return this.adapters.get(protocol);
	}

	/**
   * Get all running adapters
   * @returns Map of protocol name to adapter instance
   */
	getAllAdapters(): Map<string, any> {
		return new Map(this.adapters);
	}
}

import { EventEmitter } from 'events';
import * as mqtt from 'mqtt';
import * as mqttPattern from 'mqtt-pattern';
import { DeviceDataPoint, DeviceStatus, Logger } from '../types.js';
import { MqttAdapterConfig, MqttDevice, MqttMetricConfig } from './types.js';
import { parsePayload, coerceType } from './payload.js';
import { agentTopic } from '../../mqtt/topics.js';
import { EndpointModel } from '../../db/models/endpoint.model.js';

/**
 * MQTT Adapter
 * 
 * Architecture: This adapter is socket-agnostic. It subscribes to MQTT topics
 * from external publishers (ESP32, PLCs, IoT devices) publishing to the local
 * Mosquitto broker and emits 'data' events with sensor readings. The parent
 * AdapterManager manages SocketServer and routes data to the appropriate socket.
 * 
 * Pattern: Mosquitto broker acts as the ENDPOINT (data aggregation point),
 *          just like a Modbus gateway or OPC-UA server.
 * 
 * Events:
 * - 'started': Adapter started successfully
 * - 'stopped': Adapter stopped
 * - 'data': Emitted with SensorDataPoint[] when data is collected
 * - 'device-connected': Emitted when broker connects
 * - 'device-disconnected': Emitted when broker disconnects
 * - 'device-error': Emitted when an error occurs
 */
export class LocalBrokerMqttAdapter extends EventEmitter {
	private static readonly MAX_QUEUE_DEPTH = 1000; // Max buffered data batches
	private static readonly MAX_PAYLOAD_BYTES = 1 * 1024 * 1024; // 1MB max payload (edge-safe default)

	private config: MqttAdapterConfig;
	private logger: Logger;
	private client: mqtt.MqttClient | null = null;
	private subscriptions: Map<string, MqttDevice> = new Map();
	private deviceStatuses: Map<string, DeviceStatus> = new Map();
	private running = false;
	private connected = false;
	private emitQueue: DeviceDataPoint[][] = [];
	private processingEmitQueue = false;
	private droppedMessageCount = 0;
	private firstConnect = true; // Track first connection for subscription logic
	private reconnectAttemptCount = 0;
	private currentReconnectPeriod = 0;
	private compiledMetrics = new Map<string, Array<MqttMetricConfig & { path: string[] }>>();
	private compiledTimestampFields = new Map<string, string[]>();
	private lwtDeviceIdToName = new Map<string, string>();
	private brokerStatusTopic: string | null = null;
	private deviceUuid: string | null = null;
	// Optional human-readable labels keyed by topic (resolve via subscriptions map at publish time)
	private displayNamesByTopic = new Map<string, string>();

	constructor(config: MqttAdapterConfig, logger: Logger, deviceUuid?: string) {
		super();
		this.config = config;
		this.logger = logger;
		this.deviceUuid = deviceUuid?.trim() || null;
		this.currentReconnectPeriod = this.getBaseReconnectPeriod();

		for (const device of this.config.devices) {
			if (device.enabled) {
				this.subscriptions.set(device.topic, device);
			}

			// Cache displayName by topic for fast lookup in enqueueData
			if (device.displayName && device.displayName.trim()) {
				this.displayNamesByTopic.set(device.topic, device.displayName.trim());
			}

			const lwtDeviceId = device.deviceId?.trim();
			if (lwtDeviceId) {
				this.lwtDeviceIdToName.set(lwtDeviceId, device.name);
			}

			if (device.timestampField) {
				this.compiledTimestampFields.set(
					device.name,
					this.compileMetricPath(device.timestampField, Boolean(device.allowArrayMetrics))
				);
			}

			if (device.metrics && device.metrics.length > 0) {
				this.compiledMetrics.set(
					device.name,
					device.metrics.map(metric => ({
						...metric,
						path: this.compileMetricPath(metric.field, Boolean(device.allowArrayMetrics))
					}))
				);
			}
		}

		this.initializeDeviceStatuses();
	}

	private compileMetricPath(field: string, allowArrayMetrics: boolean): string[] {
		if (!field) {
			return [];
		}

		const normalized = allowArrayMetrics
		// Convert bracket numeric indexing only: values[0] -> values.0
			? field.replace(/\[(\d+)\]/g, '.$1')
			: field;

		return normalized.split('.').filter(Boolean);
	}

	/**
   * Start the MQTT adapter - create client and let mqtt.js handle reconnection
   * 
   * Self-healing architecture:
   * - Creates client immediately (doesn't wait for connection)
   * - mqtt.js handles automatic reconnection via reconnectPeriod
   * - Adapter survives broker downtime at startup
   * - Connection state tracked via events, not promise resolution
   * 
   * This makes the adapter resilient in edge environments where:
   * - Broker may start after agent
   * - Network may be unavailable at startup
   * - Transient failures should not kill the adapter
   */
	async start(): Promise<void> {
		if (this.running) {
			return;
		}

		this.logger.debug('Starting MQTT Adapter...');

		// Create client - let mqtt.js handle connection and reconnection
		this.createClient();

		this.running = true;

		this.emit('started');

	}

	/**
   * Stop the MQTT adapter
   */
	async stop(): Promise<void> {
		if (!this.running) {
			return;
		}

		try {
			this.logger.debug('Stopping MQTT Adapter...');

			if (this.client) {
				// Publish graceful offline status so retained state reflects intentional shutdown.
				await this.publishBrokerStatus('offline');

				// Best-effort unsubscribe to avoid stale persistent subscriptions on broker.
				await this.unsubscribeAll();

				// Production fix: Remove all listeners to prevent memory leaks
				this.client.removeAllListeners();

				// Graceful disconnect to ensure socket closes before stop completes.
				await new Promise<void>((resolve) => {
          this.client!.end(false, (error?: Error) => {
	if (error) {
		this.logger.warn(`Error while ending MQTT client connection: ${error.message}`);
	}
	resolve();
          });
				});

				this.client = null;
				this.connected = false;
			}

			this.subscriptions.clear();
			this.emitQueue = [];
			this.processingEmitQueue = false;
			this.running = false;
			this.firstConnect = true; // Reset for next start

			this.logger.debug('MQTT Adapter stopped successfully');
			this.emit('stopped');

		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.error(`Error stopping MQTT Adapter: ${errorMessage}`);
		}
	}

	/**
   * Hot-update device subscriptions without reconnecting to the broker.
   *
   * Diffs the new device list against the current one by topic and:
   * - Subscribes to topics for newly added/enabled devices
   * - Unsubscribes from topics for removed/disabled devices
   * - Updates all internal maps (subscriptions, compiledMetrics, etc.)
   * - Updates config.devices so reconnect logic re-subscribes correctly
   *
   * If the client is not yet connected the subscription changes will be
   * picked up automatically on the next 'connect' event because
   * subscribeAllConfiguredDevices() reads config.devices.
   */
	async updateDevices(newDevices: MqttDevice[]): Promise<void> {
		const oldTopics = new Set(this.subscriptions.keys());
		const newEnabledDevices = newDevices.filter(d => d.enabled);
		const newTopics = new Set(newEnabledDevices.map(d => d.topic));

		// --- Removed devices ---
		const removedTopics = [...oldTopics].filter(t => !newTopics.has(t));
		for (const topic of removedTopics) {
			const device = this.subscriptions.get(topic);
			if (!device) continue;

			// Unsubscribe from broker (best-effort; client may not be connected)
			if (this.client && this.connected) {
				await new Promise<void>(resolve => {
          this.client!.unsubscribe(topic, () => resolve());
				});
			}

			this.subscriptions.delete(topic);
			this.deviceStatuses.delete(device.name);
			this.compiledMetrics.delete(device.name);
			this.compiledTimestampFields.delete(device.name);
			this.displayNamesByTopic.delete(topic);

			if (device.deviceId?.trim()) {
				this.lwtDeviceIdToName.delete(device.deviceId.trim());
			}

			this.logger.info(`MQTT hot-update: unsubscribed removed device '${device.name}' (${topic})`);
		}

		// --- Added devices ---
		const addedDevices = newEnabledDevices.filter(d => !oldTopics.has(d.topic));
		for (const device of addedDevices) {
			// Update lookup maps before subscribing so message handler can find the device
			this.subscriptions.set(device.topic, device);

			this.deviceStatuses.set(device.name, {
				deviceName: device.name,
				connected: false,
				lastPoll: null,
				lastSeen: null,
				errorCount: 0,
				lastError: null,
				responseTimeMs: null,
				pollSuccessRate: 0,
				registersUpdated: 0,
				communicationQuality: 'offline',
			});

			if (device.displayName?.trim()) {
				this.displayNamesByTopic.set(device.topic, device.displayName.trim());
			}

			if (device.deviceId?.trim()) {
				this.lwtDeviceIdToName.set(device.deviceId.trim(), device.name);
			}

			if (device.timestampField) {
				this.compiledTimestampFields.set(
					device.name,
					this.compileMetricPath(device.timestampField, Boolean(device.allowArrayMetrics))
				);
			}

			if (device.metrics && device.metrics.length > 0) {
				this.compiledMetrics.set(
					device.name,
					device.metrics.map(metric => ({
						...metric,
						path: this.compileMetricPath(metric.field, Boolean(device.allowArrayMetrics)),
					}))
				);
			}

			// Subscribe on the live connection if available
			if (this.client && this.connected) {
				try {
					await this.subscribeToDevice(device);
				} catch (err) {
					const msg = err instanceof Error ? err.message : String(err);
					this.logger.error(`MQTT hot-update: failed to subscribe '${device.name}' (${device.topic}): ${msg}`);
				}
			} else {
				this.logger.debug(`MQTT hot-update: queued subscription for '${device.name}' (${device.topic}) ΓÇö will subscribe on next connect`);
			}
		}

		// Sync config.devices so reconnect/subscribeAllConfiguredDevices() is consistent
		this.config = { ...this.config, devices: newDevices };

		if (removedTopics.length > 0 || addedDevices.length > 0) {
			this.logger.info('MQTT hot-update complete', {
				added: addedDevices.length,
				removed: removedTopics.length,
				totalActive: this.subscriptions.size,
			});
		}
	}

	/**
   * Get status of all devices
   */
	getDeviceStatuses(): DeviceStatus[] {
		return Array.from(this.deviceStatuses.values());
	}

	/**
   * Get status of a specific device
   */
	getDeviceStatus(deviceName: string): DeviceStatus | undefined {
		return this.deviceStatuses.get(deviceName);
	}

	/**
   * Create MQTT client and attach event handlers
   * 
   * Self-healing architecture:
   * - Does NOT wait for initial connection (no timeout rejection)
   * - mqtt.js handles automatic reconnection via reconnectPeriod
   * - Survives broker downtime at startup (edge-friendly)
   * - Connection state tracked via events
   * 
   * Production-safe:
   * - Cleans up old client before creating new one (prevents listener leaks)
   * - Uses .on() for ongoing state tracking (not .once() for promises)
   * - Handles persistent session subscription logic correctly
   * - Emits events for connection state transitions
   */
	private createClient(): void {
		const brokerUrl = `mqtt://${this.config.broker.host}:${this.config.broker.port}`;

		// Generate stable clientId for persistent sessions (critical for edge agents)
		const stableClientId = this.resolveStableClientId();
		this.brokerStatusTopic = this.resolveBrokerStatusTopic();

		this.logger.debug(`Creating MQTT client for broker: ${brokerUrl}`, { 
			clientId: stableClientId,
			reconnectPeriod: this.currentReconnectPeriod,
		});

		// Cleanup old client before creating new one (prevents listener leaks)
		if (this.client) {
			this.client.removeAllListeners();
			this.client.end(true);
			this.client = null;
		}

		this.client = mqtt.connect(brokerUrl, {
			clientId: stableClientId,
			username: this.config.broker.username,
			password: this.config.broker.password,
			reconnectPeriod: this.currentReconnectPeriod,
			clean: false, // Persistent session: survive reconnects, keep subscriptions, replay QoS 1 messages
			keepalive: 30, // Send pings every 30s (well before mosquitto's 60s idle timeout)
			...(this.brokerStatusTopic ? {
				will: {
					topic: this.brokerStatusTopic,
					payload: Buffer.from('offline'),
					qos: 1,
					retain: true
				}
			} : {})
		});

		// Event-based state machine (not promise-based)
		// mqtt.js will keep retrying automatically

		this.client.on('connect', (connack) => {
			this.connected = true;
			this.resetReconnectBackoff();


			this.emit('device-connected', 'mqtt-broker');

			// Overwrite retained LWT offline marker with current online status.
			void this.publishBrokerStatus('online');

			// LWT status stream: subscribe once per connected session.
			this.subscribeToStatusTopic().catch(err => {
				this.logger.warn(`Failed to subscribe to broker status topic: ${err.message}`);
			});

			// Refresh configured subscriptions on every connect.
			if (!connack.sessionPresent) {
				this.logger.warn('MQTT session not present, subscribing all configured topics', {
					firstConnect: this.firstConnect,
					risk: this.firstConnect
						? 'No broker-side session yet; messages published before the first successful subscribe are not recoverable.'
						: 'Persistent session was lost; messages published while the adapter was disconnected may have been dropped by the broker.',
				});
			} else if (this.firstConnect) {
				this.logger.debug('Connected with existing persistent session (sessionPresent=true)');
			} else {
				this.logger.debug('Reconnected - refreshing subscriptions');
			}

			this.subscribeAllConfiguredDevices().catch(err => {
				this.logger.error(`Failed to subscribe configured topics after connect: ${err.message}`);
			});

			this.firstConnect = false;
		});

		this.client.on('error', (err) => {
			this.logger.error(`MQTT client error: ${err.message}`);
			this.emit('device-error', 'mqtt-broker', err);
			// Don't kill the client - let mqtt.js retry
		});

		this.client.on('offline', () => {
			this.connected = false;
			this.logger.warn('MQTT broker offline');
			this.emit('device-disconnected', 'mqtt-broker');
		});

		this.client.on('reconnect', () => {
			const nextReconnectDelayMs = this.scheduleNextReconnectBackoff();
			this.logger.debug('MQTT reconnecting to broker', {
				attempt: this.reconnectAttemptCount,
				nextReconnectDelayMs,
			});
		});

		this.client.on('close', () => {
			this.connected = false;
			this.logger.debug('MQTT connection closed');
		});

		// Handle incoming messages
		// Note: MQTT callback signature includes packet metadata (retain flag, qos, etc.)
		this.client.on('message', (topic, payload, packet) => {
			if (topic.startsWith('device/') && topic.endsWith('/status')) {
				this.handleLwtStatus(topic, payload, packet.retain);
				return;
			}
			this.handleMessage(topic, payload, packet.retain);
		});
	}

	private resolveStableClientId(): string {
		const deviceUuid = this.deviceUuid?.trim();
		if (deviceUuid && deviceUuid.toLowerCase() !== 'unknown') {
			return `agent-${deviceUuid}`;
		}

		throw new Error(
			'MQTT clientId requires a valid device UUID to derive agent-<deviceUuid>.'
		);
	}

	private getBaseReconnectPeriod(): number {
		const configured = Number(this.config.reconnect.period);
		return Number.isFinite(configured) ? Math.max(0, configured) : 0;
	}

	private getReconnectStrategy(): 'fixed' | 'exponential' {
		return this.config.reconnect.strategy === 'exponential' ? 'exponential' : 'fixed';
	}

	private getMaxReconnectPeriod(): number {
		const base = this.getBaseReconnectPeriod();
		const configured = Number(this.config.reconnect.maxPeriod);

		if (!Number.isFinite(configured)) {
			return base;
		}

		return Math.max(base, configured);
	}

	private getReconnectJitterRatio(): number {
		const configured = Number(this.config.reconnect.jitterRatio);
		if (!Number.isFinite(configured)) {
			return 0;
		}

		return Math.min(1, Math.max(0, configured));
	}

	private applyReconnectPeriod(periodMs: number): void {
		this.currentReconnectPeriod = periodMs;

		if (this.client) {
			(this.client.options as mqtt.IClientOptions).reconnectPeriod = periodMs;
		}
	}

	private computeReconnectPeriod(attempt: number): number {
		const base = this.getBaseReconnectPeriod();
		if (this.getReconnectStrategy() === 'fixed') {
			return base;
		}

		const maxPeriod = this.getMaxReconnectPeriod();
		const exponentialDelay = Math.min(maxPeriod, base * (2 ** Math.max(0, attempt - 1)));
		const jitterRatio = this.getReconnectJitterRatio();

		if (jitterRatio === 0) {
			return exponentialDelay;
		}

		const lowerBound = exponentialDelay * (1 - jitterRatio);
		const upperBound = exponentialDelay * (1 + jitterRatio);
		return Math.round(lowerBound + (Math.random() * (upperBound - lowerBound)));
	}

	private resetReconnectBackoff(): void {
		this.reconnectAttemptCount = 0;
		this.applyReconnectPeriod(this.getBaseReconnectPeriod());
	}

	private scheduleNextReconnectBackoff(): number {
		this.reconnectAttemptCount += 1;
		const nextPeriod = this.computeReconnectPeriod(this.reconnectAttemptCount);
		this.applyReconnectPeriod(nextPeriod);
		return nextPeriod;
	}

	private resolveBrokerStatusTopic(): string | null {
		if (!this.deviceUuid || this.deviceUuid.toLowerCase() === 'unknown') {
			this.logger.debug('Broker status topic skipped: no device UUID provided');
			return null;
		}

		try {
			return agentTopic(this.deviceUuid, 'agent', 'broker');
		} catch {
			// Tenant ID not yet initialized (pre-provisioning). Topic will remain null until reconnect.
			this.logger.debug('Broker status topic skipped: tenant ID not yet initialized');
			return null;
		}
	}

	private async publishBrokerStatus(status: 'online' | 'offline'): Promise<void> {
		if (!this.client || !this.connected || !this.brokerStatusTopic) {
			return;
		}

		await new Promise<void>((resolve, reject) => {
      this.client!.publish(
        this.brokerStatusTopic!,
        Buffer.from(status),
        { qos: 1, retain: true },
        (err) => {
	if (err) {
		reject(err);
		return;
	}
	resolve();
        }
      );
		}).catch((err) => {
			const message = err instanceof Error ? err.message : String(err);
			this.logger.warn(`Failed to publish broker status '${status}': ${message}`, {
				topic: this.brokerStatusTopic,
			});
		});
	}

	private async subscribeAllConfiguredDevices(): Promise<void> {
		for (const device of this.config.devices) {
			if (!device.enabled) {
				continue;
			}

			try {
				await this.subscribeToDevice(device);
			} catch (err) {
				const message = err instanceof Error ? err.message : String(err);
				this.logger.error(`Failed to subscribe to device topic ${device.topic}: ${message}`);
			}
		}
	}

	private async subscribeToStatusTopic(): Promise<void> {
		if (!this.client || !this.connected) {
			return;
		}

		const statusTopic = 'device/+/status';
		await new Promise<void>((resolve, reject) => {
      this.client!.subscribe(statusTopic, { qos: 1 }, (err) => {
	if (err) {
		reject(err);
		return;
	}
	resolve();
      });
		});
	}

	private async unsubscribeAll(): Promise<void> {
		if (!this.client) {
			return;
		}

		const topics = Array.from(this.subscriptions.keys());
		if (topics.length === 0) {
			return;
		}

		try {
			await new Promise<void>((resolve) => {
        this.client!.unsubscribe(topics, () => resolve());
			});
			this.logger.debug(`Unsubscribed from ${topics.length} MQTT topics before shutdown`);
		} catch (error) {
			const errorMessage = error instanceof Error ? error.message : String(error);
			this.logger.warn(`Failed to unsubscribe all MQTT topics during shutdown: ${errorMessage}`);
		}
	}

	/**
   * Subscribe to a device's topics
   */
	private async subscribeToDevice(device: MqttDevice): Promise<void> {
		if (!this.client || !this.connected) {
			throw new Error('MQTT client not connected');
		}

		const topic = device.topic;
		const qos = device.qos || this.config.qos;

		if (qos === 0) {
			this.logger.warn('MQTT subscription uses QoS 0; messages published during disconnects may be lost', {
				topic,
				deviceName: device.name,
				clientId: this.client.options.clientId,
			});
		}

		return new Promise((resolve, reject) => {
      this.client!.subscribe(topic, { qos }, (err) => {
	if (err) {
		this.logger.error(`Failed to subscribe to topic: ${topic} - ${err.message}`);
		reject(err);
		return;
	}

	this.subscriptions.set(topic, device);
	resolve();
      });
		});
	}

	/**
   * Find device config for incoming topic (supports MQTT wildcards: +, #)
   * Uses mqtt-pattern library for proper wildcard matching
   * 
   * Performance Note: O(N) linear search through subscriptions.
   * Fine for typical deployments (10-100 devices).
   * For high-scale (1000+ wildcard filters), consider:
   * - Pre-compile patterns
   * - Index by first topic segment
   * - Use trie-based matching
   */
	private findDeviceForTopic(topic: string): MqttDevice | undefined {
		for (const [filter, device] of this.subscriptions.entries()) {
			if (mqttPattern.matches(filter, topic)) {
				return device;
			}
		}
		return undefined;
	}

	private handleLwtStatus(topic: string, payload: Buffer, retain: boolean): void {
		if (retain) {
			return;
		}

		const deviceId = topic.split('/')[1];
		if (!deviceId) {
			return;
		}

		const deviceName = this.lwtDeviceIdToName.get(deviceId);
		if (!deviceName) {
			this.logger.debug(`Ignoring LWT status for unmapped deviceId: ${deviceId}`, { topic });
			return;
		}

		const statusText = payload.toString('utf8').trim().toLowerCase();
		const status = this.deviceStatuses.get(deviceName);
		if (!status) {
			return;
		}

		const now = new Date();
		if (statusText === 'online') {
			status.connected = true;
			status.communicationQuality = 'good';
			status.lastSeen = now;
			status.lastPoll = now;
			this.logger.debug(`LWT: device online`, { deviceId, deviceName });
		} else if (statusText === 'offline') {
			status.connected = false;
			status.communicationQuality = 'offline';
			this.logger.debug(`LWT: device offline`, { deviceId, deviceName });
		}
	}

	private enqueueData(points: DeviceDataPoint[], topic: string): void {
		if (this.emitQueue.length >= LocalBrokerMqttAdapter.MAX_QUEUE_DEPTH) {
			this.droppedMessageCount++;
			if (this.droppedMessageCount % 100 === 1) {
				this.logger.warn('Dropping MQTT messages due to bounded queue limit', {
					queueDepth: this.emitQueue.length,
					droppedTotal: this.droppedMessageCount,
					maxQueueDepth: LocalBrokerMqttAdapter.MAX_QUEUE_DEPTH,
					topic
				});
			}
			return;
		}

		// Attach resolvedDisplayName if a config override exists for this topic
		const resolvedDisplayName = this.displayNamesByTopic.get(topic);
		const enriched = resolvedDisplayName
			? points.map(p => ({ ...p, resolvedDisplayName }))
			: points;

		this.emitQueue.push(enriched);
		void this.processEmitQueue();
	}

	private async processEmitQueue(): Promise<void> {
		if (this.processingEmitQueue) {
			return;
		}

		this.processingEmitQueue = true;
		try {
			while (this.emitQueue.length > 0) {
				const points = this.emitQueue.shift();
				if (!points) {
					continue;
				}

				const listeners = this.listeners('data');
				for (const listener of listeners) {
					try {
						await Promise.resolve(listener(points));
					} catch (error) {
						const errorMessage = error instanceof Error ? error.message : String(error);
						this.logger.error(`MQTT data listener failed: ${errorMessage}`);
					}
				}

				await new Promise<void>(resolve => setImmediate(resolve));
			}
		} finally {
			this.processingEmitQueue = false;
		}
	}

	private getFieldFast(payload: any, path: string[]): any {
		let value = payload;
		for (const segment of path) {
			if (value == null) {
				return undefined;
			}
			value = value[segment];
		}
		return value;
	}

	private resolveTimestamp(rawTimestamp: any, fallback: string): string {
		if (rawTimestamp === undefined || rawTimestamp === null) {
			return fallback;
		}

		// Numeric epoch support: seconds or milliseconds
		if (typeof rawTimestamp === 'number' && Number.isFinite(rawTimestamp)) {
			const epochMs = rawTimestamp < 1_000_000_000_000 ? rawTimestamp * 1000 : rawTimestamp;
			const date = new Date(epochMs);
			return Number.isNaN(date.getTime()) ? fallback : date.toISOString();
		}

		// String support: ISO date or numeric epoch string
		if (typeof rawTimestamp === 'string') {
			const trimmed = rawTimestamp.trim();
			if (!trimmed) {
				return fallback;
			}

			const numeric = Number(trimmed);
			if (Number.isFinite(numeric)) {
				const epochMs = numeric < 1_000_000_000_000 ? numeric * 1000 : numeric;
				const date = new Date(epochMs);
				return Number.isNaN(date.getTime()) ? fallback : date.toISOString();
			}

			const date = new Date(trimmed);
			return Number.isNaN(date.getTime()) ? fallback : date.toISOString();
		}

		return fallback;
	}

	private resolveIncomingUnit(parsed: unknown, metric: string): string | undefined {
		if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
			const parsedObj = parsed as Record<string, unknown>;

			const units = parsedObj.units;
			if (units && typeof units === 'object' && !Array.isArray(units)) {
				const mappedUnit = (units as Record<string, unknown>)[metric];
				if (typeof mappedUnit === 'string' && mappedUnit.trim()) {
					return mappedUnit.trim();
				}
			}

			const suffixedUnit = parsedObj[`${metric}_unit`];
			if (typeof suffixedUnit === 'string' && suffixedUnit.trim()) {
				return suffixedUnit.trim();
			}

			const payloadName = parsedObj.name;
			const payloadUnit = parsedObj.unit;
			if (payloadName === metric && typeof payloadUnit === 'string' && payloadUnit.trim()) {
				return payloadUnit.trim();
			}
		}

		return undefined;
	}

	private canonicalizeUnit(unit: string | undefined): string | undefined {
		if (!unit) {
			return undefined;
		}

		const trimmed = unit.trim();
		if (!trimmed) {
			return undefined;
		}

		const normalized = trimmed.toLowerCase();
		switch (normalized) {
			case 'c':
			case '┬░c':
			case 'degc':
			case 'deg_c':
			case 'celsius':
				return 'C';
			case 'f':
			case '┬░f':
			case 'fahrenheit':
				return 'F';
			case 'k':
			case 'kelvin':
				return 'K';
			case 'pa':
				return 'Pa';
			case 'kpa':
				return 'kPa';
			case 'bar':
				return 'bar';
			case 'mbar':
				return 'mbar';
			case 'mm/s':
				return 'mm/s';
			case 'm/s':
				return 'm/s';
			case 'psi':
				return 'psi';
			case 'atm':
				return 'atm';
			case '%':
			case 'percent':
			case 'percentage':
				return '%';
			case 'ppm':
				return 'ppm';
			case 'ppb':
				return 'ppb';
			case 'db':
			case 'dba':
				return 'dB';
			case 'lux':
			case 'lx':
				return 'lux';
			case 'w':
				return 'W';
			case 'kw':
				return 'kW';
			case 'kwh':
				return 'kWh';
			case 'v':
				return 'V';
			case 'a':
				return 'A';
			case 'rpm':
				return 'RPM';
			default:
				this.logger.warn('Unknown unit encountered', { unit: trimmed });
				return trimmed;
		}
	}

	private resolveUnitDimension(unit: string): 'temperature' | 'pressure' | undefined {
		switch (unit) {
			case 'C':
			case 'F':
			case 'K':
				return 'temperature';
			case 'Pa':
			case 'kPa':
			case 'bar':
			case 'mbar':
			case 'psi':
			case 'atm':
				return 'pressure';
			default:
				return undefined;
		}
	}

	private convertToBaseUnit(value: number, unit: string, dimension: 'temperature' | 'pressure'): number {
		if (dimension === 'temperature') {
			switch (unit) {
				case 'K':
					return value;
				case 'C':
					return value + 273.15;
				case 'F':
					return ((value - 32) * 5 / 9) + 273.15;
			}
		}

		if (dimension === 'pressure') {
			switch (unit) {
				case 'Pa':
					return value;
				case 'kPa':
					return value * 1000;
				case 'bar':
					return value * 100000;
				case 'mbar':
					return value * 100;
				case 'psi':
					return value * 6894.757293168;
				case 'atm':
					return value * 101325;
			}
		}

		throw new Error(`Unsupported unit conversion source: ${unit}`);
	}

	private convertFromBaseUnit(value: number, unit: string, dimension: 'temperature' | 'pressure'): number {
		if (dimension === 'temperature') {
			switch (unit) {
				case 'K':
					return value;
				case 'C':
					return value - 273.15;
				case 'F':
					return ((value - 273.15) * 9 / 5) + 32;
			}
		}

		if (dimension === 'pressure') {
			switch (unit) {
				case 'Pa':
					return value;
				case 'kPa':
					return value / 1000;
				case 'bar':
					return value / 100000;
				case 'mbar':
					return value / 100;
				case 'psi':
					return value / 6894.757293168;
				case 'atm':
					return value / 101325;
			}
		}

		throw new Error(`Unsupported unit conversion target: ${unit}`);
	}

	private convertUnitValue(value: number, fromUnit: string, toUnit: string): number {
		if (fromUnit === toUnit) {
			return value;
		}

		const fromDimension = this.resolveUnitDimension(fromUnit);
		const toDimension = this.resolveUnitDimension(toUnit);

		if (!fromDimension || !toDimension || fromDimension !== toDimension) {
			throw new Error(`Unsupported unit conversion: ${fromUnit} -> ${toUnit}`);
		}

		const baseValue = this.convertToBaseUnit(value, fromUnit, fromDimension);
		return this.convertFromBaseUnit(baseValue, toUnit, toDimension);
	}

	private normalizePrecision(precision: number | undefined): number | undefined {
		if (!Number.isFinite(precision)) {
			return undefined;
		}

		return Math.max(0, Math.floor(Number(precision)));
	}

	private roundNumericValue(value: number, precision: number): number {
		const factor = 10 ** precision;
		return Math.round((value + Number.EPSILON) * factor) / factor;
	}

	private normalizeMetricValue(
		rawValue: any,
		type: string,
		incomingUnit: string | undefined,
		canonicalUnit: string | undefined,
		precision: number | undefined,
	): { value: number | boolean | string | null; unit?: string } {
		const value = coerceType(rawValue, type);
		const normalizedIncoming = this.canonicalizeUnit(incomingUnit);
		const normalizedCanonical = this.canonicalizeUnit(canonicalUnit);
		const normalizedPrecision = this.normalizePrecision(precision);

		if (typeof value !== 'number' || !Number.isFinite(value)) {
			return {
				value,
				unit: normalizedCanonical ?? normalizedIncoming,
			};
		}

		if (normalizedCanonical) {
			if (!normalizedIncoming || normalizedIncoming === normalizedCanonical) {
				return {
					value: normalizedPrecision !== undefined
						? this.roundNumericValue(value, normalizedPrecision)
						: value,
					unit: normalizedCanonical,
				};
			}

			try {
				const convertedValue = this.convertUnitValue(value, normalizedIncoming, normalizedCanonical);
				return {
					value: this.roundNumericValue(convertedValue, normalizedPrecision ?? 2),
					unit: normalizedCanonical,
				};
			} catch (error) {
				this.logger.warn('Unknown unit conversion, storing raw value', {
					from: normalizedIncoming,
					to: normalizedCanonical,
					error: error instanceof Error ? error.message : String(error),
				});

				return {
					value,
					unit: normalizedIncoming,
				};
			}
		}

		return {
			value: normalizedPrecision !== undefined
				? this.roundNumericValue(value, normalizedPrecision)
				: value,
			unit: normalizedIncoming,
		};
	}

	private buildMetricPoint(
		device: MqttDevice,
		metric: string,
		rawValue: any,
		incomingUnit: string | undefined,
		canonicalUnit: string | undefined,
		precision: number | undefined,
		type: string | undefined,
		deviceId: string | undefined,
		topic: string,
		now: string,
		retain: boolean
	): DeviceDataPoint {
		const normalized = this.normalizeMetricValue(
			rawValue,
			type || device.dataType || 'string',
			incomingUnit,
			canonicalUnit,
			precision,
		);

		return {
			deviceName: device.name,
			...(deviceId && { deviceId }),
			metric: metric || topic,
			value: normalized.value,
			...(normalized.unit !== undefined && { unit: normalized.unit }),
			timestamp: now,
			quality: retain ? 'UNCERTAIN' : 'GOOD',
			...(retain && { qualityCode: 'RETAINED_MESSAGE' })
		};
	}

	private resolveMessageDeviceId(device: MqttDevice, parsed: unknown): string | undefined {
		if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
			const candidate = (parsed as any).deviceId ?? (parsed as any).device_id;
			if (typeof candidate === 'string' && candidate.trim()) {
				return candidate.trim();
			}
			if (typeof candidate === 'number' && Number.isFinite(candidate)) {
				return String(candidate);
			}
		}

		if (typeof device.deviceId === 'string' && device.deviceId.trim()) {
			return device.deviceId.trim();
		}

		return undefined;
	}

	/**
   * Handle incoming MQTT message
   * 
   * @param topic - MQTT topic
   * @param payload - Message payload
   * @param retain - Retained message flag (true = stale/historical data)
   */
	private handleMessage(topic: string, payload: Buffer, retain: boolean = false): void {
		// Production fix #8: Max payload size guard
		// Protects against memory exhaustion from malicious/corrupt messages
		if (payload.length > LocalBrokerMqttAdapter.MAX_PAYLOAD_BYTES) {
			this.droppedMessageCount++;
			this.logger.warn('Dropping oversized MQTT message', {
				topic,
				payloadSize: payload.length,
				maxAllowed: LocalBrokerMqttAdapter.MAX_PAYLOAD_BYTES,
				droppedTotal: this.droppedMessageCount,
				hint: 'Possible JSON bomb or malicious payload'
			});
			return;
		}

		// Check if topic matches any configured device
		const device = this.findDeviceForTopic(topic);

		// If no device configured for this topic, ignore
		if (!device) {
			this.logger.debug(`Ignoring message for unconfigured topic: ${topic}`);
			return;
		}

		// Liveness is based on message receipt, not parse success.
		if (!retain) {
			this.trackMessageActivity(device.name);
		}

		try {
			const parsed = parsePayload(payload);
			const now = new Date().toISOString();
			const timestampPath = this.compiledTimestampFields.get(device.name);
			const payloadTimestamp = timestampPath && typeof parsed === 'object' && parsed !== null
				? this.resolveTimestamp(this.getFieldFast(parsed, timestampPath), now)
				: now;
			const resolvedDeviceId = this.resolveMessageDeviceId(device, parsed);
			const points: DeviceDataPoint[] = [];

			const compiledDeviceMetrics = this.compiledMetrics.get(device.name);
			if (compiledDeviceMetrics && compiledDeviceMetrics.length > 0) {
				if (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) {
					for (const metricConfig of compiledDeviceMetrics) {
						const rawValue = this.getFieldFast(parsed, metricConfig.path);

						if (rawValue === undefined) {
							this.logger.debug(`MQTT metric field not found in payload`, {
								topic,
								deviceName: device.name,
								field: metricConfig.field,
							});
							continue;
						}

						try {
							points.push(this.buildMetricPoint(
								device,
								metricConfig.metric,
								rawValue,
								this.resolveIncomingUnit(parsed, metricConfig.metric),
								metricConfig.unit,
								metricConfig.precision,
								metricConfig.type,
								resolvedDeviceId,
								topic,
								payloadTimestamp,
								retain
							));
						} catch (fieldError) {
							this.logger.warn(`Failed to coerce MQTT metric field '${metricConfig.field}'`, {
								topic,
								deviceName: device.name,
								metric: metricConfig.metric,
								error: fieldError instanceof Error ? fieldError.message : String(fieldError)
							});
						}
					}
				} else {
					this.logger.warn('MQTT multi-metric config requires JSON object payload', {
						topic,
						deviceName: device.name
					});
				}
			}

			if (device.autoMetrics && typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) {
				for (const [key, rawValue] of Object.entries(parsed)) {
					// Skip nested objects/arrays in auto mode to avoid emitting ambiguous metrics.
					if (rawValue !== null && typeof rawValue === 'object') {
						continue;
					}

					try {
						points.push(this.buildMetricPoint(
							device,
							key,
							rawValue,
							this.resolveIncomingUnit(parsed, key),
							device.defaultUnits?.[key],
							device.defaultPrecisions?.[key],
							undefined,
							resolvedDeviceId,
							topic,
							payloadTimestamp,
							retain
						));
					} catch (fieldError) {
						this.logger.warn(`Failed to coerce MQTT auto metric field '${key}'`, {
							topic,
							deviceName: device.name,
							error: fieldError instanceof Error ? fieldError.message : String(fieldError)
						});
					}
				}
			}

			// Default behavior without explicit metric mapping:
			// emit every primitive field from JSON object payloads.
			if (points.length === 0) {
				const singleMetric = device.metric || topic;
				let singleType = device.dataType;
				let singleSource: unknown = parsed;

				if (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) {
					const parsedObj = parsed as Record<string, unknown>;

					if (parsedObj.value !== undefined && (parsedObj.value === null || typeof parsedObj.value !== 'object')) {
						singleSource = parsedObj.value;
					} else {
						const metadataKeys = new Set([
							'timestamp', 'ts', 'time', 'name', 'unit',
							'deviceId', 'device_id', 'device_uuid', 'topic', 'units',
						]);

						const primitiveEntries = Object.entries(parsedObj).filter(([key, value]) => {
							if (metadataKeys.has(key)) {
								return false;
							}
							if (key.endsWith('_unit')) {
								return false;
							}
							return value === null || ['string', 'number', 'boolean'].includes(typeof value);
						});

						if (primitiveEntries.length > 0) {
							for (const [metricName, metricValue] of primitiveEntries) {
								points.push(this.buildMetricPoint(
									device,
									metricName,
									metricValue,
									this.resolveIncomingUnit(parsedObj, metricName),
									device.defaultUnits?.[metricName],
									device.defaultPrecisions?.[metricName],
									undefined,
									resolvedDeviceId,
									topic,
									payloadTimestamp,
									retain
								));
							}

							this.logger.debug('MQTT emitted primitive fields from object payload', {
								topic,
								deviceName: device.name,
								fields: primitiveEntries.map(([key]) => key),
							});
						} else {
							// No scalar field to coerce; preserve payload as JSON text.
							singleSource = JSON.stringify(parsedObj);
							singleType = 'json';
						}
					}
				}

				if (points.length === 0) {
					points.push(this.buildMetricPoint(
						device,
						singleMetric,
						singleSource,
						this.resolveIncomingUnit(parsed, singleMetric),
						device.unit,
						device.precision,
						singleType,
						resolvedDeviceId,
						topic,
						payloadTimestamp,
						retain
					));
				}
			}

			// Emit data through bounded queue for real backpressure handling.
			this.enqueueData(points, topic);

			if (retain) {
				this.logger.debug(`Retained message ignored for device health tracking`, {
					topic,
					deviceName: device.name
				});
			}

		} catch (err) {
			const errorMessage = err instanceof Error ? err.message : String(err);
			this.logger.error(`Failed to parse MQTT message from topic ${topic}: ${errorMessage}`);

			// Emit BAD quality data point
			const dataPoint: DeviceDataPoint = {
				deviceName: device.name,
				metric: device.metric || topic,
				value: null,
				...(device.unit !== undefined && { unit: device.unit }),
				timestamp: new Date().toISOString(),
				quality: 'BAD',
				qualityCode: 'PARSE_ERROR'
			};

			this.enqueueData([dataPoint], topic);
		}
	}

	/**
   * Initialize device statuses
   * 
   * Note: MQTT devices don't have persistent connections like Modbus/OPC-UA.
   * Connection state should be inferred from:
   * - lastSeen timestamp (message recency)
   * - Last Will and Testament (LWT) messages
   * - Application-specific staleness thresholds
   */
	private initializeDeviceStatuses(): void {
		for (const device of this.config.devices) {
			this.deviceStatuses.set(device.name, {
				deviceName: device.name,
				connected: false, // MQTT: Use LWT or staleness logic to determine this
				lastPoll: null,
				lastSeen: null,
				errorCount: 0,
				lastError: null,
				responseTimeMs: null,
				pollSuccessRate: 0,
				registersUpdated: 0,
				communicationQuality: 'offline'
			});
		}
	}

	/**
   * Track message activity (not connection state)
   * 
   * For MQTT devices:
   * - Message arrival Γëá device connected
   * - Devices may publish once per hour and sleep
   * - "Connected" state should be inferred from lastSeen + staleness threshold
   * - Use Last Will and Testament (LWT) for definitive offline detection
   */
	private trackMessageActivity(deviceName: string): void {
		const status = this.deviceStatuses.get(deviceName);
		if (!status) {
			return;
		}

		const now = new Date();
		status.lastSeen = now;
		status.lastPoll = now;
		status.registersUpdated = (status.registersUpdated || 0) + 1;
		status.communicationQuality = 'good';

		// Persist lastSeen to DB so stale-device checks don't flag MQTT endpoints as null
		EndpointModel.updateLastSeenByName(deviceName).catch((err: Error) => {
			this.logger.warn(`Failed to update lastSeen for ${deviceName}: ${err.message}`);
		});

		// Note: Don't set connected=true here
		// Let higher-level logic decide connectivity based on:
		// - Time since lastSeen (staleness)
		// - LWT messages
		// - Application requirements
	}
}

/**
 * MQTT Discovery Plugin
 * 
 * Simplified topic validation approach (not auto-discovery)
 * User provides explicit topics ΓåÆ we verify they publish data
 * 
 * Pattern: MQTT topic = endpoint (like Modbus register or OPC-UA node)
 * 
 * Discovery Strategy:
 * - User supplies specific topics to validate
 * - Subscribe to each topic
 * - Wait for messages (10-15 seconds)
 * - If messages received ΓåÆ topic is active
 * - Infer basic data type (number, boolean, string, json)
 * - Return validated topics as candidates
 * 
 * No Complex Features:
 * - Γ¥î No wildcard scanning
 * - Γ¥î No metadata parsing
 * - Γ¥î No confidence scoring
 * - Γ¥î No compound topic analysis
 * - Γ¥î No observer roots
 * - Γ¥î No passive discovery
 * 
 * Industrial Best Practice:
 * - Explicit configuration > Auto-discovery magic
 * - Validate what user asks for > Scan everything
 * - Deterministic behavior > Heuristics
 */

import type { AgentLogger } from '../../logging/agent-logger';
import { LogComponents } from '../../logging/types';
import { BaseDiscoveryPlugin, DiscoveredDevice, ValidationResult } from '../types';
import * as mqtt from 'mqtt';
import crypto from 'crypto';

export interface MqttDiscoveryOptions {
  brokerUrl?: string;          // e.g., 'mqtt://mosquitto:1883' or 'mqtts://broker:8883'
  username?: string;
  password?: string;
  topics: string[];            // REQUIRED: Explicit topics to validate (e.g., ['device/sensor01/temperature'])
  samplingDurationMs?: number; // Default: 10000 (10s) - how long to listen for messages
  qos?: 0 | 1 | 2;             // QoS for discovery subscription (default: 0)

  // TLS/SSL support (for mqtts://)
  ca?: Buffer;                 // CA certificate
  cert?: Buffer;               // Client certificate
  key?: Buffer;                // Client private key
  rejectUnauthorized?: boolean; // Verify server certificate (default: true)
}

interface TopicValidation {
  topic: string;
  messagesReceived: number;
  retainedMessagesReceived: number; // Track retained messages separately
  firstPayload?: string;
  firstSeen?: Date;
  lastSeen?: Date;
  hasRetained?: boolean;   // Did we receive a retained message?
  hasLive?: boolean;       // Did we receive a live (non-retained) message?
}

/**
 * Generate MQTT fingerprint
 * Based on topic path (stable identifier)
 */
function generateMqttFingerprint(topic: string): string {
	return crypto
		.createHash('sha256')
		.update(`mqtt:${topic}`)
		.digest('hex')
		.substring(0, 32);
}

export class LocalBrokerMqttDiscoveryPlugin extends BaseDiscoveryPlugin {
	private client?: mqtt.MqttClient;
	private validatedTopics: Map<string, TopicValidation> = new Map();
	private brokerConfig?: MqttDiscoveryOptions; // Store for validate() reuse

	constructor(
		logger?: AgentLogger,
    private mqttFactory: (url: string, options: any) => mqtt.MqttClient = mqtt.connect
	) {
		super('mqtt', logger);
	}

	/**
   * Phase 1: Topic validation
   * Subscribe to explicit topics, verify they receive messages
   */
	async discover(options?: MqttDiscoveryOptions, signal?: AbortSignal): Promise<DiscoveredDevice[]> {
		this.validatedTopics.clear();

		const brokerUrl = options?.brokerUrl || process.env.MQTT_BROKER_URL;
		if (!brokerUrl) {
			throw new Error('MQTT_BROKER_URL is required for MQTT discovery');
		}
		const topics = options?.topics || [];
		const samplingDurationMs = options?.samplingDurationMs || 10000; // 10 seconds default
		const qos = options?.qos ?? 0;

		// Store broker config for validate() reuse
		this.brokerConfig = options;

		// Validation: topics are required
		if (!topics || topics.length === 0) {
			this.logger?.warnSync('No topics provided for MQTT discovery', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				hint: 'Provide explicit topics to validate (e.g., ["device/sensor01/temperature"])'
			});
			return [];
		}

		this.logger?.infoSync('Starting MQTT topic validation', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			protocol: this.protocol,
			phase: 'discovery',
			brokerUrl,
			topicCount: topics.length,
			topics: topics.slice(0, 5), // Log first 5 topics
			samplingDurationMs
		});

		try {
			// Connect to broker with TLS support
			this.client = this.mqttFactory(brokerUrl, {
				username: options?.username,
				password: options?.password,
				clientId: `iotistic-discovery-${Date.now()}`,
				clean: true,
				reconnectPeriod: 0, // Don't auto-reconnect during discovery
				// TLS options (for mqtts://)
				ca: options?.ca,
				cert: options?.cert,
				key: options?.key,
				rejectUnauthorized: options?.rejectUnauthorized ?? true
			});

			// Handle abort signal for graceful cancellation
			if (signal) {
				signal.addEventListener('abort', () => {
					this.logger?.warnSync('Discovery aborted by signal', {
						component: LogComponents.discovery + "] [" + this.protocol as any
					});
					this.cleanupClient();
				});
			}

			// Wait for connection
			await new Promise<void>((resolve, reject) => {
				const timeout = setTimeout(() => {
					this.logger?.errorSync('MQTT connection timeout - broker unreachable', undefined, {
						component: LogComponents.discovery + "] [" + this.protocol as any,
						brokerUrl,
						timeout: '5000ms',
						hint: 'Check if broker is running and accessible from agent container'
					});
					reject(new Error(`MQTT connection timeout - cannot reach ${brokerUrl}`));
				}, 5000);

        this.client!.on('connect', () => {
	clearTimeout(timeout);
	this.logger?.infoSync('Connected to MQTT broker for discovery', {
		component: LogComponents.discovery + "] [" + this.protocol as any,
		brokerUrl
	});
	resolve();
        });

        this.client!.on('error', (err) => {
	clearTimeout(timeout);
	this.logger?.errorSync('MQTT connection error', err, {
		component: LogComponents.discovery + "] [" + this.protocol as any,
		brokerUrl,
		error: err.message
	});
	reject(err);
        });
			});

			// Subscribe to each topic
			for (const topic of topics) {
				await new Promise<void>((resolve, reject) => {
          this.client!.subscribe(topic, { qos }, (err) => {
	if (err) {
		this.logger?.errorSync(`Failed to subscribe to topic: ${topic}`, err, {
			component: LogComponents.discovery + "] [" + this.protocol as any
		});
		reject(err);
	} else {
		this.logger?.debugSync(`Subscribed to topic: ${topic}`, {
			component: LogComponents.discovery + "] [" + this.protocol as any
		});

		// Initialize validation entry
		this.validatedTopics.set(topic, {
			topic,
			messagesReceived: 0,
			retainedMessagesReceived: 0,
			hasRetained: false,
			hasLive: false
		});

		resolve();
	}
          });
				});
			}

			this.logger?.debugSync(`Sampling ${topics.length} topics for ${samplingDurationMs}ms`, {
				component: LogComponents.discovery + "] [" + this.protocol as any
			});

			// Listen for messages with packet info to detect retained flag
			this.client.on('message', (topic, payload, packet) => {
				this.handleMessage(topic, payload.toString(), packet.retain);
			});

			// Wait for sampling duration (or until aborted)
			await new Promise<void>(resolve => {
				const timer = setTimeout(resolve, samplingDurationMs);
				signal?.addEventListener('abort', () => {
					clearTimeout(timer);
					resolve();
				});
			});

			// Disconnect with proper cleanup
			this.cleanupClient();

			// Analyze results
			const activeTopics = Array.from(this.validatedTopics.values()).filter(t => t.messagesReceived > 0);
			const inactiveTopics = Array.from(this.validatedTopics.values()).filter(t => t.messagesReceived === 0);

			this.logger?.infoSync('Discovery complete', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				totalTopics: topics.length,
				activeTopics: activeTopics.length,
				inactiveTopics: inactiveTopics.length
			});

			if (inactiveTopics.length > 0) {
				this.logger?.warnSync(
					`${inactiveTopics.length} topic(s) did not receive messages during sampling period`,
					{
						component: LogComponents.discovery + "] [" + this.protocol as any,
						inactiveTopics: inactiveTopics.map(t => t.topic),
						recommendation: 'Verify publishers are active or increase samplingDurationMs'
					}
				);
			}

			// Log retained message awareness
			const retainedOnlyTopics = activeTopics.filter(t => t.hasRetained && !t.hasLive);
			if (retainedOnlyTopics.length > 0) {
				this.logger?.warnSync(
					`${retainedOnlyTopics.length} topic(s) have only retained messages (no live publisher observed)`,
					{
						component: LogComponents.discovery + "] [" + this.protocol as any,
						retainedOnlyTopics: retainedOnlyTopics.map(t => t.topic),
						recommendation: 'These topics may have stale data - verify publishers are running'
					}
				);
			}

			// Convert active topics to DiscoveredDevice format
			return this.convertToDevices(activeTopics);

		} catch (error) {
			this.logger?.errorSync(
				'MQTT discovery failed',
        error as Error,
        { component: LogComponents.discovery + "] [" + this.protocol as any }
			);

			this.cleanupClient();

			return [];
		}
	}

	/**
   * Handle incoming message during sampling
   * Tracks both retained and live messages for production observability
   */
	private handleMessage(topic: string, payload: string, isRetained: boolean = false): void {
		let validation = this.validatedTopics.get(topic);
		if (!validation) {
			// Initialize new topic tracking
			validation = {
				topic,
				messagesReceived: 0,
				retainedMessagesReceived: 0,
				hasRetained: false,
				hasLive: false
			};
			this.validatedTopics.set(topic, validation);
		}

		const now = new Date();

		if (validation.messagesReceived === 0) {
			// First message for this topic
			validation.firstPayload = payload;
			validation.firstSeen = now;

			this.logger?.debugSync(`Topic active: ${topic}`, {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				payloadPreview: payload.substring(0, 100),
				retained: isRetained
			});
		}

		validation.messagesReceived++;
		validation.lastSeen = now;

		// Track retained vs live messages
		if (isRetained) {
			validation.retainedMessagesReceived++;
			validation.hasRetained = true;
		} else {
			validation.hasLive = true;
		}
	}

	/**
   * Infer basic data type from payload
   * Returns broad categories only: 'number', 'boolean', 'string', 'json'
   * 
   * Production-safe numeric detection (avoids edge cases like "Infinity", "NaN", "00123")
   */
	private inferDataType(payload: string): string {
		// Try JSON parsing first
		try {
			const parsed = JSON.parse(payload);

			// If it's an object or array, return 'json'
			if (typeof parsed === 'object') {
				return 'json';
			}

			// JSON primitive values
			if (typeof parsed === 'number' && Number.isFinite(parsed)) {
				return 'number';
			}

			if (typeof parsed === 'boolean') {
				return 'boolean';
			}

			// JSON string value
			return 'string';

		} catch {
			// Not JSON - analyze raw string
			const trimmed = payload.trim();

			// Explicit boolean keywords (case-insensitive)
			const lower = trimmed.toLowerCase();
			if (lower === 'true' || lower === 'false') {
				return 'boolean';
			}

			// Production-safe numeric detection: exact pattern match
			// Avoids "Infinity", "NaN", leading zeros, whitespace
			if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
				return 'number';
			}

			return 'string';
		}
	}

	/**
   * Convert validated topics to DiscoveredDevice format
   */
	private convertToDevices(validatedTopics: TopicValidation[]): DiscoveredDevice[] {
		const devices: DiscoveredDevice[] = [];

		for (const validation of validatedTopics) {
			const fingerprint = generateMqttFingerprint(validation.topic);

			// Generate name from topic with length limit to avoid excessively long names
			let topicName = validation.topic.replace(/\//g, '_');
			if (topicName.length > 58) {
				// For very long topics, use last 55 chars (most specific part)
				// Final name = mqtt_ (5) + ... (3) + last 55 chars = 63 chars max
				topicName = '...' + topicName.slice(-55);
			}
			const name = `mqtt_${topicName}`;

			// Infer data type from first payload
			const dataType = validation.firstPayload 
				? this.inferDataType(validation.firstPayload)
				: 'string';

			const device: DiscoveredDevice = {
				name,
				protocol: 'mqtt',
				fingerprint,
				connection: {
					topic: validation.topic,
					dataType
				},
				dataPoints: [],  // MQTT uses topics, not data points
				confidence: 'high', // If we got messages, it's active
				discoveredAt: validation.firstSeen?.toISOString() || new Date().toISOString(),
				validated: false // User must validate before enabling
			};

			devices.push(device);

			this.logger?.debugSync(`Validated topic: ${validation.topic}`, {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				name,
				dataType,
				messagesReceived: validation.messagesReceived
			});
		}

		return devices;
	}

	/**
   * Phase 2: Validate a specific device
   * Fast validation: Subscribe to topic, wait for single message
   * Uses stored broker config from discover() for consistency
   */
	async validate(device: DiscoveredDevice): Promise<ValidationResult> {
		const topic = device.connection?.topic;

		if (!topic || typeof topic !== 'string') {
			return {
				deviceInfo: {
					valid: false,
					message: 'Invalid topic configuration - missing topic field'
				}
			};
		}

		this.logger?.debugSync('Validating MQTT topic', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			topic
		});

		try {
			// Use broker config from discover() for consistent authentication
			const brokerUrl = this.brokerConfig?.brokerUrl || process.env.MQTT_BROKER_URL;
			if (!brokerUrl) {
				throw new Error('MQTT_BROKER_URL is required for MQTT topic validation');
			}

			// Short validation: 5 seconds to receive at least one message
			const validationResult = await this.quickValidateTopic(
				brokerUrl, 
				topic,
				this.brokerConfig // Pass full config including credentials
			);

			if (validationResult) {
				this.logger?.infoSync(`Topic validated successfully: ${topic}`, {
					component: LogComponents.discovery + "] [" + this.protocol as any
				});

				return {
					deviceInfo: {
						valid: true,
						message: 'Topic is active and receiving messages'
					}
				};
			} else {
				this.logger?.warnSync(`Topic validation failed (no messages): ${topic}`, {
					component: LogComponents.discovery + "] [" + this.protocol as any
				});

				return {
					deviceInfo: {
						valid: false,
						message: 'No messages received during validation period'
					}
				};
			}
		} catch (error) {
			this.logger?.errorSync(
				'Topic validation error',
        error as Error,
        { component: LogComponents.discovery + "] [" + this.protocol as any, topic }
			);

			return {
				deviceInfo: {
					valid: false,
					message: `Validation failed: ${(error as Error).message}`
				}
			};
		}
	}

	/**
   * Quick topic validation: Subscribe and wait for single message
   * Production-safe: No race conditions, proper cleanup, supports auth + TLS
   */
	private async quickValidateTopic(
		brokerUrl: string, 
		topic: string,
		config?: MqttDiscoveryOptions
	): Promise<boolean> {
		return new Promise((resolve) => {
			let resolved = false;

			// Safe resolve: Prevent race condition from multiple callbacks
			const safeResolve = (value: boolean) => {
				if (!resolved) {
					resolved = true;
					resolve(value);
				}
			};

			const client = this.mqttFactory(brokerUrl, {
				clientId: `iotistic-validate-${Date.now()}`,
				clean: true,
				reconnectPeriod: 0,
				// Use credentials from config for consistent auth
				username: config?.username,
				password: config?.password,
				// TLS support
				ca: config?.ca,
				cert: config?.cert,
				key: config?.key,
				rejectUnauthorized: config?.rejectUnauthorized ?? true
			});

			let messageReceived = false;
			const timeout = setTimeout(() => {
				// Cleanup before resolving
				client.removeAllListeners('message');
				client.removeAllListeners('error');
				client.removeAllListeners('connect');
				client.end(true);
				safeResolve(messageReceived);
			}, 5000); // 5 second validation window

			const connectHandler = () => {
				client.subscribe(topic, { qos: 0 }, (err) => {
					if (err) {
						clearTimeout(timeout);
						client.removeAllListeners('message');
						client.removeAllListeners('error');
						client.removeAllListeners('connect');
						client.end(true);
						safeResolve(false);
					}
				});
			};

			const messageHandler = (receivedTopic: string) => {
				if (receivedTopic === topic) {
					messageReceived = true;
					clearTimeout(timeout);
					client.removeAllListeners('message');
					client.removeAllListeners('error');
					client.removeAllListeners('connect');
					client.end(true);
					safeResolve(true);
				}
			};

			const errorHandler = () => {
				clearTimeout(timeout);
				client.removeAllListeners('message');
				client.removeAllListeners('error');
				client.removeAllListeners('connect');
				client.end(true);
				safeResolve(false);
			};

			client.on('connect', connectHandler);
			client.on('message', messageHandler);
			client.on('error', errorHandler);
		});
	}

	/**
   * Check if MQTT client library is available
   */
	async isAvailable(): Promise<boolean> {
		// MQTT module is a hard dependency and already imported at the top of this file
		// If the module wasn't available, this file wouldn't even load
		return true;
	}

	/**
   * Cleanup MQTT client with proper event listener removal
   * Production rule: Every listener added must be cleaned up
   */
	private cleanupClient(): void {
		if (this.client) {
			this.client.removeAllListeners('message');
			this.client.removeAllListeners('error');
			this.client.removeAllListeners('connect');
			this.client.end(true);
			this.client = undefined;
		}
	}
}

/**
 * MQTT Payload Parser Utilities
 * 
 * Pure functions for parsing and type-coercing MQTT payloads.
 * Extracted from adapter for better testability and reusability.
 * 
 * @module mqtt/payload-parser
 */

/**
 * Parse MQTT payload based on dataType
 * 
 * Strategy:
 * 1. Try JSON parse first
 * 2. If valid JSON, return parsed object/primitive
 * 3. Otherwise, return plain text
 * 
 * @param payload - Raw MQTT message buffer
 * @returns Parsed raw value (object, array, primitive, or string)
 */
export function parsePayload(payload: Buffer): unknown {
	const str = payload.toString();

	// Try JSON first
	try {
		return JSON.parse(str);
	} catch {
		// Not JSON, return as plain text
		return str;
	}
}

/**
 * Coerce value to expected dataType
 * 
 * Supports both:
 * - Broad types from discovery: 'number', 'boolean', 'string', 'json'
 * - Specific types from manual config: 'int32', 'float32', 'uint32'
 * 
 * Production-safe: Detects NaN and throws error rather than silently returning invalid data
 * 
 * @param value - Value to coerce (any type)
 * @param dataType - Target data type
 * @returns Coerced value
 * @throws Error if coercion results in NaN for numeric types
 */
export function coerceType(value: any, dataType: string): number | boolean | string {
	const valueForError =
    typeof value === 'object' && value !== null
	? JSON.stringify(value)
	: String(value);

	switch (dataType) {
		case 'number':  // Broad category from discovery
		case 'float':
		case 'float32':
		case 'double': {
			const n = parseFloat(value);
			// Production fix: Detect NaN and throw error
			if (Number.isNaN(n)) {
				throw new Error(`Numeric coercion resulted in NaN for value: "${valueForError}"`);
			}
			return n;
		}
		case 'int':
		case 'int16':
		case 'int32':
		case 'integer': {
			const n = parseInt(value, 10);
			// Production fix: Detect NaN and throw error
			if (Number.isNaN(n)) {
				throw new Error(`Numeric coercion resulted in NaN for value: "${valueForError}"`);
			}
			return n;
		}
		case 'uint16':
		case 'uint32': {
			const n = Math.abs(parseInt(value, 10));
			// Production fix: Detect NaN and throw error
			if (Number.isNaN(n)) {
				throw new Error(`Numeric coercion resulted in NaN for value: "${valueForError}"`);
			}
			return n;
		}
		case 'boolean':
			return value === 'true' || value === '1' || value === 1 || value === true;
		case 'json':    // Broad category from discovery
			// For JSON dataType with object value, stringify it; otherwise convert to string
			return typeof value === 'object' && value !== null ? JSON.stringify(value) : String(value);
		case 'string':
			return String(value);
		default:
			return String(value);
	}
}

/**
 * SNMP Discovery Plugin
 * 
 * Discovers SNMP devices via network scanning
 * Supports SNMPv1, v2c, and v3
 * 
 * Discovery Strategy:
 * - IP range scanning with SNMP Get requests
 * - sysDescr (1.3.6.1.2.1.1.1.0) as primary detection
 * - Validation reads additional OIDs for device identification
 * 
 * Industrial Best Practice:
 * - Concurrent scanning with rate limiting
 * - Respect network bandwidth (avoid broadcast storms)
 * - Standard MIB-II OIDs for maximum compatibility
 */

import type { AgentLogger } from '../../logging/agent-logger';
import { LogComponents } from '../../logging/types';
import { BaseDiscoveryPlugin, DiscoveredDevice, ValidationResult } from '../types';
import { generateSNMPFingerprint } from '../fingerprint';
import type { ConfigManager } from '../../agent/config.js';
import * as dns from 'dns';
import { promisify } from 'util';
import { pLimit } from '../../lib/p-limit.js';

const dnsLookup = promisify(dns.lookup);

export interface SNMPDiscoveryOptions {
  ipRanges?: string[];          // e.g., ['192.168.1.0/24', '10.0.0.1-10.0.0.50']
  port?: number;                // Default: 161
  community?: string;           // SNMPv1/v2c community (default: 'public')
  version?: 'v1' | 'v2c' | 'v3'; // SNMP version (default: 'v2c')
  timeout?: number;             // ms per device scan (default: 2000)
  retries?: number;             // Retry count (default: 1)
  concurrency?: number;         // Concurrent scans (default: 10)
  // SNMPv3 options (if version='v3')
  v3Username?: string;
  v3AuthProtocol?: 'MD5' | 'SHA';
  v3AuthKey?: string;
  v3PrivProtocol?: 'DES' | 'AES';
  v3PrivKey?: string;
}

interface SNMPDeviceInfo {
  sysDescr: string;
  sysObjectID?: string;
  sysName?: string;
  sysLocation?: string;
  sysContact?: string;
  sysUpTime?: number;
}

export class SNMPDiscoveryPlugin extends BaseDiscoveryPlugin {
	private configManager?: ConfigManager;

	constructor(logger?: AgentLogger, configManager?: ConfigManager) {
		super('snmp', logger);
		this.configManager = configManager;
	}

	/**
   * Phase 1: Fast IP range scanning for SNMP responders
   */
	async discover(options?: SNMPDiscoveryOptions): Promise<DiscoveredDevice[]> {
		const discovered: DiscoveredDevice[] = [];

		// Get discovery targets from endpoints (those with community but no dataPoints)
		const discoveryTargets = this.configManager?.getDiscoveryTargets?.('snmp') || [];

		if (discoveryTargets.length === 0) {
			this.logger?.debugSync('No SNMP discovery targets configured (need community without dataPoints)', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				protocol: this.protocol
			});
			return [];
		}

		this.logger?.debugSync(`Starting SNMP discovery (${discoveryTargets.length} targets)`, {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			protocol: this.protocol,
			phase: 'discovery',
			targetCount: discoveryTargets.length
		});

		// Build list of hosts to scan with their connection metadata
		const hostsToScan: Array<{ 
      ip: string; 
      port: number;
      community: string;
      connectionName?: string; 
      connectionUuid?: string;
      timeout?: number;
      retries?: number;
    }> = [];

		for (const endpoint of discoveryTargets) {
			const conn = endpoint.connection;
			if (!conn?.host || !conn?.community) continue;

			const ips = await this.expandIPRanges([conn.host]);
			ips.forEach(ip => hostsToScan.push({ 
				ip,
				port: conn.port || 161,
				community: conn.community,
				connectionName: endpoint.name,
				connectionUuid: endpoint.uuid,
				timeout: conn.timeout || 2000,
				retries: conn.retries || 1
			}));
		}

		// Filter out gateway IPs
		const nonGatewayHosts = hostsToScan.filter(h => !h.ip.endsWith('.1'));
		const gatewayCount = hostsToScan.length - nonGatewayHosts.length;
		if (gatewayCount > 0) {
			this.logger?.debugSync(`Skipped ${gatewayCount} gateway IPs`, {
				component: LogComponents.discovery + "] [" + this.protocol as any
			});
		}

		this.logger?.debugSync(`Scanning ${nonGatewayHosts.length} IP addresses for SNMP devices`, {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			totalIPs: nonGatewayHosts.length
		});

		// Concurrent scanning with rate limiting
		const concurrency = options?.concurrency || 10;
		const limit = pLimit(concurrency);

		const scanResults = await Promise.allSettled(
			nonGatewayHosts.map(({ ip, port, community, connectionName, connectionUuid, timeout, retries }) =>
				limit(async () => {
					try {
						const deviceInfo = await this.testSNMPDevice(
							ip,
							port,
							community,
							'v2c', // Default to v2c
							timeout || 2000,
							retries || 1
						);

						if (deviceInfo) {
							// Generate cryptographic fingerprint
							const fingerprint = generateSNMPFingerprint(ip, deviceInfo.sysObjectID || deviceInfo.sysDescr);

							const device: DiscoveredDevice = {
								name: this.generateDeviceName(ip, deviceInfo),
								protocol: 'snmp' as any, // Will be fixed in base interface
								fingerprint,
								connection: {
									host: ip,
									port,
									community, // Always use from endpoint
									timeout,
									retries,
									connectionName,
									connectionUuid
								},
								dataPoints: this.generateDefaultDataPoints(deviceInfo),
								confidence: 'medium',
								discoveredAt: new Date().toISOString(),
								validated: false,
								metadata: {
									ipAddress: ip,
									port,
									community,
									sysDescr: deviceInfo.sysDescr,
									sysObjectID: deviceInfo.sysObjectID,
									discoveryMethod: 'sysDescr-read'
								}
							};

							this.logger?.debugSync(`Discovered SNMP device at ${ip}`, {
								component: LogComponents.discovery + "] [" + this.protocol as any,
								phase: 'discovery',
								sysDescr: deviceInfo.sysDescr?.substring(0, 50) + '...'
							});

							return device;
						}

						return null;
					} catch (error) {
						this.logger?.debugSync(`No SNMP response from ${ip}`, {
							component: LogComponents.discovery + "] [" + this.protocol as any,
							error: (error as Error).message
						});
						return null;
					}
				})
			)
		);

		// Collect successful discoveries
		for (const result of scanResults) {
			if (result.status === 'fulfilled' && result.value) {
				discovered.push(result.value);
			}
		}

		this.logger?.debugSync(`SNMP discovery complete: ${discovered.length} devices found`, {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			totalScanned: nonGatewayHosts.length,
			discovered: discovered.length
		});

		return discovered;
	}

	/**
   * Phase 2: Validate device (read additional OIDs for identification)
   */
	async validate(device: DiscoveredDevice, timeout = 5000): Promise<ValidationResult | null> {
		this.logger?.debugSync('Validating SNMP device', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			host: device.connection.host,
			phase: 'validation'
		});

		try {
			const snmp = await this.createSNMPSession(device.connection);

			// Read additional system info OIDs
			const oids = [
				'1.3.6.1.2.1.1.1.0',  // sysDescr
				'1.3.6.1.2.1.1.2.0',  // sysObjectID
				'1.3.6.1.2.1.1.4.0',  // sysContact
				'1.3.6.1.2.1.1.5.0',  // sysName
				'1.3.6.1.2.1.1.6.0',  // sysLocation
				'1.3.6.1.2.1.1.7.0'   // sysServices
			];

			const varbinds = await this.snmpGet(snmp, oids, timeout);

			// Parse results
			const sysDescr = varbinds[0]?.value?.toString() || '';
			const sysObjectID = varbinds[1]?.value?.toString() || '';
			const sysContact = varbinds[2]?.value?.toString() || '';
			const sysName = varbinds[3]?.value?.toString() || '';
			const sysLocation = varbinds[4]?.value?.toString() || '';
			const sysServices = varbinds[5]?.value || 0;

			// Extract manufacturer and model from sysDescr
			const { manufacturer, modelNumber } = this.parseSysDescr(sysDescr);

			const validationResult: ValidationResult = {
				manufacturer,
				modelNumber,
				firmwareVersion: this.extractFirmwareVersion(sysDescr),
				capabilities: this.parseCapabilities(sysServices as number),
				deviceInfo: {
					sysDescr,
					sysObjectID,
					sysContact,
					sysName,
					sysLocation,
					sysServices
				}
			};

			this.logger?.debugSync('SNMP device validated', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				host: device.connection.host,
				manufacturer,
				model: modelNumber,
				phase: 'validation'
			});

			snmp.close();
			return validationResult;

		} catch (error) {
			this.logger?.warnSync('SNMP validation failed', {
				component: LogComponents.discovery + "] [" + this.protocol as any,
				host: device.connection.host,
				error: (error as Error).message
			});
			return null;
		}
	}

	/**
   * Check if SNMP is available (net-snmp library)
   */
	async isAvailable(): Promise<boolean> {
		try {
			await import('net-snmp');
			return true;
		} catch {
			this.logger?.debugSync('net-snmp library not available', {
				component: LogComponents.discovery + "] [" + this.protocol as any
			});
			return false;
		}
	}

	/**
   * Test single IP for SNMP response
   */
	private async testSNMPDevice(
		ip: string,
		port: number,
		community: string,
		version: string,
		timeout: number,
		retries: number
	): Promise<SNMPDeviceInfo | null> {
		try {
			const snmp = await import('net-snmp');

			// Create SNMP session
			let session: any;
			if (version === 'v3') {
				// SNMPv3 requires user object - skip for now in discovery
				// Would need v3Username, authKey, etc. from options
				return null;
			} else {
				session = snmp.createSession(ip, community, {
					port,
					retries,
					timeout
				});
			}

			// Read sysDescr (1.3.6.1.2.1.1.1.0) as primary detection
			const oid = '1.3.6.1.2.1.1.1.0';

			return new Promise((resolve, reject) => {
				session.get([oid], (error: Error | null, varbinds: any[]) => {
					session.close();

					if (error) {
						reject(error);
						return;
					}

					if (varbinds && varbinds.length > 0 && !snmp.isVarbindError(varbinds[0])) {
						const sysDescr = varbinds[0].value.toString();
						resolve({
							sysDescr
						});
					} else {
						resolve(null);
					}
				});
			});

		} catch (_error) {
			return null;
		}
	}

	/**
   * Create SNMP session with full configuration
   */
	private async createSNMPSession(connection: any): Promise<any> {
		const snmp = await import('net-snmp');

		if (connection.version === 'v3') {
			const user = {
				name: connection.username,
				level: snmp.SecurityLevel.authPriv,
				authProtocol: connection.authProtocol === 'SHA' 
					? snmp.AuthProtocols.sha 
					: snmp.AuthProtocols.md5,
				authKey: connection.authKey,
				privProtocol: connection.privProtocol === 'AES'
					? snmp.PrivProtocols.aes
					: snmp.PrivProtocols.des,
				privKey: connection.privKey
			};

			return snmp.createV3Session(connection.host, user, {
				port: connection.port,
				retries: connection.retries,
				timeout: connection.timeout
			});
		} else {
			return snmp.createSession(connection.host, connection.community, {
				port: connection.port,
				retries: connection.retries,
				timeout: connection.timeout,
				version: connection.version === 'v1' ? snmp.Version1 : snmp.Version2c
			});
		}
	}

	/**
   * Perform SNMP GET request
   */
	private async snmpGet(session: any, oids: string[], timeout: number): Promise<any[]> {
		return new Promise((resolve, reject) => {
			let timedOut = false;

			const timer = setTimeout(() => {
				timedOut = true;
				// Don't close session inside timeout closure - let caller handle cleanup
				// This prevents closure retention in survivor space
				reject(new Error('SNMP GET timeout'));
			}, timeout);

			session.get(oids, (error: Error | null, varbinds: any[]) => {
				clearTimeout(timer);

				if (timedOut) {
					// Request already timed out, ignore result
					return;
				}

				if (error) {
					reject(error);
				} else {
					resolve(varbinds || []);
				}
			});
		});
	}

	/**
   * Get default IP ranges from environment or local network
   * 
   * @deprecated This method is dangerous and should not be used
   * It defaults to scanning entire subnets which floods the network
   * Always explicitly configure IP ranges via SNMP_IP_RANGES env var
   */
	private getDefaultIPRanges(): string[] {
		const envRanges = process.env.SNMP_IP_RANGES;
		if (envRanges) {
			return envRanges.split(',').map(r => r.trim());
		}

		// DO NOT auto-detect networks - this causes network flooding
		// Return empty array instead
		this.logger?.warnSync('getDefaultIPRanges() called but SNMP_IP_RANGES not set - network scan prevented', {
			component: LogComponents.discovery + "] [" + this.protocol as any,
			note: 'Set SNMP_IP_RANGES env var to enable SNMP discovery'
		});
		return [];
	}

	/**
   * Expand IP ranges to individual IPs
   * Supports CIDR notation (192.168.1.0/24) and ranges (192.168.1.1-192.168.1.50)
   */
	private async expandIPRanges(ranges: string[]): Promise<string[]> {
		const ips: string[] = [];

		for (const range of ranges) {
			if (range.includes('/')) {
				// CIDR notation
				ips.push(...this.expandCIDR(range));
			} else if (range.includes('-')) {
				// IP range
				ips.push(...this.expandRange(range));
			} else if (this.isValidIP(range)) {
				// Single IP
				ips.push(range);
			} else {
				// Hostname/container name - resolve to IP
				this.logger?.debugSync(`Attempting to resolve hostname: ${range}`, {
					component: LogComponents.discovery + "] [" + this.protocol as any
				});
				try {
					const resolved = await dnsLookup(range);
					ips.push(resolved.address);
					this.logger?.debugSync(`Resolved hostname ${range} to ${resolved.address}`, {
						component: LogComponents.discovery + "] [" + this.protocol as any
					});
				} catch (error) {
					this.logger?.errorSync(
						`Failed to resolve hostname: ${range}`,
            error as Error,
            {
	component: LogComponents.discovery + "] [" + this.protocol as any,
	note: 'Make sure container/hostname is reachable'
            }
					);
				}
			}
		}

		return ips;
	}

	/**
   * Check if string is a valid IPv4 address
   */
	private isValidIP(str: string): boolean {
		const parts = str.split('.');
		if (parts.length !== 4) return false;
		return parts.every(part => {
			const num = parseInt(part, 10);
			return num >= 0 && num <= 255 && part === num.toString();
		});
	}

	/**
   * Expand CIDR notation to IP list
   */
	private expandCIDR(cidr: string): string[] {
		const [network, maskBits] = cidr.split('/');
		const mask = parseInt(maskBits, 10);

		if (mask < 16 || mask > 32) {
			this.logger?.warnSync(`Skipping CIDR ${cidr}: mask must be /16 to /32`, {
				component: LogComponents.discovery + "] [" + this.protocol as any
			});
			return [];
		}

		const ips: string[] = [];
		const parts = network.split('.').map(Number);
		const hostCount = Math.pow(2, 32 - mask);

		// Limit to reasonable scan size (max 1024 IPs)
		const maxIPs = Math.min(hostCount - 2, 1024); // -2 for network and broadcast

		const baseIP = (parts[0] << 24) + (parts[1] << 16) + (parts[2] << 8) + parts[3];

		for (let i = 1; i <= maxIPs; i++) {
			const ip = baseIP + i;
			const ipStr = [
				(ip >>> 24) & 255,
				(ip >>> 16) & 255,
				(ip >>> 8) & 255,
				ip & 255
			].join('.');
			ips.push(ipStr);
		}

		return ips;
	}

	/**
   * Expand IP range to IP list (e.g., 192.168.1.1-192.168.1.50)
   */
	private expandRange(range: string): string[] {
		const [start, end] = range.split('-').map(s => s.trim());
		const startParts = start.split('.').map(Number);
		const endParts = end.split('.').map(Number);

		const ips: string[] = [];
		const startIP = (startParts[0] << 24) + (startParts[1] << 16) + (startParts[2] << 8) + startParts[3];
		const endIP = (endParts[0] << 24) + (endParts[1] << 16) + (endParts[2] << 8) + endParts[3];

		// Limit to reasonable scan size
		const count = Math.min(endIP - startIP + 1, 1024);

		for (let i = 0; i < count; i++) {
			const ip = startIP + i;
			const ipStr = [
				(ip >>> 24) & 255,
				(ip >>> 16) & 255,
				(ip >>> 8) & 255,
				ip & 255
			].join('.');
			ips.push(ipStr);
		}

		return ips;
	}

	/**
   * Generate device name from IP and device info
   */
	private generateDeviceName(ip: string, info: SNMPDeviceInfo): string {
		if (info.sysName) {
			return info.sysName.toLowerCase().replace(/[^a-z0-9_-]/g, '_');
		}

		// Use last octet of IP
		const lastOctet = ip.split('.').pop();
		return `snmp_device_${lastOctet}`;
	}

	/**
   * Generate default data points from device info
   */
	private generateDefaultDataPoints(_info: SNMPDeviceInfo): any[] {
		return [
			{
				name: 'sysName',
				oid: '1.3.6.1.2.1.1.5.0',
				unit: '',
				dataType: 'string'
			},
			{
				name: 'sysUpTime',
				oid: '1.3.6.1.2.1.1.3.0',
				unit: 'timeticks',
				dataType: 'timeticks'
			}
		];
	}

	/**
   * Parse manufacturer and model from sysDescr
   */
	private parseSysDescr(sysDescr: string): { manufacturer?: string; modelNumber?: string } {
		// Common patterns in sysDescr:
		// "Cisco IOS Software, C2960 Software..."
		// "Linux hostname 4.19.0-17-amd64..."
		// "HP ProCurve Switch 2824..."

		const patterns = [
			/^(\w+)\s+(.+?)\s+(?:Software|Switch)/i, // Cisco, HP, etc.
			/^(Linux|Windows|FreeBSD)/i,              // OS-based
			/^(.+?)\s+Version/i                       // Generic "Product Version"
		];

		for (const pattern of patterns) {
			const match = sysDescr.match(pattern);
			if (match) {
				return {
					manufacturer: match[1],
					modelNumber: match[2]
				};
			}
		}

		return {};
	}

	/**
   * Extract firmware version from sysDescr
   */
	private extractFirmwareVersion(sysDescr: string): string | undefined {
		const versionMatch = sysDescr.match(/Version\s+([0-9.]+)/i);
		return versionMatch ? versionMatch[1] : undefined;
	}

	/**
   * Parse capabilities from sysServices integer
   */
	private parseCapabilities(sysServices: number): string[] {
		const capabilities: string[] = [];

		if (sysServices & 1) capabilities.push('physical');
		if (sysServices & 2) capabilities.push('datalink');
		if (sysServices & 4) capabilities.push('internet');
		if (sysServices & 8) capabilities.push('end-to-end');
		if (sysServices & 64) capabilities.push('application');

		return capabilities;
	}
}

import { z } from 'zod';
