		const envTargets = process.env.BACNET_DISCOVERY_TARGETS?.split(",")
			.map((t) => t.trim())
			.filter(Boolean);
		const discoveryTargets = cloudProtocol?.discoveryTargets || envTargets;

		return {
			enabled: cloudProtocol?.enabled ?? false,
			port: cloudProtocol?.port ?? 47808,
			...(discoveryTargets &&
        discoveryTargets.length > 0 && { discoveryTargets }),
			...(cloudProtocol?.broadcastAddress && {
				broadcastAddress: cloudProtocol.broadcastAddress,
			}),
			timeout: cloudProtocol?.timeout ?? 5000,
			maxDevices: cloudProtocol?.maxDevices ?? 100,
		};
