	// ==================== NORMALIZATION ====================

	/**
   * Normalize device property names (camelCase ΓåÆ snake_case)
   * Handles both API and SQLite conventions
   * CRITICAL: UUID is the canonical endpoint identifier.
   */
	public normalizeDevice(device: ProtocolAdapterDevice): any {
		const deviceAny = device as any;

		const uuid = device.uuid;

		if (!uuid) {
			this.logger?.warnSync("Device missing uuid field", {
				component: LogComponents.configManager,
				operation: "normalizeDevice",
				deviceName: device.name,
				deviceProtocol: device.protocol,
				reason: "UUID is required for endpoint reconciliation",
			});
		}

		return {
			uuid,
			name: device.name,
			protocol: device.protocol,
			enabled: device.enabled !== undefined ? device.enabled : true,
			poll_interval: deviceAny.pollInterval || deviceAny.poll_interval || 5000,
			connection: deviceAny.connection,
			data_points:
        deviceAny.dataPoints || deviceAny.data_points || deviceAny.registers,
			metadata: deviceAny.metadata,
		};
	}

	/**
   * Main reconciliation logic
   */
	public async reconcile(): Promise<ConfigReconciliationResult> {
		this.logger?.infoSync("Starting config reconciliation", {
			component: LogComponents.configManager,
			operation: "reconcile",
		});

		const result: ConfigReconciliationResult = {
			success: true,
			devicesRegistered: 0,
			devicesUpdated: 0,
			devicesUnregistered: 0,
			errors: [],
			timestamp: new Date(),
		};

		try {
			// First, copy all non-device fields from target to current config
			// This ensures logging, features, settings, etc. are always up-to-date
			const { endpoints: _targetEndpoints, ...otherTargetFields } =
        this.targetConfig;
			const { endpoints: currentEndpoints, ...otherCurrentFields } =
        this.currentConfig;

			// Detect feature changes before merging
			const oldFeatures = this.currentConfig.features;
			const newFeatures = otherTargetFields.features;

			// Merge non-device fields into current config
			Object.assign(this.currentConfig, otherTargetFields);

			// Restore endpoints array (will be reconciled separately)
			if (currentEndpoints) {
				this.currentConfig.endpoints = currentEndpoints;
			}

			// Emit feature change event if features changed OR if this is first-time config load
			if (
				newFeatures &&
        (!oldFeatures || !deepEqual(oldFeatures, newFeatures))
			) {
				this.emit("features-changed", {
					old: oldFeatures || {},
					new: newFeatures,
				});

				const changes = oldFeatures
					? Object.keys(newFeatures).filter(
						(key) => oldFeatures[key] !== newFeatures[key],
					)
					: Object.keys(newFeatures);

				this.logger?.infoSync("Feature configuration changed", {
					component: LogComponents.configManager,
					operation: "reconcile",
					isFirstLoad: !oldFeatures,
					changes,
				});
			}

			// Emit anomaly config change event if anomaly config changed.
			// Primary key is anomalyDetection; anomaly is legacy compatibility.
			const oldAnomalyConfig =
        otherCurrentFields.anomalyDetection ?? otherCurrentFields.anomaly;
			const newAnomalyConfig =
        otherTargetFields.anomalyDetection ?? otherTargetFields.anomaly;
			if (newAnomalyConfig && !deepEqual(oldAnomalyConfig, newAnomalyConfig)) {
				this.emit("anomaly-config-changed", {
					old: oldAnomalyConfig,
					new: newAnomalyConfig,
				});

				this.logger?.infoSync("Anomaly configuration changed", {
					component: LogComponents.configManager,
					operation: "reconcile",
				});
			}

			// Sync endpoints to SQLite using UUID-based operations
			// This replaces the separate ProtocolAdaptersHandler logic
			await this.syncDevicesToDatabase();

			// Refresh in-memory current endpoints from canonical database state.
			// This prevents stale snapshot IDs (legacy name-based ids) from bypassing strict UUID reconciliation.
			const dbCurrentConfig = await this.getCurrentConfig();
			this.currentConfig.endpoints = dbCurrentConfig.endpoints || [];

			// Calculate steps for sensor reconciliation
			const steps = this.calculateSteps();

			if (steps.length === 0) {
				this.logger?.infoSync("No device config changes needed", {
					component: LogComponents.configManager,
					operation: "reconcile",
				});

				// Even if no sensor changes, save current config to persist other field updates
				await this.saveCurrentConfigToDB();

				return result;
			}

			this.logger?.infoSync("Generated config reconciliation steps", {
				component: LogComponents.configManager,
				operation: "reconcile",
				stepsCount: steps.length,
			});
			// Execute steps
			for (const step of steps) {
				try {
					await this.executeStep(step);

					// Update result counters
					if (step.action === "registerDevice") {
						result.devicesRegistered++;
					} else if (step.action === "updateDevice") {
						result.devicesUpdated++;
					} else if (step.action === "unregisterDevice") {
						result.devicesUnregistered++;
					}
				} catch (error: any) {
					this.logger?.errorSync(
						"Config step failed",
						error instanceof Error ? error : new Error(String(error)),
						{
							component: LogComponents.configManager,
							operation: "reconcile",
							action: step.action,
							deviceId: step.device?.id || step.deviceId,
						},
					);

					result.success = false;
					result.errors.push({
						deviceId: step.device?.id || step.deviceId || "unknown",
						error: error.message,
					});

					// Continue with remaining steps (K8s style)
				}
			}

			this.logger?.infoSync("Config reconciliation complete", {
				component: LogComponents.configManager,
				operation: "reconcile",
				devicesRegistered: result.devicesRegistered,
				devicesUpdated: result.devicesUpdated,
				devicesUnregistered: result.devicesUnregistered,
				errors: result.errors.length,
			});

			// Save updated config to local database
			await this.saveCurrentConfigToDB();

			this.emit("config-applied");
		} catch (error) {
			this.logger?.errorSync(
				"Critical error during config reconciliation",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "reconcile",
				},
			);
			result.success = false;
			throw error;
		}

		return result;
	}

	/**
   * Sync endpoints to SQLite database using UUID-based operations
   * Integrated from ProtocolAdaptersHandler for unified config management.
   *
   * IMPORTANT:
   * This phase only upserts target endpoints into the local DB.
   * It must NOT delete endpoints that disappeared from target state, because
   * unregisterDevice reconciliation steps are responsible for the full cleanup:
   * - remove endpoint row from local DB
   * - update currentConfig snapshot
   * - drive adapter / publish reload after reconciliation-complete
   *
   * If we delete rows here first, calculateSteps() can miss removals entirely and
   * runtime teardown never runs.
   */
	private async syncDevicesToDatabase(): Promise<void> {
		const devices = this.targetConfig.endpoints || [];

		if (!devices || !Array.isArray(devices) || devices.length === 0) {
			await this.syncMosquittoAuthToFiles([]);
			return;
		}

		try {
			// Get current devices from SQLite to detect deletions
			const currentDevices = await EndpointModel.getAll();

			// Enforce canonical identity: endpoints must have UUID.
			// Rows without UUID cannot participate in strict target-state reconciliation.
			const removedInvalidCount = EndpointModel.deleteMissingUuid();
			if (removedInvalidCount > 0) {
				this.logger?.warnSync(
					"Removed invalid endpoints from database (missing UUID)",
					{
						component: LogComponents.configManager,
						operation: "syncEndpointsToDatabase",
						removedCount: removedInvalidCount,
					},
				);
			}

			// UUID is the canonical endpoint identifier.
			const targetDeviceUuids = new Set(
				devices.map((d: any) => d.uuid).filter(Boolean),
			);

			// For each device in target state
			for (const device of devices) {
				const connection = this.parseConnectionValue(
					device,
					"syncEndpointsToDatabase",
					true,
				);

				if (this.isModbusDiscoveryTarget(device, connection)) {
					this.logger?.debugSync(
						"Skipping discovery target device (has slaveRange)",
						{
							component: LogComponents.configManager,
							operation: "syncEndpointsToDatabase",
							deviceUuid: device.uuid,
							deviceName: device.name,
							connection: connection,
							slaveRange: connection.slaveRange,
							reason:
                "Discovery target - only discovered slaves should be in endpoints table",
						},
					);
					continue; // Skip to next device
				}

				// Normalize property names from cloud API (camelCase) to SQLite (snake_case)
				const normalizedDevice = this.normalizeDevice(
          device as ProtocolAdapterDevice,
				);

				// UUID-only lookup
				let existing: any = null;
				try {
					if (!normalizedDevice.uuid) {
						this.logger?.warnSync(
							"Skipping endpoint without UUID during sync",
							{
								component: LogComponents.configManager,
								operation: "syncEndpointsToDatabase",
								deviceName: normalizedDevice.name,
								protocol: normalizedDevice.protocol,
							},
						);
						continue;
					}

					existing = await EndpointModel.getByUuid(normalizedDevice.uuid);
				} catch (lookupError) {
					this.logger?.warnSync(
						"Failed to lookup existing device, treating as new",
						{
							component: LogComponents.configManager,
							operation: "syncEndpointsToDatabase",
							deviceUuid: normalizedDevice.uuid,
							deviceName: normalizedDevice.name,
							error:
                lookupError instanceof Error
	? lookupError.message
	: String(lookupError),
						},
					);
					// Continue as if device doesn't exist - will trigger CREATE path
				}

				if (existing) {
					this.logger?.infoSync("Found existing device in DB", {
						component: LogComponents.configManager,
						operation: "syncEndpointsToDatabase",
						agentUuid: existing.uuid,
						agentName: existing.name,
						existingDataPointsCount: existing.data_points?.length || 0,
					});

					// CRITICAL: Preserve discovered data_points if target state has empty array
					// This prevents reconciliation from overwriting discovery results
					// Flow: Discovery finds nodes ΓåÆ saves to DB ΓåÆ cloud syncs ΓåÆ reconcile runs
					// Without this check, reconcile would overwrite with cloud's empty array
					const shouldPreserveDataPoints =
            existing.data_points &&
            existing.data_points.length > 0 &&
            (!normalizedDevice.data_points ||
              normalizedDevice.data_points.length === 0);

					if (shouldPreserveDataPoints) {
						normalizedDevice.data_points = existing.data_points;
					}

					await EndpointModel.updateByUuid(
						normalizedDevice.uuid,
						normalizedDevice,
					);
					this.logger?.infoSync("Updated endpoint in database", {
						component: LogComponents.configManager,
						agentUuid: normalizedDevice.uuid,
						agentName: normalizedDevice.name,
						protocol: normalizedDevice.protocol,
						dataPointsCount: normalizedDevice.data_points?.length || 0,
					});
				} else {
					this.logger?.infoSync("Device NOT found in DB (will CREATE)", {
						component: LogComponents.configManager,
						operation: "syncEndpointsToDatabase",
						agentUuid: normalizedDevice.uuid,
						agentName: normalizedDevice.name,
						targetDataPointsCount: normalizedDevice.data_points?.length || 0,
					});

					// CRITICAL: Check for discovered data_points in discovery cache
					// When a new device is created during reconciliation, the cloud doesn't have
					// the discovered nodes yet, so dataPoints will be empty. But discovery may have
					// just run and cached the results. Check cache before creating with empty array.
					const endpointUrl = normalizedDevice.connection?.endpointUrl;
					if (endpointUrl && this.discoveryService) {
						this.logger?.debugSync("Checking discovery cache for new device", {
							component: LogComponents.configManager,
							operation: "syncEndpointsToDatabase",
							endpointUrl,
							hasDiscoveryService: !!this.discoveryService,
							hasGetMethod: !!this.discoveryService.getDiscoveredDevice,
						});

						const discoveredDevice =
              this.discoveryService.getDiscoveredDevice?.(endpointUrl);
						if (
							discoveredDevice &&
              discoveredDevice.dataPoints &&
              discoveredDevice.dataPoints.length > 0
						) {
							this.logger?.debugSync(
								"Γ£à USING cached discovered data_points (CREATE path)",
								{
									component: LogComponents.configManager,
									agentUuid: normalizedDevice.uuid,
									agentName: normalizedDevice.name,
									endpointUrl,
									cachedDataPointsCount: discoveredDevice.dataPoints.length,
									reason: "Found in discovery cache - using cached nodes",
								},
							);

							// Use discovered data_points instead of empty array from target state
							normalizedDevice.data_points = discoveredDevice.dataPoints;
						} else {
							this.logger?.debugSync("ΓÜá∩╕Å Discovery cache MISS for new device", {
								component: LogComponents.configManager,
								agentUuid: normalizedDevice.uuid,
								agentName: normalizedDevice.name,
								endpointUrl,
								cacheHit: !!discoveredDevice,
								hasDataPoints: discoveredDevice?.dataPoints?.length || 0,
								reason:
                  "Will create with empty data_points - discovery may not have run yet",
							});
						}
					} else {
						const protocol = String(
							normalizedDevice.protocol || "",
						).toLowerCase();
						const logFn = endpointUrl
							? this.logger?.warnSync.bind(this.logger)
							: this.logger?.debugSync.bind(this.logger);

						logFn?.("ΓÜá∩╕Å Cannot check discovery cache", {
							component: LogComponents.configManager,
							agentUuid: normalizedDevice.uuid,
							agentName: normalizedDevice.name,
							protocol,
							hasEndpointUrl: !!endpointUrl,
							hasDiscoveryService: !!this.discoveryService,
							reason: endpointUrl
								? "No discoveryService"
								: "No endpointUrl (expected for some protocols like mqtt)",
						});
					}

					await EndpointModel.create(normalizedDevice);

					// CRITICAL: Verify what was actually saved to DB
					let verifyInsert: any = null;
					try {
						verifyInsert = await EndpointModel.getByUuid(normalizedDevice.uuid);
					} catch (verifyError) {
						this.logger?.warnSync("Failed to verify inserted endpoint", {
							component: LogComponents.configManager,
							agentName: normalizedDevice.name,
							agentUuid: normalizedDevice.uuid,
							error:
                verifyError instanceof Error
	? verifyError.message
	: String(verifyError),
						});
					}

					this.logger?.infoSync("Added endpoint to database", {
						component: LogComponents.configManager,
						agentUuid: normalizedDevice.uuid,
						agentName: normalizedDevice.name,
						protocol: normalizedDevice.protocol,
						dataPointsCount: normalizedDevice.data_points?.length || 0,
						dbDataPointsCount: verifyInsert?.data_points?.length || 0,
						dbFirstDataPoint: verifyInsert?.data_points?.[0] || null,
						verificationMethod: "by-uuid",
					});
				}
			}

			const pendingRemovalDevices = currentDevices.filter(
				(currentDevice) =>
					currentDevice.uuid && !targetDeviceUuids.has(currentDevice.uuid),
			);

			if (pendingRemovalDevices.length > 0) {
				this.logger?.infoSync(
					"Endpoints missing from target state will be removed during unregister reconciliation",
					{
						component: LogComponents.configManager,
						operation: "syncEndpointsToDatabase",
						removedCount: pendingRemovalDevices.length,
						removedDevices: pendingRemovalDevices.map((device) => ({
							uuid: device.uuid,
							name: device.name,
							protocol: device.protocol,
						})),
					},
				);
			}

			await this.syncMosquittoAuthToFiles(devices);
		} catch (error) {
			this.logger?.errorSync(
				"Failed to sync endpoints to database",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "syncEndpointsToDatabase",
				},
			);
		}
	}
	private async syncMosquittoAuthToFiles(devices: any[]): Promise<void> {
		try {
			const reconciler = new MqttFileAuthReconciler(this.logger);
			const rawDocker = (this.containerManager as any)?.getDocker?.();
			const dockerManager: MqttAuthContainerManager | undefined = rawDocker
				? {
					findContainerByName: async (name: string) => {
						const all = await rawDocker.listContainers({ all: true });
						const found = (all as any[]).find((c) =>
							(c.Names as string[]).some((n) => n === `/${name}`),
						);
						return found ? rawDocker.getContainer(found.Id) : null;
					},
				}
				: undefined;

			const result = await reconciler.reconcile(devices, {
				authDir: resolveMosquittoAuthDir(),
				containerName: "iotistic-mosquitto-agent",
				dockerManager,
			});

			if (result.changed) {
				this.logger?.infoSync("Reconciled MQTT file auth", {
					component: LogComponents.configManager,
					operation: "syncMosquittoAuthToFiles",
					users: result.users,
					acls: result.acls,
				});
			}
		} catch (error) {
			this.logger?.errorSync(
				"Failed to reconcile MQTT file auth",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "syncMosquittoAuthToFiles",
				},
			);
		}
	}

	/**
   * Calculate what config changes are needed
   */
	private calculateSteps(): ConfigStep[] {
		const steps: ConfigStep[] = [];

		const allTargetDevices = this.targetConfig.endpoints || [];
		const currentDevices = this.currentConfig.endpoints || [];

		// CRITICAL: Filter out discovery targets (devices with slaveRange)
		// Discovery targets should never be in reconciliation steps - they're config-only
		const filteredTargetDevices = allTargetDevices.filter((agent: any) => {
			const connection = this.parseConnectionValue(agent, "calculateSteps");

			// Skip Modbus discovery targets (have slaveRange)
			if (this.isModbusDiscoveryTarget(agent, connection)) {
				this.logger?.infoSync(
					"Filtered out discovery target from reconciliation steps",
					{
						component: LogComponents.configManager,
						operation: "calculateSteps",
						agentName: agent.name,
						slaveRange: connection.slaveRange,
						reason: "Discovery targets are config-only, not reconciled",
					},
				);
				return false; // Exclude from targetDevices
			}

			return true; // Include in targetDevices
		});

		// Canonicalize target IDs: cloud may send uuid without id.
		const targetDevices = filteredTargetDevices
			.map((agent: any) => {
				const canonicalId = agent.uuid;
				if (!canonicalId) {
					this.logger?.warnSync("Skipping target endpoint without uuid", {
						component: LogComponents.configManager,
						operation: "calculateSteps",
						deviceName: agent.name,
						protocol: agent.protocol,
					});
					return null;
				}

				return {
					...agent,
					id: canonicalId,
				};
			})
			.filter((agent: any) => agent !== null);

		this.logger?.debugSync("Calculating reconciliation steps", {
			component: LogComponents.configManager,
			operation: "calculateSteps",
			allTargetCount: allTargetDevices.length,
			filteredTargetCount: targetDevices.length,
			currentCount: currentDevices.length,
			filteredOut: allTargetDevices.length - targetDevices.length,
		});

		// Build maps for easier comparison
		const targetMap = new Map(
			targetDevices.map((d) => [d.id || (d as any).uuid, d]),
		);
		const currentMap = new Map(
			currentDevices
				.map((d: any) => [d.id || d.uuid, d] as const)
				.filter(([id]) => !!id),
		);

		// Devices to add (in target but not in current)
		for (const device of targetDevices) {
			if (!currentMap.has(device.id)) {
				this.logger?.debugSync("Device needs to be registered", {
					component: LogComponents.configManager,
					operation: "calculateSteps",
					deviceId: device.id,
					deviceName: device.name,
				});

				steps.push({
					action: "registerDevice",
					device: device,
				});
			}
		}

		// Devices to remove (in current but not in target)
		for (const device of currentDevices) {
			const currentDeviceId = (device as any).id || (device as any).uuid;
			if (!currentDeviceId) {
				this.logger?.warnSync(
					"Current endpoint snapshot missing id/uuid during reconciliation",
					{
						component: LogComponents.configManager,
						operation: "calculateSteps",
						deviceName: (device as any).name,
						protocol: (device as any).protocol,
					},
				);
				continue;
			}

			if (!targetMap.has(currentDeviceId)) {
				this.logger?.debugSync("Device needs to be unregistered", {
					component: LogComponents.configManager,
					operation: "calculateSteps",
					deviceId: currentDeviceId,
					deviceName: device.name,
				});

				steps.push({
					action: "unregisterDevice",
					deviceId: currentDeviceId,
				});
			}
		}

		// Devices to update (config changed)
		for (const targetDevice of targetDevices) {
			const targetDeviceId = targetDevice.id || (targetDevice as any).uuid;
			const currentDevice = currentMap.get(targetDeviceId);
			if (currentDevice && !deepEqual(targetDevice, currentDevice)) {
				this.logger?.debugSync("Device needs to be updated", {
					component: LogComponents.configManager,
					operation: "calculateSteps",
					deviceId: targetDeviceId,
					deviceName: targetDevice.name,
				});

				steps.push({
					action: "updateDevice",
					device: targetDevice,
				});
			}
		}

		return steps;
	}

	/**
   * Execute a single config step
   */
	private async executeStep(step: ConfigStep): Promise<void> {
		switch (step.action) {
			case "registerDevice":
				if (step.device) {
					await this.registerEndpoint(step.device);
				}
				break;

			case "updateDevice":
				if (step.device) {
					await this.updateEndpoint(step.device);
				}
				break;

			case "unregisterDevice":
				if (step.deviceId) {
					await this.unregisterEndpoint(step.deviceId);
				}
				break;
		}
	}

	/**
   * Register a protocol adapter device
   */
	private async registerEndpoint(device: ProtocolAdapterDevice): Promise<void> {
		this.logger?.infoSync("Registering protocol adapter device", {
			component: LogComponents.configManager,
			operation: "registerDevice",
			deviceId: device.id,
			deviceName: device.name,
			protocol: device.protocol,
		});

		// Save device to SQLite sensors table
		try {
			const { EndpointModel: DeviceSensorModel } = await import(
				"../db/models/endpoint.model.js"
			);

			const connection = this.resolveAdapterConnection(device);
			const metadata = this.buildEndpointMetadata(device, connection, true);

			// Normalize property names (camelCase ΓåÆ snake_case)
			const normalizedEndpoint: Partial<Endpoint> = {
				name: device.name,
				protocol: device.protocol as any, // Accept any protocol string
				enabled: device.enabled !== undefined ? device.enabled : true,
				poll_interval: device.pollInterval || 5000,
				connection: connection,
				data_points:
          (device as any).dataPoints || (device as any).registers || [],
				metadata: metadata,
			};

			// Use upsert to handle devices that may already exist (e.g., discovered devices)
			await DeviceSensorModel.upsert(normalizedEndpoint as Endpoint);

			this.logger?.infoSync("Device saved to sensors table", {
				component: LogComponents.configManager,
				operation: "registerDevice",
				deviceName: device.name,
			});
		} catch (error) {
			this.logger?.errorSync(
				"Failed to save device to sensors table",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "registerDevice",
					deviceName: device.name,
				},
			);
			throw error;
		}

		// Update current config to reflect the change
		if (!this.currentConfig.endpoints) {
			this.currentConfig.endpoints = [];
		}

		this.currentConfig.endpoints.push(cloneDeep(device));

		// Persist current config to database
		await this.saveCurrentConfigToDB();

		this.emit("device-registered", device);

		this.logger?.infoSync("Device registered successfully", {
			component: LogComponents.configManager,
			operation: "registerDevice",
			deviceName: device.name,
		});
	}

	/**
   * Update a protocol adapter device
   */
	private async updateEndpoint(device: ProtocolAdapterDevice): Promise<void> {
		if (!device.id) {
			throw new Error(
				`updateDevice requires UUID id for device ${device.name}`,
			);
		}

		this.logger?.infoSync("Updating protocol adapter device", {
			component: LogComponents.configManager,
			operation: "updateDevice",
			deviceId: device.id,
			deviceName: device.name,
		});

		// Update device in SQLite sensors table (or create if doesn't exist)
		try {
			const { EndpointModel: DeviceSensorModel } = await import(
				"../db/models/endpoint.model.js"
			);

			const connection = this.resolveAdapterConnection(device);
			const metadata = this.buildEndpointMetadata(device, connection, false);

			// Get existing device first to check for data_points preservation
			const existing = await DeviceSensorModel.getByUuid(device.id);

			// Prepare data_points with preservation logic
			let dataPoints =
        (device as any).dataPoints || (device as any).registers || [];

			// CRITICAL: Preserve discovered data_points if target state has empty array
			// Same logic as syncEndpointsToDatabase() - don't overwrite discovery results
			if (
				existing &&
        existing.data_points &&
        existing.data_points.length > 0 &&
        (!dataPoints || dataPoints.length === 0)
			) {
				this.logger?.debugSync(
					"Preserving existing data_points in updateEndpoint",
					{
						component: LogComponents.configManager,
						deviceName: device.name,
						existingCount: existing.data_points.length,
					},
				);
				dataPoints = existing.data_points;
			}

			// Normalize property names (camelCase ΓåÆ snake_case)
			// Normalize property names (camelCase ΓåÆ snake_case)
			const normalizedDevice = {
				protocol: device.protocol as "modbus" | "can" | "opcua",
				enabled: device.enabled !== undefined ? device.enabled : true,
				poll_interval: device.pollInterval || 5000,
				connection: connection,
				data_points: dataPoints,
				metadata: metadata,
			};

			if (existing) {
				// Device exists - update it
				await DeviceSensorModel.updateByUuid(device.id, normalizedDevice);

				this.logger?.infoSync("Device updated in endpoints table", {
					component: LogComponents.configManager,
					operation: "updateDevice",
					deviceName: device.name,
				});
			} else {
				// Device doesn't exist - create it (upsert behavior)
				await DeviceSensorModel.create({
					uuid: device.id,
					name: device.name,
					...normalizedDevice,
				});

				this.logger?.infoSync(
					"Device created in endpoints table (was missing)",
					{
						component: LogComponents.configManager,
						operation: "updateDevice",
						deviceName: device.name,
					},
				);
			}
		} catch (error) {
			this.logger?.errorSync(
				"Failed to update device in endpoints table",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "updateDevice",
					deviceName: device.name,
				},
			);
			throw error;
		}

		// Update current config
		if (!this.currentConfig.endpoints) {
			this.currentConfig.endpoints = [];
		}

		const endpointIndex = this.currentConfig.endpoints.findIndex(
			(d) => d.id === device.id,
		);

		if (endpointIndex !== -1) {
			this.currentConfig.endpoints[endpointIndex] = cloneDeep(device);
		}

		// Persist current config to database
		await this.saveCurrentConfigToDB();

		this.emit("device-updated", device);

		this.logger?.infoSync("Device updated successfully", {
			component: LogComponents.configManager,
			operation: "updateDevice",
			deviceId: device.id,
		});
	}

	/**
   * Unregister a protocol adapter device
   */
	private async unregisterEndpoint(deviceId: string): Promise<void> {
		this.logger?.infoSync("Unregistering protocol adapter device", {
			component: LogComponents.configManager,
			operation: "unregisterDevice",
			deviceId,
		});

		let device = this.currentConfig.endpoints?.find(
			(d: any) => d.id === deviceId || d.uuid === deviceId,
		);

		if (!device) {
			try {
				const existingEndpoint = await EndpointModel.getByUuid(deviceId);
				if (existingEndpoint) {
					device = {
						id: existingEndpoint.uuid,
						uuid: existingEndpoint.uuid,
						name: existingEndpoint.name,
						protocol: existingEndpoint.protocol,
						enabled: Boolean(existingEndpoint.enabled),
						pollInterval: existingEndpoint.poll_interval,
						metadata: existingEndpoint.metadata,
						dataPoints: existingEndpoint.data_points,
						connectionString: JSON.stringify(existingEndpoint.connection),
					} as any;
				}
			} catch (lookupError) {
				this.logger?.warnSync(
					"Failed to load endpoint from DB during unregister fallback",
					{
						component: LogComponents.configManager,
						operation: "unregisterDevice",
						deviceId,
						error:
              lookupError instanceof Error
	? lookupError.message
	: String(lookupError),
					},
				);
			}
		}

		if (!device) {
			throw new Error(
				`Endpoint not found in current config or DB for deviceId=${deviceId}`,
			);
		}

		// Remove device from SQLite sensors table
		try {
			const { EndpointModel: DeviceSensorModel } = await import(
				"../db/models/endpoint.model.js"
			);
			const deleted = await DeviceSensorModel.deleteByUuid(deviceId);

			if (!deleted) {
				throw new Error(`Failed to delete endpoint row by uuid=${deviceId}`);
			}

			const remainingEndpoint = await DeviceSensorModel.getByUuid(deviceId);
			const verifiedDeleted = !remainingEndpoint;

			this.logger?.infoSync("Device removed from sensors table", {
				component: LogComponents.configManager,
				operation: "unregisterDevice",
				deviceUuid: deviceId,
				deviceName: device.name,
				verifiedDeleted,
				remainingEndpointName: remainingEndpoint?.name,
			});

			if (!verifiedDeleted) {
				this.logger?.warnSync(
					"Endpoint row still exists after delete attempt",
					{
						component: LogComponents.configManager,
						operation: "unregisterDevice",
						deviceUuid: deviceId,
						deviceName: device.name,
						remainingEndpoint,
					},
				);
			}
		} catch (error) {
			this.logger?.errorSync(
				"Failed to remove device from sensors table",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "unregisterDevice",
					deviceName: device.name,
				},
			);
			throw error;
		}

		// Update current config
		if (this.currentConfig.endpoints) {
			this.currentConfig.endpoints = this.currentConfig.endpoints.filter(
				(d: any) => d.id !== deviceId && d.uuid !== deviceId,
			);
		}

		// Persist current config to database
		await this.saveCurrentConfigToDB();

		this.emit("device-unregistered", deviceId);

		this.logger?.infoSync("Device unregistered successfully", {
			component: LogComponents.configManager,
			operation: "unregisterDevice",
			deviceId,
		});
	}

	/**
   * Load current config from database
   * This restores the last reconciled state so we don't re-register devices on restart
   */
	private async loadCurrentConfigFromDB(): Promise<void> {
		try {
			const snapshot = StateSnapshotModel.getLatest("config");

			if (snapshot) {
				this.currentConfig = JSON.parse(snapshot.state);

				// DETAILED DEBUG: Log what was loaded from database
				this.logger?.infoSync("=== LOADED CONFIG FROM DATABASE ===", {
					component: LogComponents.configManager,
					operation: "loadCurrentConfig",
					deviceCount: this.currentConfig.endpoints?.length || 0,
					endpoints: this.currentConfig.endpoints?.map((e: any) => ({
						uuid: e.uuid,
						name: e.name,
						protocol: e.protocol,
						connection: e.connection,
						dataPointsCount: e.dataPoints?.length || 0,
					})),
					createdAt: snapshot.createdAt,
				});
			} else {
				this.logger?.debugSync(
					"No current config in database, starting fresh",
					{
						component: LogComponents.configManager,
						operation: "loadCurrentConfig",
					},
				);
			}
		} catch (error) {
			this.logger?.errorSync(
				"Failed to load current config from DB",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "loadCurrentConfig",
				},
			);
		}
	}

	/**
   * Save current config to database
   * This persists the reconciled state so we can restore it on restart
   */
	private async saveCurrentConfigToDB(): Promise<void> {
		try {
			const configJson = JSON.stringify(this.currentConfig);

			StateSnapshotModel.replace("config", configJson);

			this.logger?.infoSync("Current config saved to database", {
				component: LogComponents.configManager,
				operation: "saveCurrentConfig",
			});
		} catch (error) {
			this.logger?.errorSync(
				"Failed to save current config to DB",
				error instanceof Error ? error : new Error(String(error)),
				{
					component: LogComponents.configManager,
					operation: "saveCurrentConfig",
				},
			);
		}
	}

	// ==================== REACTIVE HANDLERS ====================

	/**
   * Classify endpoint changes (added, removed, modified)
   */
	private classifyEndpointChanges(
		oldEndpoints: any[],
		newEndpoints: any[],
	): {
    added: any[];
    removed: any[];
    modified: any[];
  } {
		const oldMap = new Map(
			oldEndpoints.filter((e) => e.uuid).map((e) => [e.uuid, e]),
		);
		const newMap = new Map(
			newEndpoints.filter((e) => e.uuid).map((e) => [e.uuid, e]),
		);

		const added = newEndpoints.filter((e) => e.uuid && !oldMap.has(e.uuid));
		const removed = oldEndpoints.filter((e) => e.uuid && !newMap.has(e.uuid));
		const modified = newEndpoints.filter((e) => {
			if (!e.uuid) return false;
			const oldEndpoint = oldMap.get(e.uuid);
			return oldEndpoint && !deepEqual(oldEndpoint, e);
		});

		return { added, removed, modified };
	}

	/**
   * Handle logging configuration changes
   */
	public handleLoggingConfigChanges(change: { old: any; new: any }): void {
		if (!this.logger) {
			return;
		}

		// Use change.new directly (targetConfig not updated yet when this event fires)
		const newLogLevel = (change.new?.level ??
      process.env.LOG_LEVEL ??
      "info") as LogLevel;

		// Update log level dynamically
		this.logger.setLogLevel(newLogLevel);

		this.logger.infoSync(
			"Logging configuration updated from cloud - DYNAMIC UPDATE APPLIED",
			{
				component: LogComponents.configManager,
				oldLogLevel: change.old?.level,
				newLogLevel: newLogLevel,
				enableFilePersistence: change.new?.enableFilePersistence,
				enableCompression: change.new?.enableCompression,
				logBatchSize: change.new?.logBatchSize,
				logFlushIntervalMs: change.new?.logFlushIntervalMs,
			},
		);
	}

	/**
   * Handle intervals configuration changes
   */
	public handleIntervalsChanges(change: { old: any; new: any }): void {
		const intervals = this.getIntervalConfig();

		this.logger?.infoSync(
			"Intervals configuration changed - APPLYING DYNAMIC UPDATES",
			{
				component: LogComponents.configManager,
				old: change.old,
				new: change.new,
				parsed: intervals,
			},
		);

		if (
			this.discoveryService &&
      (this.discoveryLightTimer || this.discoveryFullTimer)
		) {
			this.logger?.infoSync(
				"Discovery intervals changed, restarting timers - DYNAMIC UPDATE",
				{
					component: LogComponents.configManager,
					lightIntervalHours:
            intervals.discoveryLightIntervalMs! / (60 * 60 * 1000),
					fullIntervalHours:
            intervals.discoveryFullIntervalMs! / (60 * 60 * 1000),
				},
			);

			this.emit("restart-discovery-timers", intervals);
		}

		if (this.containerManager) {
			this.containerManager.stopAutoReconciliation();
			this.containerManager.startAutoReconciliation(
        intervals.reconciliationIntervalMs!,
			);

			this.logger?.infoSync(
				"Reconciliation interval updated from cloud - DYNAMIC UPDATE APPLIED",
				{
					component: LogComponents.configManager,
					oldIntervalMs:
            change.old?.device?.reconciliationIntervalMs ||
            change.old?.reconciliationIntervalMs,
					newIntervalMs: intervals.reconciliationIntervalMs,
					intervalMinutes: intervals.reconciliationIntervalMs! / 60000,
				},
			);
		}

		if (this.cloudSync) {
			this.cloudSync.updateIntervals({
				pollInterval: intervals.targetStatePollIntervalMs!,
				reportInterval: intervals.deviceReportIntervalMs!,
				metricsInterval: intervals.metricsIntervalMs!,
			});

			this.logger?.infoSync("CloudSync intervals updated from cloud", {
				component: LogComponents.configManager,
				pollIntervalMs: intervals.targetStatePollIntervalMs,
				reportIntervalMs: intervals.deviceReportIntervalMs,
				metricsIntervalMs: intervals.metricsIntervalMs,
			});
		}
	}

	/**
   * Handle memory configuration changes
   */
	public handleMemoryConfigChanges(_change: { old: any; new: any }): void {
		const performanceConfig = this.getPerformanceConfig();
		const newInterval = performanceConfig.memoryCheckIntervalMs!;
		const newThreshold = performanceConfig.memoryThresholdMb! * 1024 * 1024;

		import("../system/memory.js").then(
			({ stopMemoryMonitoring, setMemoryLogger, startMemoryMonitoring }) => {
				stopMemoryMonitoring();

				setMemoryLogger(this.logger);
				startMemoryMonitoring(newInterval, newThreshold, () => {
					this.logger?.errorSync(
						"Memory threshold breached - agent may need restart",
						undefined,
						{
							component: LogComponents.configManager,
							thresholdMB: newThreshold / (1024 * 1024),
							action: "Consider restarting agent or investigating memory leak",
						},
					);
				});

				this.logger?.infoSync("Memory monitoring updated from cloud", {
					component: LogComponents.configManager,
					intervalMs: newInterval,
					thresholdMB: newThreshold / (1024 * 1024),
				});
			},
		);
	}

	/**
   * Handle scheduled restart configuration changes
   */
	public handleScheduledRestartConfig(change: { old: any; new: any }): void {
		const restartConfig = change.new;

		if (this.scheduledRestartTimer) {
			clearTimeout(this.scheduledRestartTimer);
			this.scheduledRestartTimer = undefined;
			this.logger?.infoSync("Cleared existing scheduled restart timer", {
				component: LogComponents.configManager,
			});
		}

		if (!restartConfig || !restartConfig.enabled) {
			this.logger?.debugSync("Scheduled restart disabled or not configured", {
				component: LogComponents.configManager,
				config: restartConfig || "not set",
			});
			return;
		}

		const intervalDays = parseInt(restartConfig.intervalDays, 10);
		if (isNaN(intervalDays) || intervalDays < 1 || intervalDays > 90) {
			this.logger?.warnSync(
				"Invalid scheduled restart intervalDays, must be 1-90",
				{
					component: LogComponents.configManager,
					providedValue: restartConfig.intervalDays,
					using: "disabled",
				},
			);
			return;
		}

		const restartTimeMs = intervalDays * 24 * 60 * 60 * 1000;
		const restartAt = new Date(Date.now() + restartTimeMs);

		this.logger?.infoSync("Scheduled restart configured from cloud", {
			component: LogComponents.configManager,
			enabled: true,
			intervalDays,
			restartAtISO: restartAt.toISOString(),
			restartAtLocal: restartAt.toLocaleString(),
			reason: restartConfig.reason || "heap_fragmentation_cleanup",
			configSource: "cloud_target_state",
		});

		this.emit("schedule-restart", { restartTimeMs, restartConfig });
	}

	/**
   * Handle endpoints configuration changes
   * This is called when the cloud updates the endpoints config
   */
	public async handleEndpointsChanges(change: {
    old: any;
    new: any;
  }): Promise<void> {
		const newEndpoints = change.new || [];
		const oldEndpoints = change.old || [];

		// CRITICAL: Update targetConfig.endpoints immediately so getDiscoveryTargets() sees new endpoints
		// This prevents race condition where discovery runs before setTarget() is called
		this.targetConfig.endpoints = newEndpoints;

		// Classify changes (added, removed, modified)
		const changeType = this.classifyEndpointChanges(oldEndpoints, newEndpoints);

		this.logger?.infoSync("Endpoints configuration changed from cloud", {
			component: LogComponents.configManager,
			oldCount: oldEndpoints.length,
			newCount: newEndpoints.length,
			added: changeType.added.length,
			removed: changeType.removed.length,
			modified: changeType.modified.length,
		});

		// Determine which protocols were affected by changes (added or modified endpoints)
		const changedEndpoints = [...changeType.added, ...changeType.modified];

		// CRITICAL: Also include OPC UA endpoints with null/empty data_points for auto-discovery
		// This handles the case where device is synced from cloud without nodes
		const opcuaWithoutNodes = newEndpoints.filter(
			(e: any) =>
				e.protocol === "opcua" &&
        e.connection?.endpointUrl &&
        (!e.data_points || e.data_points.length === 0),
		);

		// Combine changed endpoints with OPC UA endpoints needing discovery
		const allEndpointsNeedingDiscovery = [
			...changedEndpoints,
			...opcuaWithoutNodes,
		];
		const affectedProtocols = [
			...new Set(allEndpointsNeedingDiscovery.map((e: any) => e.protocol)),
		];

		if (affectedProtocols.length === 0) {
			this.logger?.debugSync(
				"No protocols affected by endpoint changes, skipping discovery",
				{
					component: LogComponents.configManager,
				},
			);
			return;
		}

		if (opcuaWithoutNodes.length > 0) {
			this.logger?.infoSync(
				"Triggered auto-discovery for OPC UA devices without nodes",
				{
					component: LogComponents.configManager,
					deviceCount: opcuaWithoutNodes.length,
					devices: opcuaWithoutNodes.map((e: any) => e.name),
				},
			);
		}

		// Filter endpoints that support discovery (only for affected protocols)
		// Discovery validates connectivity for:
		// - Modbus: slaveRange (scan multiple slaves) or slaveId (single slave)
		// - OPC-UA: discovery URLs
		// - SNMP: IP ranges or specific hosts
		// - MQTT: topic discovery
		// - BACnet: device discovery
		const discoverableEndpoints = allEndpointsNeedingDiscovery.filter(
			(e: any) => {
				if (
					e.protocol === "modbus" &&
          (e.connection?.slaveId !== undefined || e.connection?.slaveRange)
				)
					return true;
				if (e.protocol === "opcua" && e.connection?.endpointUrl) return true; // OPC UA discovery via endpoint
				if (e.protocol === "snmp" && e.connection?.host) return true;
				if (e.protocol === "mqtt" && e.connection?.discoveryRoots) return true;
				if (e.protocol === "bacnet") return true; // BACnet uses broadcast discovery
				return false;
			},
		);

		if (discoverableEndpoints.length > 0 && this.discoveryService) {
			const shouldAllowDiscoveryWrites = discoverableEndpoints.some(
				(e: any) => e.protocol === "modbus" && e.connection?.slaveRange,
			);

			// Get unique list of protocols that need discovery (from discoverable endpoints only)
			const discoveryProtocols = [
				...new Set(discoverableEndpoints.map((e: any) => e.protocol)),
			];

			// Emit pre-discovery event to stop features and free IPC connection slots
			// This prevents "max clients reached" errors when discovery tries to validate connectivity
			this.discoveryService.emit("pre-discovery", {
				protocols: discoveryProtocols,
				trigger: "config-change",
			});

			// Run discovery with skipDbWrites flag to avoid overwriting reconcile's changes
			// Discovery will emit discovery-complete event for batch reload
			this.discoveryService
				.runDiscovery({
					trigger: "config-change",
					validate: true, // Full validation to ensure endpoints are reachable
					forceRun: true, // Bypass rate limiting (config-driven change)
					protocols: discoveryProtocols, // Only scan changed protocols
					skipDbWrites: !shouldAllowDiscoveryWrites, // Allow discovery to persist new slaves for modbus slaveRange targets
				})
				.catch((err: Error) => {
					this.logger?.errorSync(
						"Discovery validation failed after endpoint change",
						err,
						{
							component: LogComponents.configManager,
							protocols: discoveryProtocols,
						},
					);
				});
		}

		// Log removed endpoints (cleanup handled by reconcile())
		if (changeType.removed.length > 0) {
			this.logger?.infoSync(
				"Endpoints removed, will be cleaned up during reconciliation",
				{
					component: LogComponents.configManager,
					removedCount: changeType.removed.length,
					removedNames: changeType.removed.map((e) => e.name),
				},
			);
		}
	}

	// ==================== TYPED EVENT EMITTER ====================

	// Typed event emitter methods
	public on<K extends keyof ConfigManagerEvents>(
		event: K,
		listener: ConfigManagerEvents[K],
	): this {
		return super.on(event, listener as any);
	}

	public emit<K extends keyof ConfigManagerEvents>(
		event: K,
		...args: Parameters<ConfigManagerEvents[K]>
	): boolean {
		return super.emit(event, ...args);
	}
}

/**
 * Base Feature Class
 * 
 * Provides common functionality for all agent features:
 * - MQTT connection management
 * - Logger setup
 * - Lifecycle management (start/stop)
 * - Configuration validation
 * - Event emitter capabilities
 */

import { EventEmitter } from 'events';
import { CloudMqttClient } from '../mqtt/manager.js';
import { AgentLogger } from '../logging/agent-logger.js';

export interface FeatureConfig {
  enabled: boolean;
  cloudApiUrl?: string; // Optional: for features that need cloud connectivity
  [key: string]: any;
}

export interface FeatureLogger {
  info(message: string): void;
  warn(message: string): void;
  error(message: string, errorOrContext?: any, context?: Record<string, any>): void;
  debug(message: string, ...args: any[]): void;
}

export interface MqttConnection {
  publish(topic: string, payload: string | Buffer, options?: { qos?: 0 | 1 | 2 }): Promise<void>;
  subscribe(topic: string, options?: { qos?: 0 | 1 | 2 }, handler?: (topic: string, payload: Buffer) => void): Promise<void>;
  unsubscribe(topic: string): Promise<void>;
  isConnected(): boolean;
}

export abstract class BaseFeature extends EventEmitter {
	protected config: FeatureConfig;
	protected logger: FeatureLogger;
	protected mqttConnection?: MqttConnection;
	protected deviceUuid: string;
	protected featureName: string;
	protected isRunning: boolean = false;
	protected requiresProvisioning: boolean = false; // Set to true for cloud-dependent features
	private debugEnvVar: string;

	constructor(
		config: FeatureConfig,
		agentLogger: AgentLogger,
		featureName: string,
		deviceUuid: string,
		requiresMqtt: boolean = true,
		debugEnvVar?: string,
		requiresProvisioning: boolean = false
	) {
		super(); // Initialize EventEmitter
		this.config = config;
		this.deviceUuid = deviceUuid;
		this.featureName = featureName;
		this.debugEnvVar = debugEnvVar || 'DEBUG';
		this.requiresProvisioning = requiresProvisioning;

		// Create feature-specific logger wrapper
		this.logger = this.createLogger(agentLogger, featureName);

		// Setup MQTT connection if required
		if (requiresMqtt) {
			this.mqttConnection = this.setupMqttConnection();
		}
	}

	/**
   * Create a feature-specific logger that wraps the agent logger
   */
	private createLogger(agentLogger: AgentLogger, featureName: string): FeatureLogger {
		return {
			info: (message: string) => agentLogger.infoSync(message, { component: featureName }),
			warn: (message: string) => agentLogger.warnSync(message, { component: featureName }),
			error: (message: string, errorOrContext?: any, context?: Record<string, any>) => {
				if (errorOrContext instanceof Error) {
					agentLogger.errorSync(message, errorOrContext, {
						component: featureName,
						...context,
					});
					return;
				}

				if (errorOrContext && typeof errorOrContext === 'object') {
					agentLogger.errorSync(message, undefined, {
						component: featureName,
						...errorOrContext,
						...context,
					});
					return;
				}

				if (typeof errorOrContext !== 'undefined') {
					agentLogger.errorSync(message, new Error(String(errorOrContext)), {
						component: featureName,
						...context,
					});
					return;
				}

				agentLogger.errorSync(message, undefined, { component: featureName });
			},
			debug: (message: string, ...args: any[]) => {
				if (this.isDebugEnabled()) {
					agentLogger.debugSync(message, { component: featureName, args });
				}
			}
		};
	}

	/**
  * Setup MQTT connection using centralized CloudMqttClient
   */
	private setupMqttConnection(): MqttConnection {
		const mqttManager = CloudMqttClient.getInstance();

		if (!mqttManager.isConnected()) {
			this.logger.warn('MQTT Manager not connected - feature will have limited functionality');
		}

		// Return CloudMqttClient directly (it implements MqttConnection interface)
		return mqttManager;
	}

	/**
   * Check if debug mode is enabled for this feature
   */
	protected isDebugEnabled(): boolean {
		return process.env[this.debugEnvVar] === 'true';
	}

	/**
   * Wait for MQTT connection with timeout
   */
	protected async waitForMqttConnection(timeoutMs: number = 5000): Promise<boolean> {
		if (!this.mqttConnection) {
			return false;
		}

		if (this.mqttConnection.isConnected()) {
			return true;
		}

		this.logger.warn(`MQTT not connected, waiting up to ${timeoutMs}ms...`);

		const checkInterval = 100;
		let waited = 0;

		while (!this.mqttConnection.isConnected() && waited < timeoutMs) {
			await new Promise(resolve => setTimeout(resolve, checkInterval));
			waited += checkInterval;
		}

		if (this.mqttConnection.isConnected()) {
			this.logger.info('MQTT connection established');
			return true;
		} else {
			this.logger.error('MQTT connection timeout');
			return false;
		}
	}

	/**
   * Validate configuration
   * Override in subclass to implement feature-specific validation
   */
	protected validateConfig(): void {
		if (!this.config.enabled) {
			throw new Error('Feature is disabled');
		}
	}

  /**
   * Initialize the feature
   * Override in subclass to implement feature-specific initialization
   */
  protected abstract onInitialize(): Promise<void>;

  /**
   * Start the feature
   * Override in subclass to implement feature-specific start logic
   */
  protected abstract onStart(): Promise<void>;

  /**
   * Stop the feature
   * Override in subclass to implement feature-specific stop logic
   */
  protected abstract onStop(): Promise<void>;

  /**
   * Public start method with common lifecycle management
   */
  public async start(): Promise<void> {
	if (this.isRunning) {
		this.logger.warn('Feature already running');
		return;
	}

	// Check if feature requires provisioning (cloud API endpoint)
	if (this.requiresProvisioning && (!this.config.cloudApiUrl || this.config.cloudApiUrl.trim() === '')) {
		this.logger.info(`${this.featureName} skipped - device not provisioned (requires cloud API endpoint)`);
		return; // Gracefully skip without throwing error
	}

	try {
		this.logger.debug('Starting feature...');
		this.validateConfig();
		await this.onInitialize();
		await this.onStart();
		this.isRunning = true;
		this.logger.debug('Feature started successfully');
	} catch (error) {
		this.logger.error('Failed to start feature', error);
		throw error;
	}
  }

  /**
   * Public stop method with common lifecycle management
   */
  public async stop(): Promise<void> {
	if (!this.isRunning) {
		return;
	}

	try {
		this.logger.debug('Stopping feature...');
		await this.onStop();
		this.isRunning = false;
		this.logger.debug('Feature stopped successfully');
	} catch (error) {
		this.logger.error('Failed to stop feature', error);
		throw error;
	}
  }

  /**
   * Check if feature is running
   */
  public running(): boolean {
	return this.isRunning;
  }
}

import type { AnomalyDetectionService } from '../../../anomaly/index.js';
import type { Protocol } from '../../../anomaly/types.js';
import type { Prediction } from '../../../anomaly/forecaster.js';
import { extractRawDeviceState, normalizeDeviceState } from '../../../anomaly/device-state.js';

type Reading = {
  [key: string]: any;
  deviceName?: string;
  metric?: string;
  registerName?: string;
  name?: string;
  value?: unknown;
  device_uuid?: string;
  deviceUuid?: string;
  deviceState?: unknown;
  state?: unknown;
  status?: unknown;
  readings?: Reading[];
  device_state?: unknown;
  raw_device_state?: unknown;
  anomaly_score?: number;
  anomaly_threshold?: number;
  baseline_samples?: number;
  detection_methods?: string[];
  predicted_next?: number;
  trend?: string;
  trend_strength?: number;
  forecast_confidence?: number;
  time_to_threshold?: {
    threshold: number;
    estimated_seconds: number;
    confidence: number;
  };
};

/**
 * Enriches pre-parsed messages with anomaly scores, thresholds, and forecasts
 * from the edge anomaly service.  Supports both OPC-UA (direct object) and
 * Modbus ({readings: [...]}) formats.
 */
export class AnomalyEnricher {
	constructor(
    private readonly getService: () => AnomalyDetectionService | undefined,
    private readonly deviceUuid: string,
    private readonly protocol: Protocol | undefined,
	) {}

	enrich(messages: unknown[], deviceName: string): unknown[] {
		const service = this.getService();
		if (!service) return messages;

		const predictions = service.getPredictions();

		for (const data of messages) {
			const d = data as Reading;

			// Modbus format: { readings: [...] }
			if (d.readings && Array.isArray(d.readings)) {
				for (const reading of d.readings) {
					if (typeof reading !== 'object' || reading === null) continue;
					const readingDeviceName: string = reading.deviceName || deviceName;
					const fieldName: string | undefined = reading.metric || reading.registerName || reading.name;
					if (!fieldName) continue;

					this.applyDeviceState(reading, reading);
					this.attachScores(service, predictions, reading, readingDeviceName, fieldName);
				}
			}
			// OPC-UA format: direct reading object
			else if (d.deviceName && (d.metric || d.registerName || d.name) && d.value !== undefined) {
				const readingDeviceName: string = d.deviceName;
				const fieldName: string | undefined = d.metric || d.registerName || d.name;
				if (!fieldName) continue;

				this.applyDeviceState(d, d);
				this.attachScores(service, predictions, d, readingDeviceName, fieldName);
			}
		}

		return messages;
	}

	private applyDeviceState(target: Reading, source: Reading): void {
		const raw = extractRawDeviceState(source);

		if (raw === undefined) return;

		if (target.device_state === undefined) {
			target.device_state = normalizeDeviceState(this.protocol, raw);
		}
		if (target.raw_device_state === undefined) {
			target.raw_device_state = raw;
		}
	}

	private buildMetricKey(
		deviceIdentifier: string | undefined,
		deviceName: string,
		fieldName: string,
	): string {
		const identifier =
      typeof deviceIdentifier === 'string' && deviceIdentifier.trim()
	? deviceIdentifier.trim()
	: deviceName || 'unknown';

		return `${this.deviceUuid}_${identifier}_${fieldName}`;
	}

	private attachScores(
		service: AnomalyDetectionService,
		predictions: Record<string, Prediction> | undefined,
		target: Reading,
		deviceIdentifierName: string,
		fieldName: string,
	): void {
		const metricName = this.buildMetricKey(
			target.device_uuid || target.deviceUuid || deviceIdentifierName,
			deviceIdentifierName,
			fieldName,
		);
		const score = service.getAnomalyScore(metricName);
		if (score === undefined) return;

		target.anomaly_score = score;

		const metadata = service.getAnomalyMetadata(metricName);
		if (metadata) {
			target.anomaly_threshold = metadata.threshold;
			target.baseline_samples = metadata.samples;
			target.detection_methods = metadata.methods;
		}

		const p = predictions?.[metricName];
		if (p) {
			target.predicted_next = p.predicted_next;
			target.trend = p.trend;
			target.trend_strength = p.trend_strength;
			target.forecast_confidence = p.confidence;
			if (p.time_to_threshold) target.time_to_threshold = p.time_to_threshold;
		}
	}
}

import type { AnomalyDetectionService } from '../../../anomaly/index.js';
import type { Protocol } from '../../../anomaly/types.js';
import { extractRawDeviceState } from '../../../anomaly/device-state.js';
import type { Logger } from '../types.js';

/**
 * Walks each batch message, extracts every numeric field, and feeds them to the
 * anomaly detector.  The service is resolved lazily via `getService` so that
 * late injection (configureAnomalyFeed called after construction) is supported.
 */
export class AnomalyFeed {
	private static readonly MAX_RECURSION_DEPTH = 6;

	// Per-batch dedup ΓÇö reset at the start of every processBatch() call
	private batchVisited = new WeakSet<Record<string, unknown> | unknown[]>();
	private batchProcessedMetrics = new Set<string>();
	private batchCandidateMetrics = new Set<string>();
	private batchSkippedMetrics = new Set<string>();
	private batchMetricLabels = new Map<string, string>();
	private currentService?: AnomalyDetectionService;

	constructor(
    private readonly getService: () => AnomalyDetectionService | undefined,
    private readonly deviceUuid: string,
    private readonly protocol: Protocol | undefined,
    private readonly logger?: Logger,
	) {}

	processBatch(messages: unknown[], deviceName: string): void {
		const service = this.getService();
		const hasService = !!service;
		const hasConfiguredMetrics = !!service?.hasConfiguredMetrics();


		if (!hasService) {
			this.logger?.debug('Endpoint batch skipped: anomaly service unavailable', {
				deviceName,
				messageCount: messages.length,
			});
			return;
		}

		if (!hasConfiguredMetrics) {
			this.logger?.debug('Endpoint batch skipped: no configured anomaly metrics', {
				deviceName,
				messageCount: messages.length,
			});
			return;
		}

		this.currentService = service;

		const timestampMs = Date.now();
		this.batchVisited = new WeakSet();
		this.batchProcessedMetrics.clear();
		this.batchCandidateMetrics.clear();
		this.batchSkippedMetrics.clear();
		this.batchMetricLabels.clear();

		try {
			for (const data of messages) {
				this.extractNumericFields(data, deviceName, timestampMs);
			}
		} finally {
			this.currentService = undefined;
		}

		if (this.batchProcessedMetrics.size > 0) {
			this.logger?.debug('Endpoint processing complete', {
				deviceName,
				messageCount: messages.length,
				extractedMetricCount: this.batchProcessedMetrics.size,
				sampleMetrics: Array.from(this.batchProcessedMetrics).slice(0, 10),
			});
		}

		this.logger?.debug('Endpoint batch evaluation summary', {
			deviceName,
			messageCount: messages.length,
			candidateMetricCount: this.batchCandidateMetrics.size,
			evaluatedMetricCount: this.batchProcessedMetrics.size,
			skippedMetricCount: this.batchSkippedMetrics.size,
			sampleSkippedMetrics: Array.from(this.batchSkippedMetrics).slice(0, 10),
			sampleSkippedLabels: Array.from(this.batchSkippedMetrics)
				.slice(0, 10)
				.map((metricKey) => this.batchMetricLabels.get(metricKey) || metricKey),
		});
	}

	// --- helpers ----------------------------------------------------------------

	private toFiniteNumber(value: unknown): number | undefined {
		if (typeof value === 'number' && Number.isFinite(value)) return value;
		if (typeof value === 'string') {
			const trimmed = value.trim();
			if (!trimmed) return undefined;
			const parsed = Number(trimmed);
			if (Number.isFinite(parsed)) return parsed;
		}
		return undefined;
	}

	// Canonical 3-part key: <endpointDeviceUuid>_<deviceIdentifier>_<fieldName>
	private buildMetricKey(deviceIdentifier: string | undefined, deviceName: string, fieldName: string): string {
		const identifier =
      typeof deviceIdentifier === 'string' && deviceIdentifier.trim()
	? deviceIdentifier.trim()
	: (deviceName || 'unknown');
		const metricKey = `${this.deviceUuid}_${identifier}_${fieldName}`;

		// this.logger?.debug('Built metricKey', {
		//   metricKey,
		//   deviceName,
		//   deviceIdentifier: identifier,
		//   fieldName,
		// });

		return metricKey;
	}

	private resolveDeviceId(...candidates: unknown[]): string | undefined {
		for (const c of candidates) {
			if (typeof c === 'string' && c.trim()) return c.trim();
			if (typeof c === 'number' && Number.isFinite(c)) return String(c);
		}
		return undefined;
	}

	private dispatchToAnomaly(
		metricKey: string,
		point: Omit<Parameters<AnomalyDetectionService['processDataPoint']>[0], 'metric'>,
	): boolean {
		const service = this.currentService;
		this.batchCandidateMetrics.add(metricKey);
		this.batchMetricLabels.set(metricKey, this.buildFriendlyMetricLabel(metricKey, point));
		if (!service) return false;
		const configured = service.isMetricConfigured(metricKey);

		// this.logger?.debug('Config gate check', {
		//   metricKey,
		//   configured,
		// });

		if (!configured) {
			this.batchSkippedMetrics.add(metricKey);
			return false;
		}
		const dedupKey = `${metricKey}:${point.timestamp}`;
		if (this.batchProcessedMetrics.has(dedupKey)) return false;
		this.batchProcessedMetrics.add(dedupKey);
		service.processDataPoint({ metric: metricKey, ...point });
		return true;
	}

	private buildFriendlyMetricLabel(
		metricKey: string,
		point: Omit<Parameters<AnomalyDetectionService['processDataPoint']>[0], 'metric'>,
	): string {
		const tags = (point as { tags?: Record<string, unknown> }).tags;
		if (!tags || typeof tags !== 'object') return metricKey;

		const deviceName = typeof tags.deviceName === 'string' && tags.deviceName.trim()
			? tags.deviceName.trim()
			: (typeof tags.sensorName === 'string' && tags.sensorName.trim() ? tags.sensorName.trim() : undefined);

		const fieldName = typeof tags.fieldName === 'string' && tags.fieldName.trim()
			? tags.fieldName.trim()
			: (typeof tags.field === 'string' && tags.field.trim() ? tags.field.trim() : undefined);

		if (deviceName && fieldName) return `${deviceName}/${fieldName}`;
		if (fieldName) return fieldName;
		return metricKey;
	}

	// Bare number payload ΓÇö no device wrapper, falls back to endpoint identity.
	private dispatchDirectNumeric(value: number, deviceName: string, timestampMs: number, prefix: string): void {
		const fieldName = prefix || 'value';
		const metricKey = this.buildMetricKey(undefined, deviceName, fieldName);
		const fallbackDeviceId = deviceName ? `endpoint:${deviceName}` : undefined;

		this.logger?.warn('No explicit deviceId in payload; using fallback identity', {
			device: deviceName, protocol: this.protocol,
			metricKey, fallbackDeviceId, reason: 'direct_numeric_payload',
		});

		this.dispatchToAnomaly(metricKey, {
			source: 'endpoint', protocol: this.protocol, rawDeviceState: undefined,
			value, unit: '', timestamp: timestampMs, quality: 'GOOD',
			deviceId: fallbackDeviceId,
			tags: { sensorName: deviceName, endpointId: deviceName, field: fieldName },
		});
	}

	// OPC-UA reading object: { deviceName, metric|name, value, ... }
	private dispatchReadingObject(data: any, parentDeviceName: string, timestampMs: number): void {
		const readingDeviceName: string = data.deviceName;
		const payloadDeviceUuid: string | undefined = data.device_uuid || data.deviceUuid;
		const resolvedDeviceId = this.resolveDeviceId(data.deviceId, data.device_id);
		const fieldName: string = data.metric || data.name;
		const value = this.toFiniteNumber(data.value);
		const quality: string = data.quality || 'GOOD';

		if (value === undefined) {
			this.logger?.debug('Skipping non-numeric reading', {
				endpoint: parentDeviceName, deviceName: readingDeviceName, fieldName,
				rawType: typeof data.value, rawValue: data.value,
			});
			return;
		}

		const effectiveDeviceId = resolvedDeviceId || `endpoint:${parentDeviceName}`;
		if (!resolvedDeviceId && !payloadDeviceUuid) {
			this.logger?.warn('No explicit deviceId in payload; using fallback identity', {
				device: parentDeviceName, protocol: this.protocol,
				metricName: fieldName, deviceName: readingDeviceName, fallbackDeviceId: effectiveDeviceId,
				reason: 'reading_object_missing_device_id',
			});
		}

		const metricKey = this.buildMetricKey(payloadDeviceUuid || readingDeviceName, parentDeviceName, fieldName);
		this.dispatchToAnomaly(metricKey, {
			source: 'endpoint', protocol: this.protocol,
			rawDeviceState: data.deviceState ?? data.state ?? data.status ?? extractRawDeviceState(data),
			value, unit: data.unit || '', timestamp: timestampMs,
			quality: quality === 'GOOD' || quality === 'Good' ? 'GOOD' : 'BAD',
			deviceId: effectiveDeviceId,
			tags: {
				sensorName: parentDeviceName, endpointId: parentDeviceName,
				...(payloadDeviceUuid && { deviceUuid: payloadDeviceUuid }),
				deviceName: readingDeviceName, fieldName,
			},
		});
	}

	// Modbus readings array: [{ deviceName, metric|registerName, value, ... }]
	private dispatchReadingsArray(readings: any[], parentDeviceName: string, timestampMs: number): void {
		for (const reading of readings) {
			if (typeof reading !== 'object' || reading === null) continue;

			const readingDeviceName: string = reading.deviceName || parentDeviceName;
			const payloadDeviceUuid: string | undefined = reading.device_uuid || reading.deviceUuid;
			const resolvedDeviceId = this.resolveDeviceId(reading.deviceId, reading.device_id);
			// metric (standard) > registerName (Modbus) > name (legacy)
			const fieldName: string | undefined = reading.metric || reading.registerName || reading.name;
			const value = this.toFiniteNumber(reading.value);
			const quality: string = reading.quality || 'GOOD';

			if (!fieldName) continue;

			if (value === undefined) {
				this.logger?.debug('Skipping non-numeric array reading', {
					endpoint: parentDeviceName, deviceName: readingDeviceName, fieldName,
					rawType: typeof reading.value, rawValue: reading.value,
				});
				continue;
			}

			const effectiveDeviceId = resolvedDeviceId || `endpoint:${parentDeviceName}`;
			if (!resolvedDeviceId && !payloadDeviceUuid) {
				this.logger?.warn('No explicit deviceId in payload; using fallback identity', {
					device: parentDeviceName, protocol: this.protocol,
					metricName: fieldName, deviceName: readingDeviceName, fallbackDeviceId: effectiveDeviceId,
					reason: 'readings_array_missing_device_id',
				});
			}

			const metricKey = this.buildMetricKey(payloadDeviceUuid || readingDeviceName, parentDeviceName, fieldName);
			this.dispatchToAnomaly(metricKey, {
				source: 'endpoint', protocol: this.protocol,
				rawDeviceState: reading.deviceState ?? reading.state ?? reading.status ?? extractRawDeviceState(reading),
				value, unit: reading.unit || '', timestamp: timestampMs,
				quality: quality === 'GOOD' || quality === 'Good' ? 'GOOD' : 'BAD',
				deviceId: effectiveDeviceId,
				tags: {
					sensorName: parentDeviceName, endpointId: parentDeviceName,
					...(payloadDeviceUuid && { deviceUuid: payloadDeviceUuid }),
					deviceName: readingDeviceName, fieldName,
				},
			});
		}
	}

	// Walk a payload recursively; routes each numeric field to the anomaly service.
	// Fast-paths (in order): bare number ΓåÆ OPC-UA object ΓåÆ Modbus array ΓåÆ generic walk.
	private extractNumericFields(data: any, deviceName: string, timestampMs: number, prefix = '', depth = 0): void {
		if (depth > AnomalyFeed.MAX_RECURSION_DEPTH) return;

		if (typeof data === 'number') {
			this.dispatchDirectNumeric(data, deviceName, timestampMs, prefix);
			return;
		}

		if (typeof data !== 'object' || data === null) return;

		// Circular-reference guard: only reachable if data is an object and not null
		if (this.batchVisited.has(data)) return;
		this.batchVisited.add(data);

		if (!Array.isArray(data) && data.deviceName && (data.metric || data.name) && data.value !== undefined) {
			this.dispatchReadingObject(data, deviceName, timestampMs);
			return;
		}

		if (Array.isArray(data) && prefix === 'readings') {
			this.dispatchReadingsArray(data, deviceName, timestampMs);
			return;
		}

		const rawState = extractRawDeviceState(data);
		const payloadDeviceUuid: string | undefined =
      (typeof data.device_uuid === 'string' && data.device_uuid) ||
      (typeof data.deviceUuid === 'string' && data.deviceUuid) ||
      undefined;
		const resolvedDeviceId = this.resolveDeviceId(
			typeof data.deviceId === 'string' ? data.deviceId : undefined,
			typeof data.device_id === 'string' ? data.device_id : undefined,
		);
		const effectiveDeviceId = resolvedDeviceId || `endpoint:${deviceName}`;

		for (const [key, value] of Object.entries(data)) {
			const num = this.toFiniteNumber(value);
			if (num !== undefined) {
				const metricName = prefix ? `${prefix}_${key}` : key;
				const metricKey = this.buildMetricKey(payloadDeviceUuid, deviceName, metricName);

				if (!resolvedDeviceId) {
					this.logger?.warn('No explicit deviceId in payload; using fallback identity', {
						device: deviceName, protocol: this.protocol,
						metricKey, field: metricName, fallbackDeviceId: effectiveDeviceId,
						reason: 'nested_numeric_missing_device_id',
					});
				}

				this.dispatchToAnomaly(metricKey, {
					source: 'endpoint', protocol: this.protocol, rawDeviceState: rawState,
					value: num, unit: '', timestamp: timestampMs, quality: 'GOOD',
					deviceId: effectiveDeviceId,
					tags: {
						sensorName: deviceName, endpointId: deviceName,
						...(payloadDeviceUuid && { deviceUuid: payloadDeviceUuid }),
						field: metricName,
					},
				});
			} else if (Array.isArray(value) || (typeof value === 'object' && value !== null)) {
				this.extractNumericFields(value, deviceName, timestampMs, key, depth + 1);
			}
		}
	}
}

import type { Logger } from '../types.js';

type ValueType = 'number' | 'string' | 'boolean' | 'object' | 'array' | 'null';
type DriftSeverity = 'warning' | 'critical';

/**
 * Per-field type observation counts used to determine dominant expected types.
 * Tracks counts per ValueType plus a total, preventing unlimited type widening:
 * a type is "expected" only when its ratio to total exceeds minTypeDominanceRatio.
 */
type TypeFrequency = {
  counts: Map<ValueType, number>;
  total: number;
};

type DriftDetectorOptions = {
  enabled: boolean;
  warmupBatches: number;
  minFieldPresenceRatio: number;
  consecutiveMissingThreshold: number;
  alertCooldownMs: number;
  adaptivePromotionBatches: number;
  /** Minimum ratio of batches-present vs batches-since-first-seen before promotion. */
  adaptivePromotionRatio: number;
  adaptiveRetireBatches: number;
  maxTrackedFields: number;
  maxTraversalDepth: number;
  maxFieldsPerBatch: number;
  /** Maximum candidates per side when searching for rename pairs. */
  maxRenameCandidates: number;
  /** Skip Levenshtein for field names longer than this. */
  maxRenameFieldLength: number;
  /**
   * A ValueType must appear in at least this fraction of observations to be
   * considered "expected". Prevents one bad payload from permanently widening
   * the accepted type set.
   */
  minTypeDominanceRatio: number;
  /** Maximum array length used in log fields to prevent oversized log payloads. */
  logSampleSize: number;
  /**
   * Run the full schema check only every Nth batch after the baseline is established.
   * 1 = every batch (default). Higher values reduce CPU at high-frequency endpoints.
   * The warmup phase always processes every batch regardless of this setting.
   */
  checkIntervalBatches: number;
};

type ExtractedSchema = {
  fields: Set<string>;
  typesByField: Map<string, Set<ValueType>>;
};

type TypeDrift = {
  field: string;
  dominantExpectedType: ValueType;
  observedTypes: ValueType[];
};

const DEFAULT_OPTIONS: DriftDetectorOptions = {
	enabled: true,
	warmupBatches: 20,
	minFieldPresenceRatio: 0.5,
	consecutiveMissingThreshold: 3,
	alertCooldownMs: 5 * 60 * 1000,
	adaptivePromotionBatches: 50,
	adaptivePromotionRatio: 0.6,
	adaptiveRetireBatches: 250,
	maxTrackedFields: 1000,
	maxTraversalDepth: 5,
	maxFieldsPerBatch: 500,
	maxRenameCandidates: 20,
	maxRenameFieldLength: 64,
	minTypeDominanceRatio: 0.15,
	logSampleSize: 10,
	checkIntervalBatches: 1,
};

const RESERVED_GENERIC_KEYS = new Set<string>([
	'timestamp',
	'ts',
	'time',
	'devicename',
	'deviceid',
	'device_id',
	'device_uuid',
	'deviceuuid',
	'quality',
	'unit',
	'status',
	'state',
	'msgid',
	'sensor',
	'protocol',
]);

function toFieldName(input: unknown): string | undefined {
	if (typeof input !== 'string') {
		return undefined;
	}

	const trimmed = input.trim();
	return trimmed.length > 0 ? trimmed : undefined;
}

function normalizeFieldName(value: string): string {
	return value
		.trim()
		.replace(/([a-z0-9])([A-Z])/g, '$1_$2')
		.replace(/[\s-]+/g, '_')
		.replace(/_+/g, '_')
		.replace(/[^a-zA-Z0-9_.:]/g, '')
		.toLowerCase();
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
	if (typeof value !== 'object' || value === null || Array.isArray(value)) {
		return undefined;
	}

	return value as Record<string, unknown>;
}

function valueTypeOf(value: unknown): ValueType {
	if (value === null) {
		return 'null';
	}

	if (Array.isArray(value)) {
		return 'array';
	}

	if (typeof value === 'number') {
		return 'number';
	}

	if (typeof value === 'string') {
		return 'string';
	}

	if (typeof value === 'boolean') {
		return 'boolean';
	}

	return 'object';
}

function isTelemetryPrimitive(value: unknown): boolean {
	return typeof value === 'number' || typeof value === 'boolean';
}

/**
 * Returns the Levenshtein edit distance between a and b, or undefined when the
 * length difference alone exceeds a reasonable rename threshold (fast path).
 * Uses a flat Int16Array instead of nested arrays to reduce GC pressure.
 */
function levenshteinDistance(a: string, b: string, maxFieldLength: number): number | undefined {
	if (Math.abs(a.length - b.length) > Math.ceil(maxFieldLength * 0.5)) {
		return undefined;
	}

	if (a === b) {
		return 0;
	}

	if (a.length === 0) {
		return b.length;
	}

	if (b.length === 0) {
		return a.length;
	}

	const rows = a.length + 1;
	const cols = b.length + 1;
	const dp = new Int16Array(rows * cols);

	for (let i = 0; i < rows; i++) {
		dp[i * cols] = i;
	}

	for (let j = 0; j < cols; j++) {
		dp[j] = j;
	}

	for (let i = 1; i < rows; i++) {
		for (let j = 1; j < cols; j++) {
			const cost = a[i - 1] === b[j - 1] ? 0 : 1;
			dp[i * cols + j] = Math.min(
				dp[(i - 1) * cols + j] + 1,
				dp[i * cols + (j - 1)] + 1,
				dp[(i - 1) * cols + (j - 1)] + cost,
			);
		}
	}

	return dp[(rows - 1) * cols + (cols - 1)];
}

function stringSimilarity(a: string, b: string, maxFieldLength: number): number | undefined {
	const maxLen = Math.max(a.length, b.length);
	if (maxLen === 0) {
		return 1;
	}

	const dist = levenshteinDistance(a, b, maxFieldLength);
	if (dist === undefined) {
		return undefined;
	}

	return 1 - dist / maxLen;
}

function sampleArray<T>(arr: T[], maxSize: number): T[] {
	return arr.length <= maxSize ? arr : arr.slice(0, maxSize);
}

export class SchemaDriftDetector {
	private readonly options: DriftDetectorOptions;
	private readonly endpointName: string;
	private readonly logger?: Logger;

	private totalBatches = 0;
	private warmupSeen = 0;
	private baseline: Set<string> | undefined;
	/**
   * Frequency-based type tracking per baseline field.
   * Baseline types are evaluated BEFORE updating with new observations so a
   * single bad batch cannot permanently widen the accepted type set.
   */
	private readonly baselineTypeFreq = new Map<string, TypeFrequency>();
	private readonly warmupFieldCounts = new Map<string, number>();
	private readonly warmupTypeFreq = new Map<string, TypeFrequency>();
	private readonly missingStreakByField = new Map<string, number>();
	/** Count and first-seen batch for candidate new fields pending promotion. */
	private readonly newFieldCounts = new Map<string, number>();
	private readonly newFieldFirstSeen = new Map<string, number>();
	private readonly newFieldTypeFreq = new Map<string, TypeFrequency>();
	/** Per-field-signature cooldown map; replaces the previous single global timestamp. */
	private readonly lastAlertAtBySignature = new Map<string, number>();
	/** Lightweight tombstones: records the batch number when a field was retired. */
	private readonly tombstones = new Map<string, number>();

	constructor(endpointName: string, logger?: Logger, options?: Partial<DriftDetectorOptions>) {
		this.endpointName = endpointName;
		this.logger = logger;
		this.options = { ...DEFAULT_OPTIONS, ...(options || {}) };
	}

	observe(messages: unknown[]): void {
		if (!this.options.enabled || messages.length === 0) {
			return;
		}

		const extracted = this.extractSchema(messages);
		if (extracted.fields.size === 0) {
			return;
		}

		this.totalBatches += 1;

		if (!this.baseline) {
			this.learnBaseline(extracted);
			return;
		}

		const interval = Math.max(1, this.options.checkIntervalBatches);
		if (interval > 1 && this.totalBatches % interval !== 0) {
			return;
		}

		this.detectDrift(extracted);
	}

	// ---------------------------------------------------------------------------
	// Baseline learning
	// ---------------------------------------------------------------------------

	private learnBaseline(extracted: ExtractedSchema): void {
		this.warmupSeen += 1;

		for (const field of extracted.fields) {
			this.incrementCount(this.warmupFieldCounts, field);
			this.recordTypeFrequency(
				this.warmupTypeFreq,
				field,
				extracted.typesByField.get(field) ?? new Set<ValueType>(),
			);
		}

		if (this.warmupSeen < this.options.warmupBatches) {
			return;
		}

		const requiredPresence = Math.max(
			1,
			Math.ceil(this.options.warmupBatches * this.options.minFieldPresenceRatio),
		);
		const baseline = new Set<string>();

		for (const [field, count] of this.warmupFieldCounts.entries()) {
			if (count < requiredPresence) {
				continue;
			}

			if (baseline.size >= this.options.maxTrackedFields) {
				break;
			}

			baseline.add(field);
			const freq = this.warmupTypeFreq.get(field);
			if (freq) {
				this.baselineTypeFreq.set(field, { counts: new Map(freq.counts), total: freq.total });
			}
		}

		this.baseline = baseline;
		this.logger?.info(`Schema baseline learned for endpoint '${this.endpointName}'`, {
			endpointName: this.endpointName,
			warmupBatches: this.warmupSeen,
			baselineFieldCount: baseline.size,
			observationMode: 'per-batch',
			sampleBaselineFields: sampleArray(Array.from(baseline), this.options.logSampleSize),
		});
	}

	// ---------------------------------------------------------------------------
	// Drift detection
	// ---------------------------------------------------------------------------

	private detectDrift(extracted: ExtractedSchema): void {
		const baseline = this.baseline;
		if (!baseline) {
			return;
		}

		const newFields: string[] = [];
		const missingFields: string[] = [];
		const typeDrifts: TypeDrift[] = [];

		for (const field of extracted.fields) {
			if (!baseline.has(field)) {
				this.handleNewField(field, extracted, newFields);
				continue;
			}

			this.missingStreakByField.set(field, 0);
			this.checkTypeDrift(field, extracted, typeDrifts);
		}

		for (const expected of baseline) {
			if (extracted.fields.has(expected)) {
				continue;
			}

			this.handleMissingField(expected, baseline, missingFields);
		}

		if (newFields.length === 0 && missingFields.length === 0 && typeDrifts.length === 0) {
			return;
		}

		const reportableNew = this.filterByCooldown(newFields, 'new');
		const reportableMissing = this.filterByCooldown(missingFields, 'missing');
		const reportableTypeDrifts = typeDrifts.filter((d) => this.isPastCooldown(`type:${d.field}`));
		for (const d of reportableTypeDrifts) {
			this.touchCooldown(`type:${d.field}`);
		}

		if (
			reportableNew.length === 0 &&
      reportableMissing.length === 0 &&
      reportableTypeDrifts.length === 0
		) {
			return;
		}

		const severity: DriftSeverity =
      reportableMissing.length > 0 || reportableTypeDrifts.length > 0 ? 'critical' : 'warning';

		const renameCandidate = this.detectRenameCandidate(reportableMissing, reportableNew);
		const s = this.options.logSampleSize;

		this.logger?.warn(`Schema drift detected for endpoint '${this.endpointName}'`, {
			endpointName: this.endpointName,
			severity,
			baselineFieldCount: baseline.size,
			observedFieldCount: extracted.fields.size,
			additiveFieldCount: reportableNew.length,
			sampleAdditiveFields: sampleArray(reportableNew, s),
			breakingFieldCount: reportableMissing.length,
			sampleBreakingFields: sampleArray(reportableMissing, s),
			typeDriftCount: reportableTypeDrifts.length,
			sampleTypeDrifts: sampleArray(reportableTypeDrifts, s),
			renameCandidate,
			observationMode: 'per-batch',
		});
	}

	private handleNewField(
		field: string,
		extracted: ExtractedSchema,
		newFields: string[],
	): void {
		newFields.push(field);

		// Resurrection: field was previously retired ΓÇö log and clear tombstone.
		const retiredAt = this.tombstones.get(field);
		if (retiredAt !== undefined) {
			this.tombstones.delete(field);
			this.logger?.info(
				`Previously retired field has reappeared for endpoint '${this.endpointName}'`,
				{
					endpointName: this.endpointName,
					field,
					retiredAtBatch: retiredAt,
					reappearedAtBatch: this.totalBatches,
				},
			);
		}

		if (!this.newFieldFirstSeen.has(field)) {
			this.newFieldFirstSeen.set(field, this.totalBatches);
		}

		this.incrementCount(this.newFieldCounts, field);
		this.recordTypeFrequency(
			this.newFieldTypeFreq,
			field,
			extracted.typesByField.get(field) ?? new Set<ValueType>(),
		);

		const stableCount = this.newFieldCounts.get(field) ?? 0;
		const firstSeen = this.newFieldFirstSeen.get(field) ?? this.totalBatches;
		const windowSize = this.totalBatches - firstSeen + 1;
		const presenceRatio = windowSize > 0 ? stableCount / windowSize : 0;

		const shouldPromote =
      stableCount >= this.options.adaptivePromotionBatches &&
      presenceRatio >= this.options.adaptivePromotionRatio &&
      this.baseline!.size < this.options.maxTrackedFields;

		if (!shouldPromote) {
			return;
		}

    this.baseline!.add(field);
    this.missingStreakByField.set(field, 0);
    this.newFieldCounts.delete(field);
    this.newFieldFirstSeen.delete(field);

    const freq = this.newFieldTypeFreq.get(field);
    if (freq) {
	this.baselineTypeFreq.set(field, { counts: new Map(freq.counts), total: freq.total });
	this.newFieldTypeFreq.delete(field);
    }

    this.logger?.info(
	`Promoted stable field into schema baseline for endpoint '${this.endpointName}'`,
	{
		endpointName: this.endpointName,
		field,
		stableBatches: stableCount,
		presenceRatio: presenceRatio.toFixed(2),
		windowSize,
	},
    );
	}

	private checkTypeDrift(
		field: string,
		extracted: ExtractedSchema,
		typeDrifts: TypeDrift[],
	): void {
		const observedTypes = extracted.typesByField.get(field);
		if (!observedTypes || observedTypes.size === 0) {
			return;
		}

		const freq = this.baselineTypeFreq.get(field);
		if (!freq) {
			// First sighting for this baseline field ΓÇö establish initial type baseline.
			this.recordTypeFrequency(this.baselineTypeFreq, field, observedTypes);
			return;
		}

		// Evaluate expected types from ESTABLISHED frequencies BEFORE updating them,
		// so a single bad batch cannot immediately widen the accepted type set.
		const expectedTypes = this.getDominantExpectedTypes(freq);

		// Update type frequency with new observations AFTER the check.
		this.recordTypeFrequency(this.baselineTypeFreq, field, observedTypes);

		if (expectedTypes.size === 0) {
			return;
		}

		const unexpectedTypes = Array.from(observedTypes).filter((t) => !expectedTypes.has(t));
		if (unexpectedTypes.length === 0) {
			return;
		}

		const dominantExpectedType = this.getDominantType(freq);
		if (!dominantExpectedType) {
			return;
		}

		typeDrifts.push({
			field,
			dominantExpectedType,
			observedTypes: Array.from(observedTypes),
		});
	}

	private handleMissingField(
		expected: string,
		baseline: Set<string>,
		missingFields: string[],
	): void {
		const streak = (this.missingStreakByField.get(expected) ?? 0) + 1;
		this.missingStreakByField.set(expected, streak);

		if (streak >= this.options.consecutiveMissingThreshold) {
			missingFields.push(expected);
		}

		if (streak >= this.options.adaptiveRetireBatches) {
			baseline.delete(expected);
			this.missingStreakByField.delete(expected);
			this.baselineTypeFreq.delete(expected);

			if (this.canTrackInMap(this.tombstones, expected)) {
				this.tombstones.set(expected, this.totalBatches);
			}

			this.logger?.info(
				`Retired stale field from schema baseline for endpoint '${this.endpointName}'`,
				{
					endpointName: this.endpointName,
					field: expected,
					missingStreak: streak,
					retiredAtBatch: this.totalBatches,
				},
			);
		}
	}

	// ---------------------------------------------------------------------------
	// Rename candidate detection
	// ---------------------------------------------------------------------------

	private detectRenameCandidate(
		missingFields: string[],
		newFields: string[],
	): { from: string; to: string; similarity: number } | undefined {
		if (missingFields.length === 0 || newFields.length === 0) {
			return undefined;
		}

		const { maxRenameCandidates, maxRenameFieldLength } = this.options;
		const candidates = missingFields.slice(0, maxRenameCandidates);
		const added = newFields.slice(0, maxRenameCandidates);
		let best: { from: string; to: string; similarity: number } | undefined;

		for (const m of candidates) {
			const fromRaw = m.split(':').slice(1).join(':');
			if (fromRaw.length > maxRenameFieldLength) {
				continue;
			}

			for (const a of added) {
				const toRaw = a.split(':').slice(1).join(':');
				if (toRaw.length > maxRenameFieldLength) {
					continue;
				}

				const similarity = stringSimilarity(fromRaw, toRaw, maxRenameFieldLength);
				if (similarity === undefined) {
					continue;
				}

				if (!best || similarity > best.similarity) {
					best = { from: m, to: a, similarity };
				}
			}
		}

		return best && best.similarity >= 0.72 ? best : undefined;
	}

	// ---------------------------------------------------------------------------
	// Field extraction with recursive traversal
	// ---------------------------------------------------------------------------

	private extractSchema(messages: unknown[]): ExtractedSchema {
		const fields = new Set<string>();
		const typesByField = new Map<string, Set<ValueType>>();
		const visited = new WeakSet<object>();

		const addField = (field: string, value: unknown): void => {
			if (fields.size >= this.options.maxFieldsPerBatch) {
				return;
			}

			if (!fields.has(field) && fields.size >= this.options.maxTrackedFields) {
				return;
			}

			fields.add(field);

			if (!this.canTrackInMap(typesByField, field)) {
				return;
			}

			let types = typesByField.get(field);
			if (!types) {
				types = new Set<ValueType>();
				typesByField.set(field, types);
			}

			types.add(valueTypeOf(value));
		};

		const traverse = (value: unknown, prefix: string, depth: number): void => {
			if (depth > this.options.maxTraversalDepth || fields.size >= this.options.maxFieldsPerBatch) {
				return;
			}

			if (Array.isArray(value)) {
				if (value.length === 0) {
					return;
				}

				const arrayRef = value as unknown as object;
				if (visited.has(arrayRef)) {
					return;
				}

				visited.add(arrayRef);

				// Array entries are traversed under the same prefix, intentionally collapsing
				// positional structure. All entries contribute to the same field namespace.
				for (const entry of value) {
					traverse(entry, prefix, depth + 1);
					if (fields.size >= this.options.maxFieldsPerBatch) {
						return;
					}
				}

				return;
			}

			const record = asRecord(value);
			if (!record) {
				return;
			}

			const objectRef = record as unknown as object;
			if (visited.has(objectRef)) {
				return;
			}

			visited.add(objectRef);

			// Track keys processed via explicit schema-aware paths to prevent
			// double-counting them as generic key:* fields below.
			const handledKeys = new Set<string>();

			// Explicit: Modbus / structured readings array.
			const readings = record.readings;
			if (Array.isArray(readings)) {
				handledKeys.add('readings');
				for (const reading of readings) {
					const rr = asRecord(reading);
					if (!rr) {
						continue;
					}

					const fieldNameRaw =
            toFieldName(rr.metric) ||
            toFieldName(rr.registerName) ||
            toFieldName(rr.name);

					if (!fieldNameRaw) {
						continue;
					}

					const normalized = normalizeFieldName(fieldNameRaw);
					if (normalized) {
						addField(`reading:${normalized}`, rr.value);
					}
				}
			}

			// Explicit: OPC-UA / direct reading object.
			const directFieldRaw =
        toFieldName(record.metric) ||
        toFieldName(record.registerName) ||
        toFieldName(record.name);

			if (directFieldRaw) {
				handledKeys.add('metric');
				handledKeys.add('register_name');
				handledKeys.add('name');
				handledKeys.add('value');
				const normalized = normalizeFieldName(directFieldRaw);
				if (normalized) {
					addField(`reading:${normalized}`, record.value);
				}
			}

			// Generic: numeric/boolean leaf fields, skipping already-handled keys and
			// reserved metadata keys. String values are intentionally excluded here to
			// avoid false positives from metadata strings (firmwareVersion, etc.).
			for (const [rawKey, rawValue] of Object.entries(record)) {
				const normalizedKey = normalizeFieldName(rawKey);
				if (!normalizedKey) {
					continue;
				}

				if (RESERVED_GENERIC_KEYS.has(normalizedKey) || handledKeys.has(normalizedKey)) {
					continue;
				}

				if (isTelemetryPrimitive(rawValue)) {
					const scopedKey = prefix ? `${prefix}.${normalizedKey}` : normalizedKey;
					addField(`key:${scopedKey}`, rawValue);
				}

				if (typeof rawValue === 'object' && rawValue !== null) {
					const nextPrefix = prefix ? `${prefix}.${normalizedKey}` : normalizedKey;
					traverse(rawValue, nextPrefix, depth + 1);
				}
			}
		};

		for (const message of messages) {
			traverse(message, '', 0);
			if (fields.size >= this.options.maxFieldsPerBatch) {
				break;
			}
		}

		return { fields, typesByField };
	}

	// ---------------------------------------------------------------------------
	// Small private helpers
	// ---------------------------------------------------------------------------

	private canTrackInMap<V>(map: Map<string, V>, field: string): boolean {
		return map.has(field) || map.size < this.options.maxTrackedFields;
	}

	private incrementCount(map: Map<string, number>, field: string, amount = 1): void {
		if (!this.canTrackInMap(map, field)) {
			return;
		}

		map.set(field, (map.get(field) ?? 0) + amount);
	}

	private recordTypeFrequency(
		freqMap: Map<string, TypeFrequency>,
		field: string,
		types: Set<ValueType>,
	): void {
		if (!this.canTrackInMap(freqMap, field)) {
			return;
		}

		let freq = freqMap.get(field);
		if (!freq) {
			freq = { counts: new Map(), total: 0 };
			freqMap.set(field, freq);
		}

		for (const t of types) {
			freq.counts.set(t, (freq.counts.get(t) ?? 0) + 1);
		}

		freq.total += 1;
	}

	/**
   * Returns the set of ValueTypes whose frequency ratio meets or exceeds
   * minTypeDominanceRatio. A type must be consistently present to be considered
   * "expected", preventing unlimited widening from occasional bad payloads.
   */
	private getDominantExpectedTypes(freq: TypeFrequency): Set<ValueType> {
		const expected = new Set<ValueType>();
		for (const [type, count] of freq.counts.entries()) {
			if (count / freq.total >= this.options.minTypeDominanceRatio) {
				expected.add(type);
			}
		}

		return expected;
	}

	private getDominantType(freq: TypeFrequency): ValueType | undefined {
		let best: { type: ValueType; count: number } | undefined;
		for (const [type, count] of freq.counts.entries()) {
			if (!best || count > best.count) {
				best = { type, count };
			}
		}

		return best?.type;
	}

	private isPastCooldown(signature: string): boolean {
		return Date.now() - (this.lastAlertAtBySignature.get(signature) ?? 0) >= this.options.alertCooldownMs;
	}

	private touchCooldown(signature: string): void {
		if (!this.canTrackInMap(this.lastAlertAtBySignature, signature)) {
			return;
		}

		this.lastAlertAtBySignature.set(signature, Date.now());
	}

	private filterByCooldown(fields: string[], prefix: string): string[] {
		const allowed: string[] = [];
		for (const field of fields) {
			const sig = `${prefix}:${field}`;
			if (!this.isPastCooldown(sig)) {
				continue;
			}

			this.touchCooldown(sig);
			allowed.push(field);
		}

		return allowed;
	}
}

import mqtt, { MqttClient, IClientOptions, IClientPublishOptions } from 'mqtt';
import { EventEmitter } from 'events';
import type { AgentLogger } from '../logging/agent-logger';
import { LogComponents } from '../logging/types';
import { MessageIdGenerator } from './utils';
import { MessageBufferSync } from './buffer';
import type { BufferSyncConfig } from './buffer';
import { serializePayload } from './codec';
import type { MqttPayload } from './codec';
import { MqttRouter } from './router';

export {
	createJsonPayload,
	createMsgpackPayload,
	serializePayload,
	deserializePayload,
	logCompressionStats,
} from './codec';
export type { MqttPayload } from './codec';

export type PublishMode = 'direct' | 'buffer-only' | 'recovering';

export interface MqttConnectOptions {
  bufferSync?: boolean;
  bufferSyncOptions?: Partial<BufferSyncConfig>;
}

/**
 * Centralized MQTT Manager - Singleton
 * 
 * This manager provides a single MQTT connection shared across the application.
 * Used by jobs, shadows, logging, and other features that need MQTT.
 * 
 * Events:
 * - 'connect': Emitted when MQTT connection is established
 * 
 * TODO (ARCHITECTURE): Consider splitting into layered architecture when complexity justifies
 * 
 * Current monolithic design works well for single-protocol use case, but future needs
 * (multi-protocol support, complex codec switching, advanced testing) may benefit from:
 * 
 * 1. MqttTransport (connect, disconnect, publish, subscribe)
 *    - Pure MQTT.js wrapper
 *    - Easy to mock for unit tests
 *    - Could be abstracted to support AMQP/WebSocket transports
 * 
 * 2. MqttCodec (serialize, deserialize)
 *    - JSON/MessagePack/Protobuf encoding
 *    - Format detection/negotiation
 *    - Independent of transport layer
 * 
 * 3. MqttReliability (queue, retry, deduplication, inflight limiting)
 *    - Pending message queue management
 *    - Exponential backoff reconnection
 *    - Token bucket inflight control
 *    - Message ID deduplication
 * 
 * Benefits:
 * - Testability: Mock transport, test reliability logic in isolation
 * - Codec swapping: Add Protobuf without touching transport/reliability
 * - Maintenance: Clear boundaries reduce cognitive load (~800 lines ΓåÆ 3x ~250 lines)
 * - Reusability: Transport layer could support non-MQTT protocols
 * 
 * Trade-offs:
 * - More files/classes (3 vs 1)
 * - More indirection (method calls across layers)
 * - Only worth it if adding MessagePack/Protobuf support or multi-protocol transport
 * 
 * Decision: Keep monolithic for now. Refactor when adding second codec or protocol.
 */
export class CloudMqttClient extends EventEmitter {
	private static instance: CloudMqttClient;
	private client: MqttClient | null = null;
	private connected = false;
	private readonly router = new MqttRouter();
	private subscribedTopics = new Map<string, number>(); // ref count: topic ΓåÆ number of active subscribers
	private connectionPromise: Promise<void> | null = null;
	private debug = false;
	private logger?: AgentLogger;
	private bufferSync?: MessageBufferSync;
	private publishMode: PublishMode = 'direct';

	// Volatile in-memory queue ΓÇö used ONLY when bufferSync is disabled.
	// When bufferSync is enabled, all offline messages go to SQLite instead (see publish()).
	// Messages here are lost on process crash; drained on reconnect via drainPendingPublishes().
	private pendingPublishes: Array<{
    topic: string;
    payload: string | Buffer;
    options?: IClientPublishOptions;
  }> = [];
	private readonly MAX_PENDING_PUBLISHES = 1000; // Hard cap ΓÇö oldest dropped above this
	private readonly PENDING_BACKPRESSURE_THRESHOLD = 750; // 75% of cap ΓÇö warn once when queue crosses this
	private readonly MAX_INFLIGHT = 10; // Max concurrent publishes (prevents socket congestion)
	private inflightPublishes = 0; // Current inflight publish count (token bucket)
	private reconnectAttempts = 0;
	private readonly MAX_RECONNECT_DELAY_MS = 30000; // 30 seconds max
	private readonly BASE_RECONNECT_DELAY_MS = 1000; // 1 second base
	private reconnectTimer: NodeJS.Timeout | null = null; // Single source of truth ΓÇö set synchronously, never races
	private consecutivePublishFailures = 0; // Reset on success or reconnect
	private readonly PUBLISH_FAILURE_THRESHOLD = 3; // Consecutive failures before forcing reconnect
	private lastBrokerUrl?: string;
	private lastOptions?: IClientOptions;
	private lastDeviceUuid?: string; // Store device UUID for reuse on reconnects
	private messageIdGenerator?: MessageIdGenerator; // For HA deduplication

	private constructor() {
		super();
	}

	public static getInstance(): CloudMqttClient {
		if (!CloudMqttClient.instance) {
			CloudMqttClient.instance = new CloudMqttClient();
		}
		return CloudMqttClient.instance;
	}

	/**
   * Set logger for the MQTT manager (singleton pattern)
   */
	public setLogger(logger: AgentLogger | undefined): void {
		this.logger = logger;
	}

	public getPublishMode(): PublishMode {
		return this.publishMode;
	}

	/**
   * Returns the current in-memory queue depth.
   * Callers can use this to apply backpressure before publishing.
   * Note: when bufferSync is enabled this queue is always 0 ΓÇö use bufferSync.getStats() instead.
   */
	public getQueueDepth(): { pending: number; inflight: number } {
		return {
			pending: this.pendingPublishes.length,
			inflight: this.inflightPublishes,
		};
	}

	public setPublishMode(mode: PublishMode, reason?: string): void {
		if (this.publishMode === mode) {
			return;
		}

		const previousMode = this.publishMode;
		this.publishMode = mode;

		this.logInfo('MQTT publish mode changed', {
			previousMode,
			nextMode: mode,
			...(reason ? { reason } : {}),
		});
	}

	public requestBufferedFlush(reason?: string): void {
		if (!this.bufferSync?.isEnabled()) {
			return;
		}

		this.debugLog(`Requesting buffered flush${reason ? ` (${reason})` : ''}`);
		this.bufferSync.requestFlush();
	}

	/**
   * Enable local message buffer sync service (idempotent)
   */
	public async enableBufferSync(
		logger?: AgentLogger,
		options?: Partial<BufferSyncConfig>
	): Promise<void> {
		if (this.bufferSync) {
			return;
		}

		const syncLogger = logger || this.logger;

		this.bufferSync = new MessageBufferSync(this, syncLogger, {
			flushBatchSize: 100,
			flushIntervalMs: 30000,
			maxRetries: 3,
			cleanupIntervalMs: 3600000,
			maxBufferRecords: 10000,
			dropPolicy: 'oldest',
			flushTriggerThreshold: 1000,
			maxFlushPerCycle: 1000,
			bufferEvenWhenOnline: false,
			enabled: options?.enabled ?? true,
			...options,
		});

		if (this.isConnected()) {
			await this.bufferSync.start();
			syncLogger?.infoSync('Message buffer sync started', {
				component: LogComponents.mqtt,
			});
		} else {
			this.once('connect', () => {
				this.bufferSync
					?.start()
					.then(() => {
						this.logInfo('Message buffer sync started');
					})
					.catch((error) => {
						this.logError(
							'Failed to start message buffer sync after MQTT connect',
							error instanceof Error ? error : new Error(String(error)),
							undefined
						);
					});
			});
		}
	}

	/**
   * Disable local message buffer sync service
   */
	public disableBufferSync(): void {
		if (!this.bufferSync) {
			return;
		}

		this.bufferSync.stop();
		this.bufferSync = undefined;

		this.logInfo('Message buffer sync stopped');
	}

	/**
   * Initialize message ID generator for HA deduplication
   * 
   * @param deviceUuid - Device UUID
   */
	public initMessageIdGenerator(deviceUuid: string): void {
		if (!this.messageIdGenerator) {
			this.messageIdGenerator = new MessageIdGenerator(deviceUuid);
			this.logger?.debugSync('Message ID generator initialized for HA deduplication', {
				component: LogComponents.mqtt,
				deviceUuid
			});
		}
	}

	// Dictionary Manager now initialized in agent.ts as top-level service
	// Consumers receive it via dependency injection (FeatureContext)

	/**
   * Connect to MQTT broker (idempotent - can be called multiple times)
   * @param brokerUrl - MQTT broker URL
   * @param options - MQTT client options
   * @param deviceUuid - Optional device UUID to initialize message ID generator for HA deduplication
   * @param extra - Optional manager-level connection options
   */
	public async connect(
		brokerUrl: string,
		options?: IClientOptions,
		deviceUuid?: string,
		extra?: MqttConnectOptions
	): Promise<void> {
		// Store connection config for self-healing
		this.lastBrokerUrl = brokerUrl;
		this.lastOptions = options;

		if (extra?.bufferSync && !this.bufferSync) {
			await this.enableBufferSync(this.logger, extra.bufferSyncOptions);
		}

		// Store device UUID for reuse on reconnects
		if (deviceUuid) {
			this.lastDeviceUuid = deviceUuid;
			// Initialize message ID generator for HA deduplication
			this.initMessageIdGenerator(deviceUuid);
		} else if (this.lastDeviceUuid) {
			// Reuse device UUID from previous connection (reconnect scenario)
			this.initMessageIdGenerator(this.lastDeviceUuid);
		}

		// If already connected, return
		if (this.client && this.connected) {
			this.debugLog('Already connected to MQTT broker');
			return Promise.resolve();
		}

		// If connection in progress, wait for it
		if (this.connectionPromise) {
			this.debugLog('Connection already in progress, waiting...');
			return this.connectionPromise;
		}

		// Clean up old client if exists (prevent listener leaks on reconnection)
		this.cleanupExistingClient();

		this.debugLog(`Connecting to MQTT broker: ${brokerUrl}`);

		return this.waitForConnection(brokerUrl, options);
	}

	private cleanupExistingClient(): void {
		if (!this.client) {
			return;
		}

		this.debugLog('Cleaning up old MQTT client before reconnection');
		this.client.removeAllListeners();
		try {
			this.client.end(true);
		} catch (error) {
			this.debugLog(`Error ending old client: ${error}`);
		}
		this.client = null;
	}

	private createClient(brokerUrl: string, options?: IClientOptions): MqttClient {
		return mqtt.connect(brokerUrl, {
			...options,
			// NOTE: 'clean' is intentionally NOT overridden here.
			// Callers pass clean via options (infra.ts: config.cleanSession ?? true).
			// With clean:false + a stable clientId (device_<uuid>), the broker preserves
			// session state across reconnects ΓÇö subscriptions and in-flight QoS1/2 messages
			// are resumed. resubscribeAll() provides belt-and-suspenders for subscriptions.
			//
			// Intentional overrides (manager owns these, caller value is irrelevant):
			reconnectPeriod: 0, // Never: we manage reconnects manually via scheduleReconnect()
		});
	}

	private attachClientHandlers(
		client: MqttClient,
		brokerUrl: string,
		options: IClientOptions | undefined,
		connectionTimeout: ReturnType<typeof setTimeout>,
		resolve: () => void,
		reject: (reason?: any) => void
	): void {
		client.on('connect', () => {
			this.handleConnect(brokerUrl, connectionTimeout, resolve);
		});

		client.on('error', (err) => {
			this.handleConnectionError(err, brokerUrl, connectionTimeout, reject);
		});

		client.on('reconnect', () => {
			this.handleReconnect();
		});

		client.on('offline', () => {
			this.handleOffline(brokerUrl, options);
		});

		client.on('close', () => {
			this.handleClose(brokerUrl, options);
		});

		client.on('disconnect', () => {
			this.handleDisconnect(brokerUrl, options);
		});

		client.on('message', (topic: string, payload: Buffer) => {
			this.routeMessage(topic, payload);
		});
	}

	private waitForConnection(brokerUrl: string, options?: IClientOptions): Promise<void> {
		this.connectionPromise = new Promise((resolve, reject) => {
			const connectionTimeout = setTimeout(() => {
				if (!this.connected && this.client) {
					this.debugLog('Connection timeout - MQTT broker not responding');
					this.client.end(true);
					reject(new Error(`MQTT connection timeout after 10s: ${brokerUrl}`));
				}
			}, 10000);

			this.client = this.createClient(brokerUrl, options);
			this.attachClientHandlers(this.client, brokerUrl, options, connectionTimeout, resolve, reject);
		});

		return this.connectionPromise;
	}

	private handleConnect(
		brokerUrl: string,
		connectionTimeout: ReturnType<typeof setTimeout>,
		resolve: () => void
	): void {
		clearTimeout(connectionTimeout);
		this.connected = true;
		this.reconnectAttempts = 0; // Reset backoff counter on successful connect
		this.consecutivePublishFailures = 0; // Reset publish failure counter on reconnect

		// Cancel any pending reconnect timer ΓÇö connection succeeded
		if (this.reconnectTimer) {
			clearTimeout(this.reconnectTimer);
			this.reconnectTimer = null;
		}

		this.logInfo('Connected to MQTT broker', {
			brokerUrl,
			reconnectAttempts: 0
		});

		this.connectionPromise = null;

		// Resubscribe to all previously registered topics (new client session starts clean)
		this.resubscribeAll();

		// Drain pending publishes
		this.drainPendingPublishes();

		// Emit connect event for listeners (e.g., CloudSync)
		this.emit('connect');

		resolve();
	}

	private handleConnectionError(
		err: Error,
		brokerUrl: string,
		connectionTimeout: ReturnType<typeof setTimeout>,
		reject: (reason?: any) => void
	): void {
		this.logError('MQTT connection error', err, {
			brokerUrl,
			connected: this.connected
		});

		if (!this.connected) {
			clearTimeout(connectionTimeout);
			this.connectionPromise = null;
			reject(err);
		}
	}

	private handleReconnect(): void {
		this.logInfo('MQTT client reconnecting', {
			reconnectAttempts: this.reconnectAttempts + 1
		});
	}

	private handleOffline(brokerUrl: string, options?: IClientOptions): void {
		this.connected = false;
		this.logInfo('MQTT client offline', {
			pendingPublishes: this.pendingPublishes.length
		});
		// Trigger reconnect immediately on offline
		this.scheduleReconnect(brokerUrl, options);
	}

	private handleClose(brokerUrl: string, options?: IClientOptions): void {
		this.connected = false;
		this.logInfo('MQTT connection closed', {
			pendingPublishes: this.pendingPublishes.length,
			reconnectAttempts: this.reconnectAttempts
		});

		// Schedule reconnect with exponential backoff
		this.scheduleReconnect(brokerUrl, options);
	}

	private handleDisconnect(brokerUrl: string, options?: IClientOptions): void {
		this.connected = false;
		this.logWarn('MQTT broker disconnected client (possibly API restart)', {
			pendingPublishes: this.pendingPublishes.length
		});
		// Trigger immediate reconnect
		this.scheduleReconnect(brokerUrl, options);
	}

	/**
   * Get message ID generator (for callers to inject msgId before serialization)
   */
	public getMessageIdGenerator(): MessageIdGenerator | undefined {
		return this.messageIdGenerator;
	}

	/**
   * Publish message to MQTT topic
   *
   * Routing decisions (in order):
   * 1. bufferSync enabled:
   *    - publishMode !== 'direct' OR offline ΓåÆ SQLite (durable, survives crash)
   *    - publishMode === 'direct' AND online  ΓåÆ live publish
   * 2. bufferSync disabled:
   *    - offline (no client / not connected)   ΓåÆ in-memory queue (volatile)
   *    - publishMode !== 'direct' AND online   ΓåÆ in-memory queue (mode ENFORCED here)
   *    - publishMode === 'direct' AND online   ΓåÆ live publish
   *
   * publishMode is always enforced: 'buffer-only' and 'recovering' never reach live publish.
   *
   * @param topic - MQTT topic
   * @param payload - Buffer, MqttPayload, or string (for backward compatibility)
   * @param options - MQTT publish options
   *
   * Note: For HA deduplication, use createJsonPayload() with msgIdGenerator before calling this.
   */
	public async publish(
		topic: string,
		payload: Buffer | MqttPayload | string,
		options?: IClientPublishOptions
	): Promise<void> {
		// Serialize payload if needed (MqttPayload ΓåÆ Buffer)
		const buffer = this.toBuffer(payload);

		if (this.bufferSync?.isEnabled()) {
			const handled = await this.bufferSync.handlePublish(topic, buffer, options);
			if (handled) {
				return;
			}
		}

		if (!this.client || !this.connected) {
			// Trigger passive self-healing reconnect (fire-and-forget ΓÇö does not block message queuing).
			void this.ensureConnected().catch(() => {});

			if (this.bufferSync?.isEnabled()) {
				// Durable path: at this point isConnected()=false, so bufferSync.handlePublish()
				// sees shouldBuffer=true and persists to SQLite ΓÇö survives a process crash.
				// This closes the race where the top-of-publish bufferSync check returned false
				// (MQTT was up) but MQTT dropped before client.publish() was reached.
				await this.bufferSync.handlePublish(topic, buffer, options);
				return;
			}

			// Volatile fallback (bufferSync disabled): in-memory queue, lost on crash.
			this.enqueuePending(topic, buffer, options);
			return;
		}

		// publishMode enforcement: 'buffer-only' and 'recovering' must never reach live publish,
		// even when the MQTT socket is open. bufferSync enforces this automatically when enabled
		// (shouldBuffer = publishMode !== 'direct'). This guard covers the bufferSync-disabled case.
		if (this.publishMode !== 'direct') {
			this.enqueuePending(topic, buffer, options);
			return;
		}

		return new Promise((resolve, reject) => {
			// Timeout: slow broker or QoS1 PUBACK delay ΓÇö not necessarily a broken connection.
			// Log and reject, but do NOT force a reconnect (would cause TCP churn and duplication).
			const timeout = setTimeout(() => {
				this.consecutivePublishFailures++;
				this.logWarn('MQTT publish timeout', {
					topic,
					consecutivePublishFailures: this.consecutivePublishFailures,
					threshold: this.PUBLISH_FAILURE_THRESHOLD,
				});
				if (
					this.consecutivePublishFailures >= this.PUBLISH_FAILURE_THRESHOLD &&
          this.lastBrokerUrl
				) {
					this.logWarn('Consecutive publish timeout threshold reached ΓÇö scheduling reconnect', {
						topic,
						consecutivePublishFailures: this.consecutivePublishFailures,
					});
					this.scheduleReconnect(this.lastBrokerUrl, this.lastOptions);
				}
				reject(new Error(`MQTT publish timeout after 5s: ${topic}`));
			}, 5000);

      this.client!.publish(topic, buffer, options || {}, (error) => {
	clearTimeout(timeout);
	if (error) {
		this.consecutivePublishFailures++;
		this.logWarn('MQTT publish failed', {
			topic,
			error: error.message,
			consecutivePublishFailures: this.consecutivePublishFailures,
			threshold: this.PUBLISH_FAILURE_THRESHOLD,
		});
		// Only schedule reconnect after N consecutive failures; a single error
		// (e.g. broker ACL rejection) is not a sign of a broken socket.
		if (
			this.consecutivePublishFailures >= this.PUBLISH_FAILURE_THRESHOLD &&
            this.lastBrokerUrl
		) {
			this.logWarn('Consecutive publish failure threshold reached ΓÇö scheduling reconnect', {
				topic,
				consecutivePublishFailures: this.consecutivePublishFailures,
			});
			this.scheduleReconnect(this.lastBrokerUrl, this.lastOptions);
		}
		reject(error);
	} else {
		this.consecutivePublishFailures = 0; // Reset on any successful publish
		resolve();
	}
      });
		});
	}


	/**
   * Publish message to MQTT topic WITHOUT queueing
   * 
   * Throws error immediately if not connected (no offline queue).
   * Use this for messages that have alternative delivery methods (e.g., HTTP fallback).
   * 
   * @param topic - MQTT topic
   * @param payload - Buffer, MqttPayload, or string (for backward compatibility)
   * @param options - MQTT publish options
   * 
   * Note: For HA deduplication, use createJsonPayload() with msgIdGenerator before calling this.
   */
	public async publishNoQueue(
		topic: string,
		payload: Buffer | MqttPayload | string,
		options?: IClientPublishOptions
	): Promise<void> {
		// Serialize payload if needed (MqttPayload ΓåÆ Buffer)
		const buffer = this.toBuffer(payload);

		if (this.bufferSync?.isEnabled()) {
			const handled = await this.bufferSync.handlePublish(topic, buffer, options);
			if (handled) {
				return;
			}
		}

		if (!this.client || !this.connected) {
			throw new Error(`MQTT not connected - cannot publish to ${topic}`);
		}

		return new Promise((resolve, reject) => {
			const timeout = setTimeout(() => {
				reject(new Error(`MQTT publish timeout after 5s: ${topic}`));
			}, 5000);

      this.client!.publish(topic, buffer, options || {}, (error) => {
	clearTimeout(timeout);
	if (error) {
		reject(error);
	} else {
		resolve();
	}
      });
		});
	}

	/**
   * Subscribe to MQTT topic with optional handler
   * 
   * Auto-reconnects if disconnected (self-healing).
   */
	public async subscribe(
		topic: string,
		options?: mqtt.IClientSubscribeOptions,
		handler?: (topic: string, payload: Buffer) => void
	): Promise<void> {
		if (!this.isConnected()) {
			this.logInfo('Auto-reconnecting for subscribe operation', { topic });
			await this.ensureConnected();
		}

		// Register handler and topic BEFORE the broker subscribe call so that
		// resubscribeAll() picks them up if a reconnect fires concurrently.
		if (handler) {
			this.router.addHandler(topic, handler);
		}
		const existingCount = this.subscribedTopics.get(topic) ?? 0;
		this.subscribedTopics.set(topic, existingCount + 1);

		// Already subscribed at broker level: skip the redundant SUBSCRIBE packet.
		// The handler is registered above and will receive messages immediately.
		if (existingCount > 0) {
			this.debugLog(`Topic already subscribed (ref=${existingCount + 1}): ${topic}`);
			return;
		}

		// First subscriber for this topic ΓÇö issue broker SUBSCRIBE.
		return new Promise((resolve, reject) => {
			const rollback = () => {
				if (handler) {
					this.router.removeHandler(handler);
				}
				// Undo the ref increment above.
				const count = this.subscribedTopics.get(topic) ?? 1;
				if (count <= 1) {
					this.subscribedTopics.delete(topic);
				} else {
					this.subscribedTopics.set(topic, count - 1);
				}
			};

      this.client!.subscribe(topic, options || {}, (error, granted) => {
	if (error) {
		const errorMsg = `Subscribe error: ${error.message || 'Unspecified error'}`;
		this.debugLog(`${errorMsg} for topic: ${topic}`);
		this.logError(`Subscribe failed for topic: ${topic}`, error, {
			topic,
			errorCode: (error as any).code,
			granted
		});
		rollback();
		reject(new Error(errorMsg));
	} else if (!granted || granted.length === 0) {
		const errorMsg = `Subscribe failed: No subscription granted for topic: ${topic}`;
		this.debugLog(`${errorMsg}`);
		this.logError(errorMsg, undefined, {
			topic,
			granted
		});
		rollback();
		reject(new Error(errorMsg));
	} else if (granted[0].qos === 128) {
		// QoS 128 means subscription failed (rejected by broker)
		const errorMsg = `Subscribe rejected by broker (QoS=128) for topic: ${topic}`;
		this.debugLog(` ${errorMsg}`);
		this.logError(errorMsg, undefined, {
			topic,
			granted
		});
		rollback();
		reject(new Error(errorMsg));
	} else {
		this.debugLog(`Subscribed to topic: ${topic} (QoS=${granted[0].qos})`);
		resolve();
	}
      });
		});
	}

	/**
   * Unsubscribe from MQTT topic
   *
   * Decrements the subscriber ref count. Only sends broker UNSUBSCRIBE and
   * removes handlers from the router when the last subscriber unsubscribes.
   * This prevents one caller from silently destroying another caller's subscription.
   */
	public async unsubscribe(topic: string): Promise<void> {
		if (!this.client) {
			throw new Error('MQTT client not initialized');
		}

		const count = this.subscribedTopics.get(topic) ?? 0;

		if (count > 1) {
			// Other subscribers still active: decrement ref, retain broker subscription and all handlers.
			this.subscribedTopics.set(topic, count - 1);
			this.debugLog(`Unsubscribe deferred for topic: ${topic} (ref now ${count - 1}, broker subscription retained)`);
			return;
		}

		// Last subscriber (or topic not tracked): remove from map and issue broker UNSUBSCRIBE.
		this.subscribedTopics.delete(topic);

		return new Promise((resolve, reject) => {
      this.client!.unsubscribe(topic, (error) => {
	if (error) {
		reject(error);
	} else {
		// Remove all handlers for this pattern now that no subscribers remain.
		this.router.removePattern(topic);
		this.debugLog(`Unsubscribed from topic: ${topic}`);
		resolve();
	}
      });
		});
	}

	/**
   * Check if connected
   */
	public isConnected(): boolean {
		return this.connected && this.client !== null;
	}

	/**
   * Disconnect from MQTT broker
   */
	public async disconnect(): Promise<void> {
		if (!this.client) return;

		// Stop background flush/cleanup timers before disconnecting transport
		this.disableBufferSync();

		return new Promise((resolve) => {
      this.client!.end(false, {}, () => {
	this.connected = false;
	this.router.clear();
	this.subscribedTopics.clear();
	this.debugLog('Disconnected from MQTT broker');
	resolve();
      });
		});
	}

	/**
   * Get the underlying MQTT client (for advanced usage)
   */
	public getClient(): MqttClient | null {
		return this.client;
	}

	/**
   * Enable/disable debug logging
   */
	public setDebug(enabled: boolean): void {
		this.debug = enabled;
	}

	/**
   * Route incoming messages to registered handlers
   * Supports overlapping patterns (e.g., foo/# and foo/bar)
   */
	private routeMessage(topic: string, payload: Buffer): void {
		this.debugLog(`Received MQTT message: ${topic} (${payload.length} bytes)`);

		this.router.route(topic, payload, (pattern, error) => {
			this.logError(`Error in MQTT handler for pattern ${pattern}`, error as Error, {
				topic,
				pattern
			});
		});
	}

	/**
   * Resubscribe all registered handlers after a reconnect.
   * Each reconnect creates a new MQTT client/session, so the broker has no
   * record of previous subscriptions ΓÇö we must re-issue them explicitly.
   */
	private resubscribeAll(): void {
		if (this.subscribedTopics.size === 0) {
			return;
		}

		const topics = [...this.subscribedTopics.keys()];
		this.logInfo(`Resubscribing to ${topics.length} topic(s) after reconnect`, {
			topics
		});

		for (const topic of topics) {
      this.client!.subscribe(topic, { qos: 1 }, (error, granted) => {
	if (error) {
		this.logError(`Resubscribe failed for topic: ${topic}`, error, {
			topic
		});
	} else if (!granted || granted.length === 0 || granted[0].qos === 128) {
		this.logError(`Resubscribe rejected by broker for topic: ${topic}`, undefined, {
			topic,
			granted
		});
	} else {
		this.logInfo(`Resubscribed to topic: ${topic} (QoS=${granted[0].qos})`, {
			topic
		});
	}
      });
		}
	}

	/**
   * Ensure the client is connected, awaiting or initiating reconnect as needed.
   *
   * - Already connected: returns immediately
   * - Connection already in progress: joins the existing promise (no duplicate attempt)
   * - Disconnected with known broker URL: initiates an immediate connect attempt
   * - No broker URL known: throws
   *
   * subscribe() awaits this directly to block until a live socket exists.
   * publish() calls it fire-and-forget (void ...catch) to nudge self-healing without
   * blocking the message-queuing return path.
   */
	private async ensureConnected(): Promise<void> {
		if (this.isConnected()) return;
		if (!this.lastBrokerUrl) {
			throw new Error('MQTT client not connected and no broker URL available for reconnect');
		}
		// If a connection attempt is already in flight, join it rather than starting another.
		if (this.connectionPromise) {
			return this.connectionPromise;
		}
		await this.connect(this.lastBrokerUrl, this.lastOptions);
	}

	private scheduleReconnect(brokerUrl: string, options?: IClientOptions): void {
		// Single source of truth guard: if a timer is already pending, all concurrent
		// triggers (offline, close, disconnect, publish timeout) are silently dropped.
		// This is race-free because timer assignment is synchronous ΓÇö no async gap.
		if (this.reconnectTimer) {
			return;
		}

		this.reconnectAttempts++;
		const exponential = Math.min(
			this.MAX_RECONNECT_DELAY_MS,
			this.BASE_RECONNECT_DELAY_MS * Math.pow(2, this.reconnectAttempts - 1)
		);
		// Full-jitter in [0.85, 1.15) of the exponential window.
		// Spreads simultaneous reconnects across all agents to prevent thundering herd.
		const jitter = Math.random() * 0.3 + 0.85;
		const delay = Math.round(exponential * jitter);

		console.log(`[MQTT] Scheduling reconnect attempt ${this.reconnectAttempts} in ${delay}ms`);

		this.reconnectTimer = setTimeout(() => {
			// Clear timer handle synchronously before any awaits so that a subsequent
			// scheduleReconnect() call (e.g. from a failed connect) is never blocked.
			this.reconnectTimer = null;

			if (this.connected) {
				return;
			}

			if (this.connectionPromise) {
				// Another connect attempt is already in flight ΓÇö wait for it to settle,
				// then re-schedule if we're still offline.
				this.connectionPromise
					.catch(() => {})
					.finally(() => {
						if (!this.connected) {
							this.connectionPromise = null;
							this.scheduleReconnect(brokerUrl, options);
						}
					});
				return;
			}

			// Force close stale client before reconnecting (critical for stuck connections)
			if (this.client) {
				console.warn(`[MQTT] Forcefully closing stale client before reconnect (attempt ${this.reconnectAttempts})`);
				this.client.removeAllListeners();
				try {
					this.client.end(true);
				} catch (error) {
					this.debugLog(`Error ending stale client: ${error}`);
				}
				this.client = null;
			}

			this.connect(brokerUrl, options).catch((error) => {
				console.error(`[MQTT] Reconnect attempt ${this.reconnectAttempts} failed:`, error);
				this.connectionPromise = null;
				this.scheduleReconnect(brokerUrl, options);
			});
		}, delay);
	}

	/**
   * Enqueue a message in the volatile in-memory queue.
   * Shared by: offline branch (not connected) and publishMode guard (connected but non-direct).
   * Applies cap eviction and backpressure warning.
   */
	private enqueuePending(
		topic: string,
		payload: Buffer,
		options?: IClientPublishOptions
	): void {
		if (this.pendingPublishes.length >= this.MAX_PENDING_PUBLISHES) {
			this.logWarn(`Pending publish queue full (${this.MAX_PENDING_PUBLISHES}), dropping oldest message`);
			this.pendingPublishes.shift();
		}
		this.pendingPublishes.push({ topic, payload, options });
		// Backpressure signal: warn exactly once when queue crosses the threshold.
		if (this.pendingPublishes.length === this.PENDING_BACKPRESSURE_THRESHOLD) {
			this.logWarn('Backpressure: pending publish queue growing', {
				queueSize: this.pendingPublishes.length,
				cap: this.MAX_PENDING_PUBLISHES,
			});
		}
		this.debugLog(`Queued message for offline delivery: ${topic} (queue size: ${this.pendingPublishes.length})`);
	}

	/**
   * Drain pending publishes on reconnect
   *
   * Uses inflight limiting (token bucket) to prevent memory spikes and socket congestion.
   * - Max 10 concurrent publishes (MAX_INFLIGHT)
   * - Continues draining as callbacks complete
   * - Critical for stability on flaky links
   */
	private drainPendingPublishes(): void {
		if (this.pendingPublishes.length === 0) {
			return;
		}

		const count = this.pendingPublishes.length;
		this.logInfo(`Draining ${count} pending MQTT messages`, {
			maxInflight: this.MAX_INFLIGHT
		});

		// Drain with inflight limiting (token bucket pattern)
		this.drainBatch();
	}

	/**
   * Drain a batch of pending publishes (respecting inflight limit)
   * Recursively called as publishes complete to maintain steady flow
   */
	private drainBatch(): void {
		// Stop if queue empty or client disconnected
		if (this.pendingPublishes.length === 0 || !this.client || !this.connected) {
			return;
		}

		// Respect inflight limit to prevent socket congestion
		while (this.pendingPublishes.length > 0 && this.inflightPublishes < this.MAX_INFLIGHT) {
			const msg = this.pendingPublishes.shift()!;
			this.inflightPublishes++;

			this.client.publish(msg.topic, msg.payload, msg.options || {}, (error) => {
				this.inflightPublishes--; // Release token

				if (error) {
					this.logError(`Failed to drain message to ${msg.topic}`, error);
					// Re-queue failed message (back to front to preserve order)
					this.pendingPublishes.unshift(msg);
				}

				// Continue draining as callbacks complete (maintains steady flow)
				this.drainBatch();
			});
		}
	}

	/**
   * Convert payload to Buffer for transport
   * Supports: Buffer (passthrough), MqttPayload (serialize), string (backward compat)
   */
	private toBuffer(payload: Buffer | MqttPayload | string): Buffer {
		if (Buffer.isBuffer(payload)) {
			return payload;
		}
		if (typeof payload === 'string') {
			return Buffer.from(payload, 'utf-8');
		}
		// MqttPayload - serialize using helper
		return serializePayload(payload);
	}

	private debugLog(message: string): void {
		if (this.debug) {
			this.logger?.debugSync(message, {
				component: LogComponents.mqtt
			});
		}
	}

	private logInfo(msg: string, data?: object): void {
		this.logger?.infoSync(msg, {
			component: LogComponents.mqtt,
			...(data || {})
		});
	}

	private logWarn(msg: string, data?: object): void {
		this.logger?.warnSync(msg, {
			component: LogComponents.mqtt,
			...(data || {})
		});
	}

	private logError(msg: string, err?: Error, data?: object): void {
		this.logger?.errorSync(msg, err, {
			component: LogComponents.mqtt,
			...(data || {})
		});
	}
}
